-- Poems batch 109
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('56298e56-39a0-420b-a728-8c69ef9619b6','送台道人','周麟之','宋','宋诗','song-poetry','','[]','我祖來從錦江曲，尚憶郫筒醉春淥。',256,'全唐诗/poet.song.123000.json','["我祖來從錦江曲，尚憶郫筒醉春淥。", "輕衫拂石踏花歸，近傍青城結茅屋。", "子孫散作淮海居，奕葉英風凜相續。", "不惟叢桂競傳芳，時有高人更超俗。", "或隨羽化附青蛇，或避詔徵稱赤局。", "我生本是林泉人，失脚塵中困羈束。", "每逢蜀士話維桑，便欲携筇訪前躅。", "道人家世出巴西，萬里江山見眉目。", "笑施砭石起膏肓，坐察形神窮倚伏。", "我席爲門君荷旃，相見忘情謝榮辱。", "幽香小鼎暮烟橫，濁酒一盃春蟻綠。", "此身多病經百罹，只合紉蘭與餐菊。", "休論燕頷覓封侯，莫說鳶肩騰火速。", "我有風懷就問君，何時一飽顔公粥。", "今日君行跨奔鹿，欲下鵝洲穿柳谷。", "他年願結白雲期，與君同看金峰鵠。"]'),
('ac144908-6355-4c26-8158-eb83a3edcda0','送僧大通還山一首','周麟之','宋','宋诗','song-poetry','','[]','三年虎卧白雲關，誰念窮猿失故山。',64,'全唐诗/poet.song.123000.json','["三年虎卧白雲關，誰念窮猿失故山。", "野客已拚花自落，道人今與鶴俱還。", "厖眉皓首雙松老，白㲲青絲一室閒。", "何日得追塵外趣，聽君擊鉢翠微間。"]'),
('d3f84195-d4f8-445d-962e-cbdc68f813df','戲呈珉禪師','周麟之','宋','宋诗','song-poetry','','[]','我來何幸識支郎，百丈峰頭寶月光。',64,'全唐诗/poet.song.123000.json','["我來何幸識支郎，百丈峰頭寶月光。", "質薄自憐非燕頷，途窮誰信是龜腸。", "漸看鬢底千絲白，敢說眉間一點黄。", "坐見錦溪秋水闊，不知何日理歸艎。"]'),
('32add1e2-636a-4592-aff5-e69de5440e64','終風行','周麟之','宋','宋诗','song-poetry','','[]','北風駕寒萬竅號，聲如八月江上濤。',136,'全唐诗/poet.song.123000.json','["北風駕寒萬竅號，聲如八月江上濤。", "又疑大鵬上青霄，南溟水擊摶扶摇。", "昆陽陣敗虎豹嘷，撼城飛瓦千兵逃。", "焚輪夜起狂終朝，直憂卷屋掀重茅。", "我居門巷如荒郊，衾無繢罽裘無羔，苦寒獵獵吹縕袍。", "笑引藤樽漱濁醪，不妨高卧醉陶陶。", "夢騎天馬騰長飈，睥睨玉臺閶闔高。", "風聲詩興兩鬭豪，醉中一掃白雲謠。"]'),
('defa78ed-8ed8-4d66-b1da-9c36807b23f3','望秦川歌  其一','周麟之','宋','宋诗','song-poetry','','[]','明皇幸蜀，一日登高山望秦川，謂高力士曰：“吾聽張九齡言，不至此。',64,'全唐诗/poet.song.123000.json','["明皇幸蜀，一日登高山望秦川，謂高力士曰：“吾聽張九齡言，不至此。", "”馬上吹笛爲曲，號《謫仙怨》，今亡焉。", "因爲八章，以申其念舊之意。"]'),
('6f949935-00e8-4012-a3bf-6caca8956382','望秦川歌  其二','周麟之','宋','宋诗','song-poetry','','[]','長安回首戰塵中，馬背行吹一笛風。',32,'全唐诗/poet.song.123000.json','["長安回首戰塵中，馬背行吹一笛風。", "寄恨翻成謫仙怨，始知深負曲江公。"]'),
('428c524f-f227-4142-b214-93b8b185f3c4','望秦川歌  其三','周麟之','宋','宋诗','song-poetry','','[]','錦囊留得玉環香，不見佳人空斷腸。',32,'全唐诗/poet.song.123000.json','["錦囊留得玉環香，不見佳人空斷腸。", "北望秦川烟草滿，尚疑飛燕舞昭陽。"]'),
('c48d3d3f-fdad-4b30-af3c-8e3549d39ea0','望秦川歌  其四','周麟之','宋','宋诗','song-poetry','','[]','向來花萼弄春輝，曾把寧王玉笛吹。',32,'全唐诗/poet.song.123000.json','["向來花萼弄春輝，曾把寧王玉笛吹。", "樂事已隨風燭過，如今橫笛不勝悲。"]'),
('c0998c9c-6a09-4aa7-bfc6-2a060a3160f7','望秦川歌  其五','周麟之','宋','宋诗','song-poetry','','[]','蜀山春動錦江流，水綠山青總是愁。',32,'全唐诗/poet.song.123000.json','["蜀山春動錦江流，水綠山青總是愁。", "愁絕不堪山上望，無人解與月宮遊。"]'),
('4cc82d0a-d006-44f3-b3e3-8d4c597ff283','望秦川歌  其六','周麟之','宋','宋诗','song-poetry','','[]','雨聲鳴棧不堪聽，盡日穿雲上杳冥。',32,'全唐诗/poet.song.123000.json','["雨聲鳴棧不堪聽，盡日穿雲上杳冥。", "羯鼓催花渾不記，曲中空唱雨霖鈴。"]'),
('c908da9f-9cae-46ad-a10d-d6ad4fd8af02','望秦川歌  其七','周麟之','宋','宋诗','song-poetry','','[]','漁陽千幟掃空來，滿目妖氛鬭不開。',32,'全唐诗/poet.song.123000.json','["漁陽千幟掃空來，滿目妖氛鬭不開。", "爲問玉京何日復，傷心黄屋幾時回。"]'),
('9633fe07-8e69-449c-a206-cd9f99cd2ec7','望秦川歌  其八','周麟之','宋','宋诗','song-poetry','','[]','煙霞縹緲認驪山，遠想樓臺紫翠間。',32,'全唐诗/poet.song.123000.json','["煙霞縹緲認驪山，遠想樓臺紫翠間。", "尚欲神遊太真院，不知身過鬼門關。"]'),
('02fa3729-6b48-4bbd-85a2-393104881d5a','望秦川歌  其九','周麟之','宋','宋诗','song-poetry','','[]','阿瞞按舞長生殿，妃子洗粧端正樓。',32,'全唐诗/poet.song.123000.json','["阿瞞按舞長生殿，妃子洗粧端正樓。", "此去恰如巫峽夢，相望千里事悠悠。"]'),
('46fe528f-6a68-4bf5-8006-ce944e4805d3','秋懷三首  其一','周麟之','宋','宋诗','song-poetry','','[]','雨沐秋容浄，雲橫天宇高。',48,'全唐诗/poet.song.123000.json','["雨沐秋容浄，雲橫天宇高。", "溪流走城塹，木葉下亭臯。", "興引淵明酒，寒侵范叔袍。", "清愁不能已，高枕誦離騷。"]'),
('b17e6112-21a5-4478-b37b-75feeb8f3655','秋懷三首  其二','周麟之','宋','宋诗','song-poetry','','[]','燕去簾帷靜，蛩鳴機杼忙。',48,'全唐诗/poet.song.123000.json','["燕去簾帷靜，蛩鳴機杼忙。", "淒風萬籟息，夜月一奩光。", "自喜襟懷豁，寧爲景物傷。", "幽窗有佳致，坐挹桂花香。"]'),
('aaa4c49e-24ee-4ef0-bda9-2d8df8daa7a3','秋懷三首  其三','周麟之','宋','宋诗','song-poetry','','[]','江遠蒓鱸晚，逕荒松菊寒。',48,'全唐诗/poet.song.123000.json','["江遠蒓鱸晚，逕荒松菊寒。", "近知秋信好，更覺旅懷寬。", "遠杵風催急，橫琴夜向闌。", "飄零莫惆悵，吾道久艱難。"]'),
('5635b0ad-250c-449d-931a-14516cffc95f','觀梅','周麟之','宋','宋诗','song-poetry','','[]','春來物物未關情，只與寒梅有舊盟。',64,'全唐诗/poet.song.123000.json','["春來物物未關情，只與寒梅有舊盟。", "芳信已催詩興動，幽香還釀客懷清。", "月摹瘦影橫窗淡，雨浴疏花照水明。", "却憶去年花下飲，共持盃酒泛飛英。"]'),
('8fddc26a-5a0b-4972-b227-3b2531b4acdd','和元革叔無悶齋','周麟之','宋','宋诗','song-poetry','','[]','家在濤江欲盡頭，結茅寧爲樂休休。',64,'全唐诗/poet.song.123000.json','["家在濤江欲盡頭，結茅寧爲樂休休。", "達人自得一經趣，游子空懷千歲憂。", "坐對聖賢唯酒適，身憑形影以詩酬。", "公今非遯元無悶，要把韋編續聖丘。"]'),
('542cba1f-0fc0-4a40-b99a-c11b37eb41a2','初除西掖士華兄以詩賀喜次韵爲謝','周麟之','宋','宋诗','song-poetry','','[]','向來歸卧白雲邊，忽拜君王詔墨鮮。',64,'全唐诗/poet.song.123000.json','["向來歸卧白雲邊，忽拜君王詔墨鮮。", "誰借羽翰超弱水，又隨簪橐過甘泉。", "酒同今夕兄酬弟，詩比當年聖得賢。", "潤色正須燕許手，小儒那有筆如椽。"]'),
('7de2d674-58f6-4bd6-9105-3a0c6890c478','西園堂榭落成種植畢工偶成口號十首呈參政張公  其一','周麟之','宋','宋诗','song-poetry','','[]','遯叟高眠石磴雲，鴟夷長泛五湖春。',32,'全唐诗/poet.song.123000.json','["遯叟高眠石磴雲，鴟夷長泛五湖春。", "爭如晝錦延華萼，同作商山四老人。"]'),
('8b875418-57bf-4bc8-a740-168619ba7272','西園堂榭落成種植畢工偶成口號十首呈參政張公  其二','周麟之','宋','宋诗','song-poetry','','[]','華堂迥出複城高，更買鄰園徹古壕。',32,'全唐诗/poet.song.123000.json','["華堂迥出複城高，更買鄰園徹古壕。", "要展渭川千畝竹，賸栽錦里百根桃。"]'),
('58103e10-9c73-4376-a91f-0bd2af40e7f6','西園堂榭落成種植畢工偶成口號十首呈參政張公  其三','周麟之','宋','宋诗','song-poetry','','[]','鈎簾待燕春風裏，把酒酬花夜月前。',32,'全唐诗/poet.song.123000.json','["鈎簾待燕春風裏，把酒酬花夜月前。", "更啟西窗納清景，煙光如畫擁斜川。"]'),
('dbfaa055-e0ce-43df-b44a-862d25e53e03','西園堂榭落成種植畢工偶成口號十首呈參政張公  其四','周麟之','宋','宋诗','song-poetry','','[]','城外青林可當山，橫雲翠靄鬰孱顔。',32,'全唐诗/poet.song.123000.json','["城外青林可當山，橫雲翠靄鬰孱顔。", "虛堂一枕林泉夢，如在煙霞縹緲間。"]'),
('dfd051e1-0049-4b30-95d8-5aada3b89bed','西園堂榭落成種植畢工偶成口號十首呈參政張公  其五','周麟之','宋','宋诗','song-poetry','','[]','林花倒影落清池，池面春波泛綠漪。',32,'全唐诗/poet.song.123000.json','["林花倒影落清池，池面春波泛綠漪。", "更築小橋亭上去，便成家世授書圯。"]'),
('6d17f305-4152-4050-a64f-c9bb6995d593','西園堂榭落成種植畢工偶成口號十首呈參政張公  其六','周麟之','宋','宋诗','song-poetry','','[]','小谿深樹鹿呦呦，野鶴無聲蕙帳幽。',32,'全唐诗/poet.song.123000.json','["小谿深樹鹿呦呦，野鶴無聲蕙帳幽。", "風月滿亭供笑語，依然不減醉翁游。"]'),
('fe2c6b07-dc2a-4a00-801c-8d38a7fdf7a6','西園堂榭落成種植畢工偶成口號十首呈參政張公  其七','周麟之','宋','宋诗','song-poetry','','[]','草木青歸二月天，川原明媚發春妍。',32,'全唐诗/poet.song.123000.json','["草木青歸二月天，川原明媚發春妍。", "臨流忽見寒梅影，皎若凌波洛浦仙。"]'),
('1d4f69c4-ce0e-48ff-9d13-26884dfbabe6','西園堂榭落成種植畢工偶成口號十首呈參政張公  其八','周麟之','宋','宋诗','song-poetry','','[]','花梢日上雨痕乾，冉冉香風破嫩寒。',32,'全唐诗/poet.song.123000.json','["花梢日上雨痕乾，冉冉香風破嫩寒。", "眼底便知紅紫近，山茶先放鶴頭丹。"]'),
('e699360f-ca75-4959-b71a-6745a4a6e1a0','西園堂榭落成種植畢工偶成口號十首呈參政張公  其九','周麟之','宋','宋诗','song-poetry','','[]','幽叢灌木便成林，準擬炎天百步陰。',32,'全唐诗/poet.song.123000.json','["幽叢灌木便成林，準擬炎天百步陰。", "應許春禽樂餘蔭，鷦鷯穩寄一枝深。"]'),
('2f02da61-aecd-4701-9a4d-12d395e1d8cd','西園堂榭落成種植畢工偶成口號十首呈參政張公  其一○','周麟之','宋','宋诗','song-poetry','','[]','水流映带清漳宅，野望遲迴半月臺。',32,'全唐诗/poet.song.123000.json','["水流映带清漳宅，野望遲迴半月臺。", "只恐宮鶑阻陪賞，日邊便有鶴書來。"]'),
('bedcec56-0fd8-411b-a9b1-1d984eeea848','與蘇州守十詩以兵衛森畫戟燕寢凝清香爲韵  其一','周麟之','宋','宋诗','song-poetry','','[]','吳山濯濯烟鬟青，湖水練練光遶城。',64,'全唐诗/poet.song.123000.json','["吳山濯濯烟鬟青，湖水練練光遶城。", "城中主人目如電，爽氣坐納山水清。", "千門鳴絃夜月靜，四野垂穎秋雲平。", "試占古語詠侯德，一賢可當百萬兵。"]'),
('acd983f0-0e97-4fba-94e8-ff6e08eaa6f4','與蘇州守十詩以兵衛森畫戟燕寢凝清香爲韵  其二','周麟之','宋','宋诗','song-poetry','','[]','蘇臺屹立層霄裏，環望水雲三百里。',64,'全唐诗/poet.song.123000.json','["蘇臺屹立層霄裏，環望水雲三百里。", "十年草綠春城荒，麋鹿肆游歌舞地。", "公來一顧風物新，華屋下蟠烟靄翠。", "正須滿意事登臨，早晚中臺拜英衛。"]'),
('f1b0ecbd-494c-4d0d-8a15-7c2d1c42219c','與蘇州守十詩以兵衛森畫戟燕寢凝清香爲韵  其三','周麟之','宋','宋诗','song-poetry','','[]','館娃宮院秋沈沈，採香芳逕花委金。',64,'全唐诗/poet.song.123000.json','["館娃宮院秋沈沈，採香芳逕花委金。", "吳王舊事久寂寞，此地猶懷千古心。", "黄堂高興動罇俎，三百畫橋絲管音。", "吳儂但識宴會樂，那知遶屋棠陰森。"]'),
('137f90ef-66f8-46fb-89e4-54900e84ab07','與蘇州守十詩以兵衛森畫戟燕寢凝清香爲韵  其四','周麟之','宋','宋诗','song-poetry','','[]','城西連柂楓橋夜，城東接舳閶門下。',64,'全唐诗/poet.song.123000.json','["城西連柂楓橋夜，城東接舳閶門下。", "細聽來往棹謳聲，一一歌呼頌仁化。", "爾知德政並龔黄，我慕風流到王謝。", "會當臨景賦新詩，寫得吳中有聲畫。"]'),
('741b156c-2eeb-4c74-a588-34677647fa42','與蘇州守十詩以兵衛森畫戟燕寢凝清香爲韵  其五','周麟之','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭雨斷兼天碧，松江月明波動色。',64,'全唐诗/poet.song.123000.json','["洞庭雨斷兼天碧，松江月明波動色。", "剪橘霜包照座黄，鱠鱸雪縷堆盤白。", "秋到湖山最佳處，此景付公天不惜。", "英名自是龍驤家，更待高閎立幡戟。"]'),
('8b8061e6-a722-4b01-a316-aa61be353738','與蘇州守十詩以兵衛森畫戟燕寢凝清香爲韵  其六','周麟之','宋','宋诗','song-poetry','','[]','相門舊列名臣傳，挺挺遺風眼中見。',64,'全唐诗/poet.song.123000.json','["相門舊列名臣傳，挺挺遺風眼中見。", "遠覽初褰賈父帷，仁風已滿袁宏扇。", "坐看詔璽天邊來，袖章入對金鑾殿。", "好追樂事醉昇平，日奉宸游玉津宴。"]'),
('8a3f4926-0692-41b8-abee-7a828599857f','與蘇州守十詩以兵衛森畫戟燕寢凝清香爲韵  其七','周麟之','宋','宋诗','song-poetry','','[]','一方靜治民安枕，天子英明用人審。',64,'全唐诗/poet.song.123000.json','["一方靜治民安枕，天子英明用人審。", "慈厚薰然布帛溫，威明皎若冰霜凜。", "斡旋妙手經畫餘，貫朽如山粟填廩。", "禁闥還容汲直歸，淮南定報姦謀寢。"]'),
('8c54fd32-3026-4b82-a7ad-c0d24dd94a31','與蘇州守十詩以兵衛森畫戟燕寢凝清香爲韵  其八','周麟之','宋','宋诗','song-poetry','','[]','六飛南駐開陪京，朝廷恃此爲金城。',64,'全唐诗/poet.song.123000.json','["六飛南駐開陪京，朝廷恃此爲金城。", "元侯卧護股肱郡，去天尺五日月明。", "誰憐游子歲一過，欲往不得如流萍。", "今日西風要留客，好山橫道煙光凝。"]'),
('95ac8fb1-dd2e-4990-8a4c-8518f34f8201','與蘇州守十詩以兵衛森畫戟燕寢凝清香爲韵  其九','周麟之','宋','宋诗','song-poetry','','[]','青衫飄泊江海生，十年篷底載我行。',64,'全唐诗/poet.song.123000.json','["青衫飄泊江海生，十年篷底載我行。", "每逢勝地一長望，江山舉目難爲情。", "登樓幾作仲宣賦，在野猶带倪寬經。", "邇來困甚幾執熱，願焉一濯秋風清。"]'),
('394d9eed-a2be-40c1-bbd1-bf51ec246366','與蘇州守十詩以兵衛森畫戟燕寢凝清香爲韵  其一○','周麟之','宋','宋诗','song-poetry','','[]','蓋公論治齊相堂，穆生酌醴元王觴。',64,'全唐诗/poet.song.123000.json','["蓋公論治齊相堂，穆生酌醴元王觴。", "古人好士乃如此，名重千載尊而光。", "我公風度冠今昔，龍門冠蓋春雲翔。", "微才詎敢充旨味，藥籠庶容芝桂香。"]'),
('40df8ffd-c1cc-475d-ae8f-e151d2a7c0c2','辛酉大雪戲成十詩以千山鳥飛絕萬逕人蹤滅爲韵  其一','周麟之','宋','宋诗','song-poetry','','[]','北風夜捲地，凍雲曉黏天。',48,'全唐诗/poet.song.123000.json','["北風夜捲地，凍雲曉黏天。", "黄竹歌未終，飛霰集我前。", "森羅崑山璧，零亂淮夷蠙。", "縛賊懸瓠城，安得兵三千。"]'),
('01b7655c-d239-438f-bd6a-fb5d126124b1','辛酉大雪戲成十詩以千山鳥飛絕萬逕人蹤滅爲韵  其二','周麟之','宋','宋诗','song-poetry','','[]','跨馿遊灞橋，策馬阻藍關。',48,'全唐诗/poet.song.123000.json','["跨馿遊灞橋，策馬阻藍關。", "詩人自清苦，逐客何當還。", "我獨擁敝繭，高卧環堵間。", "黄精已無苗，斸雪思舊山。"]'),
('155ca83b-ef21-4245-bb2a-c3a4ec21a6b8','辛酉大雪戲成十詩以千山鳥飛絕萬逕人蹤滅爲韵  其三','周麟之','宋','宋诗','song-poetry','','[]','松桂亦華顛，瓦石背玉表。',48,'全唐诗/poet.song.123000.json','["松桂亦華顛，瓦石背玉表。", "造物不作難，夜半月出皎。", "書窗互照映，甕牖驚易曉。", "舉頭忽彌望，萬里絕飛鳥。"]'),
('5265c866-b507-486d-a375-227c15a50ecc','辛酉大雪戲成十詩以千山鳥飛絕萬逕人蹤滅爲韵  其四','周麟之','宋','宋诗','song-poetry','','[]','複帳蕤香篝，綺席羅妓圍。',48,'全唐诗/poet.song.123000.json','["複帳蕤香篝，綺席羅妓圍。", "焉知蓽門子，清哦袖鶉衣。", "臘白三日寒，遽使晝掩扉。", "愁思已如許，共作風絮飛。"]'),
('df238437-664d-44e9-ab33-255bef41ec98','辛酉大雪戲成十詩以千山鳥飛絕萬逕人蹤滅爲韵  其五','周麟之','宋','宋诗','song-poetry','','[]','舊聞沙漠寒，磧鹵一丈雪。',48,'全唐诗/poet.song.123000.json','["舊聞沙漠寒，磧鹵一丈雪。", "誰憐牧羝人，白首持漢節。", "朝廷北顧憂，歲晚不忍說。", "寄言上林雁，何事音信絕。"]'),
('ee1b024c-0a55-464f-b781-ef099dc0b8f6','辛酉大雪戲成十詩以千山鳥飛絕萬逕人蹤滅爲韵  其六','周麟之','宋','宋诗','song-poetry','','[]','堆盤水精鹽，翻匙雲子飯。',48,'全唐诗/poet.song.123000.json','["堆盤水精鹽，翻匙雲子飯。", "年年六出花，不必以瑞獻。", "浪言平地尺，貧亦非所願。", "愁無儋石儲，安敢擲百萬。"]'),
('8a864ee2-9c01-489c-9b94-8010b6cd16b1','辛酉大雪戲成十詩以千山鳥飛絕萬逕人蹤滅爲韵  其七','周麟之','宋','宋诗','song-poetry','','[]','林梢宿鴉翻，未覺烟樹暝。',48,'全唐诗/poet.song.123000.json','["林梢宿鴉翻，未覺烟樹暝。", "瀟瀟打窗聲，慣向雲屋聽。", "冰結積已深，風收舞初定。", "凌晨出門喜，折屐印樵逕。"]'),
('d6908300-efaa-463b-bf2f-16822464f4c6','辛酉大雪戲成十詩以千山鳥飛絕萬逕人蹤滅爲韵  其八','周麟之','宋','宋诗','song-poetry','','[]','吾無千金裘，爲博麴米春。',48,'全唐诗/poet.song.123000.json','["吾無千金裘，爲博麴米春。", "牀頭臘甕熟，漉以淵明巾。", "飲少輒至醉，醉眼迷天垠。", "衝寒望南巷，不見披氅人。"]'),
('07ce80cb-c540-4917-b86f-1e5d45bac476','辛酉大雪戲成十詩以千山鳥飛絕萬逕人蹤滅爲韵  其九','周麟之','宋','宋诗','song-poetry','','[]','千騎射獵軍，一簑垂釣翁。',48,'全唐诗/poet.song.123000.json','["千騎射獵軍，一簑垂釣翁。", "寒江與曠野，得意應無窮。", "顧我俱未暇，緩步聊倚筇。", "惜此連璐白，涴以雞犬蹤。"]'),
('b0f56e53-3bb5-4b67-95be-cdff961b44fd','辛酉大雪戲成十詩以千山鳥飛絕萬逕人蹤滅爲韵  其一○','周麟之','宋','宋诗','song-poetry','','[]','佛衣珠唾飛，撼樹縞裙裂。',48,'全唐诗/poet.song.123000.json','["佛衣珠唾飛，撼樹縞裙裂。", "巡簷索梅笑，敧枕聽竹折。", "念此積雪寒，憂世心愈切。", "夜分耿不寐，風燈半明滅。"]'),
('72d401d0-b1c4-402c-a290-59b05408b96d','自南山歸口占上王閣老  其一','周麟之','宋','宋诗','song-poetry','','[]','湖上清遊樂有餘，玉山未倒不須扶。',32,'全唐诗/poet.song.123000.json','["湖上清遊樂有餘，玉山未倒不須扶。", "後堂深處無人到，尚許鴟夷託後車。"]'),
('0f173b26-10f6-4411-b19a-fb29e12bb5ac','自南山歸口占上王閣老  其二','周麟之','宋','宋诗','song-poetry','','[]','日高風軟不生塵，十月湖山暖似春。',32,'全唐诗/poet.song.123000.json','["日高風軟不生塵，十月湖山暖似春。", "綠綺抱來人不至，幾時容我喚真真。"]'),
('b33138e5-4d95-4f90-bde9-10e2af85009f','參政大資毗陵張公輓詩十首  其一','周麟之','宋','宋诗','song-poetry','','[]','淝上英遊遠，江南慶系長。',48,'全唐诗/poet.song.123000.json','["淝上英遊遠，江南慶系長。", "二卿雙戟貴，七葉一門光。", "早負鵬天闊，先分桂籍香。", "中興誰第一，勳烈在旂常。"]'),
('a08bb517-85e5-42fd-9767-8854576e3125','參政大資毗陵張公輓詩十首  其二','周麟之','宋','宋诗','song-poetry','','[]','德望三朝老，才華一代宗。',48,'全唐诗/poet.song.123000.json','["德望三朝老，才華一代宗。", "偉名高附鳳，餘事富雕龍。", "異刻驚黄玉，仙遊問赤松。", "忽騎箕尾去，雲路杳無蹤。"]'),
('6efb8678-1040-43b9-b1db-ad11e37724a2','參政大資毗陵張公輓詩十首  其三','周麟之','宋','宋诗','song-poetry','','[]','一馬龍驤後，中朝草創初。',48,'全唐诗/poet.song.123000.json','["一馬龍驤後，中朝草創初。", "秉樞登政路，扈蹕擁宸裾。", "像入雲臺畫，名標玉府書。", "太平資舊德，不及駕安車。"]'),
('92f8e16d-1c2c-4f7a-b9f5-33353e84693e','參政大資毗陵張公輓詩十首  其四','周麟之','宋','宋诗','song-poetry','','[]','出入紆宸眷，龍光溢帝閽。',48,'全唐诗/poet.song.123000.json','["出入紆宸眷，龍光溢帝閽。", "賜書奎畫爛，分劑寶奩存。", "尚擬陪三接，俄悲築九原。", "遺忠當厚報，豈但輟瓜恩。"]'),
('3baf076b-5ffb-4da3-8b53-18c77024222e','參政大資毗陵張公輓詩十首  其五','周麟之','宋','宋诗','song-poetry','','[]','自領一麾出，旋更五鎮雄。',48,'全唐诗/poet.song.123000.json','["自領一麾出，旋更五鎮雄。", "政追棲鳳迹，民戢带牛風。", "鑑水恩波外，西山爽氣中。", "棠陰隨處是，繞屋自蘢葱。"]'),
('91646b17-3375-4347-a593-6408703dc883','參政大資毗陵張公輓詩十首  其六','周麟之','宋','宋诗','song-poetry','','[]','晚歲游真館，分符蒞別京。',48,'全唐诗/poet.song.123000.json','["晚歲游真館，分符蒞別京。", "九關留管鑰，千騎按屯營。", "天上金甌覆，江邊玉節明。", "傷心遊宴地，悵望北山橫。"]'),
('a468b96f-5cb3-4070-aa14-7ed046ed09d8','參政大資毗陵張公輓詩十首  其七','周麟之','宋','宋诗','song-poetry','','[]','四老延清會，連年樂故鄉。',48,'全唐诗/poet.song.123000.json','["四老延清會，連年樂故鄉。", "譽騰花萼集，光動德星堂。", "今獨三荆茂，居然一鑑亡。", "慶流知有在，蘭玉藹遺芳。"]'),
('b49752c9-8321-4dca-b19a-aab4a546d34a','參政大資毗陵張公輓詩十首  其八','周麟之','宋','宋诗','song-poetry','','[]','綠野裴公趣，東山謝傅心。',48,'全唐诗/poet.song.123000.json','["綠野裴公趣，東山謝傅心。", "林泉幽夢斷，花柳舊谿深。", "瀹茗風生腋，飛觴月滿襟。", "向來親几杖，猶想聽高吟。"]'),
('1a7c087e-105d-4537-a320-f45edf423603','參政大資毗陵張公輓詩十首  其九','周麟之','宋','宋诗','song-poetry','','[]','久玷平津館，叨陪北海尊。',48,'全唐诗/poet.song.123000.json','["久玷平津館，叨陪北海尊。", "軒騰期遠到，刻苦記前言。", "穉榻恩難報，韋經業自存。", "孤蹤初筮仕，此志與誰論。"]'),
('09d85b47-2523-41e2-b20e-7768d1b4de3a','參政大資毗陵張公輓詩十首  其一○','周麟之','宋','宋诗','song-poetry','','[]','憶昔春官試，唯公季子俱。',48,'全唐诗/poet.song.123000.json','["憶昔春官試，唯公季子俱。", "別來成永訣，返哭慟諸孤。", "忍預吹簫列，空懷解劍趨。", "新阡閟長夜，雪涕墮平蕪。"]'),
('eaeddb78-1d18-4056-8313-43548e530f82','致政大夫胡公輓詩五首  其一','周麟之','宋','宋诗','song-poetry','','[]','赫奕三公胄，高華百笏門。',48,'全唐诗/poet.song.123000.json','["赫奕三公胄，高華百笏門。", "義風傾里社，名德老丘園。", "不起東山卧，空餘北海尊。", "已隨飛劍逝，猶記刻舟痕。"]'),
('d406ea35-cd78-4534-8c10-58bb5f0dcc81','致政大夫胡公輓詩五首  其二','周麟之','宋','宋诗','song-poetry','','[]','西帥乘遲日，趨庭正妙年。',48,'全唐诗/poet.song.123000.json','["西帥乘遲日，趨庭正妙年。", "飛書騰白羽，曳綵汎紅蓮。", "晚伏追風驥，長嗟墮水鳶。", "卷舒安義命，何恨及重泉。"]'),
('f5fb96c1-e4d1-44a2-8762-3ad06b8ff038','致政大夫胡公輓詩五首  其三','周麟之','宋','宋诗','song-poetry','','[]','燕寢追遺事，沈痾歎積年。',48,'全唐诗/poet.song.123000.json','["燕寢追遺事，沈痾歎積年。", "未扶鳩杖起，已報鹿車懸。", "顯服登三品，榮名謝九遷。", "英姿寧復見，歸伴玉臺仙。"]'),
('93e0b794-9105-4609-b651-5f591a148a86','致政大夫胡公輓詩五首  其四','周麟之','宋','宋诗','song-poetry','','[]','碧落承先訓，青冥屈壯圖。',48,'全唐诗/poet.song.123000.json','["碧落承先訓，青冥屈壯圖。", "珠懸三樹秀，鑑舞一鸞孤。", "逝水嗟何及，佳城讖不誣。", "江山蟠秀氣，此地卜青烏。"]'),
('a9d1af96-e0e0-4722-87ed-1e02652aa79d','致政大夫胡公輓詩五首  其五','周麟之','宋','宋诗','song-poetry','','[]','末緒慚非偶，孤蹤託契深。',48,'全唐诗/poet.song.123000.json','["末緒慚非偶，孤蹤託契深。", "委禽申舊好，奉屨負初心。", "已矣升堂拜，潸焉雪涕吟。", "四郊烟樹慘，引紼墮哀音。"]'),
('d73e53b4-c0d8-4220-80f3-042ae6748169','夫人孫氏輓詩','周麟之','宋','宋诗','song-poetry','','[]','嬪風合冠女圖中，禮法能兼郝與鍾。',64,'全唐诗/poet.song.123000.json','["嬪風合冠女圖中，禮法能兼郝與鍾。", "自許夫知黄鵠志，曾看女拜紫鸞封。", "高堂把酒同婣睦，燕坐繙經樂始終。", "千載管彤書盛事，只今門有壻如龍。"]'),
('fa4849a0-4433-4c49-87d2-f4d494782293','胡夫人輓詩  其一','周麟之','宋','宋诗','song-poetry','','[]','閫範三從正，家聲兩大餘。',48,'全唐诗/poet.song.123000.json','["閫範三從正，家聲兩大餘。", "義高黄鵠操，恩疊紫鸞書。", "澗沼登蘋藻，園林映板輿。", "忽乘飛鳳去，應傍素臺居。"]'),
('f58f0959-f4e2-4cb7-ae7c-137eee1b297a','胡夫人輓詩  其二','周麟之','宋','宋诗','song-poetry','','[]','晚歲根塵凈，端由志節隆。',48,'全唐诗/poet.song.123000.json','["晚歲根塵凈，端由志節隆。", "斂身遵七誡，彈指悟三空。", "此日傷朝露，何人賦凱風。", "我方司汗簡，盍載女師中。"]'),
('c0eb95ec-c77b-4ff3-9bf3-16eeb29cc35c','胡夫人輓詩  其三','周麟之','宋','宋诗','song-poetry','','[]','舊倚韓康伯，高堂坐累茵。',48,'全唐诗/poet.song.123000.json','["舊倚韓康伯，高堂坐累茵。", "曩先歸厚夜，今又失靈椿。", "族黨千車會，階庭五鼎陳。", "季能當大事，無負玉堂人。"]'),
('cf9657d8-1824-4d57-b375-f6fa5e1a4409','表兄知府郎中張公輓詩三首  其一','周麟之','宋','宋诗','song-poetry','','[]','自昔三珠樹，如兄最早成。',48,'全唐诗/poet.song.123000.json','["自昔三珠樹，如兄最早成。", "握蘭霑賸馥，搴桂阻高程。", "健筆三江瀉，英標一鶚橫。", "崦嵫驚電謝，坐失劍崢嶸。"]'),
('163ce38e-7423-4afa-a786-b59da768b14d','表兄知府郎中張公輓詩三首  其二','周麟之','宋','宋诗','song-poetry','','[]','淼淼沅江路，猶遲皂蓋臨。',48,'全唐诗/poet.song.123000.json','["淼淼沅江路，猶遲皂蓋臨。", "但疑三甲起，那識二毛侵。", "北海樽罍在，南園草木深。", "水亭風月夜，八詠想遺音。"]'),
('b1acdbeb-26f4-4c6b-981e-a66885507282','表兄知府郎中張公輓詩三首  其三','周麟之','宋','宋诗','song-poetry','','[]','自是吾宗出，金蘭臭味同。',48,'全唐诗/poet.song.123000.json','["自是吾宗出，金蘭臭味同。", "彯纓聯北闕，抱槧踵南宮。", "去國郵書密，還鄉巷轍通。", "詎知生死隔，回首一彈中。"]'),
('0a60d145-f91d-47d6-9c7d-cd00bc866172','楊國夫人趙氏輓章','周麟之','宋','宋诗','song-poetry','','[]','猗蘭奕葉神明胄，四德宜家綽有餘。',64,'全唐诗/poet.song.123000.json','["猗蘭奕葉神明胄，四德宜家綽有餘。", "盛事可稽彤筆史，當年曾夢紫函書。", "子登虎榜朝輝弁，夫握龍韜拱殿廬。", "長樂宮中稱萬壽，猶思翟茀擁軿車。"]'),
('48b7692e-c378-437f-babd-5f5c8a58e947','破虜凱歌六首  其一','周麟之','宋','宋诗','song-poetry','','[]','夜半江風金鼓聲，拔營初起石頭城。',32,'全唐诗/poet.song.123000.json','["夜半江風金鼓聲，拔營初起石頭城。", "虜情不料諸軍渡，一戰淮西唾手平。"]'),
('ededaa24-0670-4d13-b82c-9e85d4bfd3f0','破虜凱歌六首  其二','周麟之','宋','宋诗','song-poetry','','[]','莫怕南來生女真，皂旛罽馬漫如雲。',32,'全唐诗/poet.song.123000.json','["莫怕南來生女真，皂旛罽馬漫如雲。", "黄頭碧眼驚相語，切勿前逢八字軍。"]'),
('532426c0-5b3d-4718-b20b-1e81750922d1','破虜凱歌六首  其三','周麟之','宋','宋诗','song-poetry','','[]','山川千里戰塵清，不負當初齧指盟。',32,'全唐诗/poet.song.123000.json','["山川千里戰塵清，不負當初齧指盟。", "從此胡兒敢欺我，江淮草木已知名。"]'),
('917e69dd-c67f-495b-924f-f9be9bf268fc','破虜凱歌六首  其四','周麟之','宋','宋诗','song-poetry','','[]','將軍羽扇自臨戎，帳下健兒爭立功。',32,'全唐诗/poet.song.123000.json','["將軍羽扇自臨戎，帳下健兒爭立功。", "鐵馬莫來淮上牧，漢家旗纛半天紅。"]'),
('d41eb834-58ea-4475-ac3d-89201364849f','破虜凱歌六首  其五','周麟之','宋','宋诗','song-poetry','','[]','江花閒隊曉霏開，爭看官軍打賊回。',32,'全唐诗/poet.song.123000.json','["江花閒隊曉霏開，爭看官軍打賊回。", "十萬羌胡今已破，不煩天子六飛來。"]'),
('e12ecd61-fb48-422e-b74c-839dd84d03f4','破虜凱歌六首  其六','周麟之','宋','宋诗','song-poetry','','[]','捷書日日到甘泉，使者聯翩出勞旋。',32,'全唐诗/poet.song.123000.json','["捷書日日到甘泉，使者聯翩出勞旋。", "將士歡呼拜君賜，鵰銜寶带鵠袍鮮。"]'),
('eea5bf77-1bb6-45d5-a568-012a76011644','中原民謠 燕京小','周麟之','宋','宋诗','song-poetry','','[]','燕京小，鉅防絡野長蛇繞。',204,'全唐诗/poet.song.123000.json','["燕京小，鉅防絡野長蛇繞。", "展闢城池數倍寬，帝居占盡民居少。", "通天百尋殿十重，金爵觚棱在半空。", "萬戶千門歌舞窄，不知九市人聲寂。", "時時日曀盲風來，殺氣冥濛胡舞塞。", "舊來寢處穹廬中，今乃燕坐阿房宮。", "猶嫌北方地寒苦，又欲南嚮觀華風。", "汴都我宋興王宅，二百年來立宗祏。", "一朝飛瓦下雲端，盡毀前模變新飾。", "故老慟哭壯士讙，吾寧忍死不忍觀。", "只恐金碧塗未乾，死胡濺血川原丹。", "羣兒拍手歌相和，此地寧容犬羊涴。", "旄頭夜落五雲開，還與吾皇泰微坐。"]'),
('9133536b-b316-4f5e-a808-5b86c09655a9','中原民謠 迎送亭','周麟之','宋','宋诗','song-poetry','','[]','迎送亭，亭邊柳色何青青。',156,'全唐诗/poet.song.123000.json','["迎送亭，亭邊柳色何青青。", "樹頭風和鵲聲喜，朱甍碧瓦煙光凝。", "路人矯首城南北，牓字新題照阡陌。", "金牌天使走馬來，蕃官出門餞迎客。", "車頭老人扶軛行，自言身是宋遺氓。", "斯亭豈爲迎送設，殆欲迎宋非虛名。", "南人側耳驚相顧，此語端能卜天數。", "說與征夫且緩驅，往來怕見征塵污。", "莫折亭前百年柳，曾經宋德栽培久。", "只期南望翠華歸，再拜馬前稱萬壽。"]'),
('3b86d37c-9606-41d1-9593-329a6627e996','中原民謠 金瀾酒','周麟之','宋','宋诗','song-poetry','','[]','金瀾酒，皓月委波光入酒。',188,'全唐诗/poet.song.123000.json','["金瀾酒，皓月委波光入酒。", "冰壺避暑壓瓊艘，火炕敵寒揮玉斗。", "追歡長是秉燭遊，日高未放傳盃手。", "生平飲血狐兔場，釀糜爲酒氈爲裳。", "猶存故事設茶食，金剛大鐲胡麻香。", "五辛盈柈雁粉黑，豈解玉食羅雲漿。", "南使來時北風冽，冰山峨峨千里雪。", "休嗟虜酒不醉人，別有班觴下層闕。", "或言此酒名金瀾，金數欲盡天意闌。", "醉魂未醒醆未覆，會看骨肉爭相殘。", "一雙寶榼雲龍翥，明日辭朝倒壺去。", "旨留餘瀝酹亡胡，帝鄉自有薔薇露。"]'),
('7d9d3267-d6f8-495f-bedf-c4106dd8afa9','中原民謠 歸德府','周麟之','宋','宋诗','song-poetry','','[]','歸德府，四野坡池抱重阻。',204,'全唐诗/poet.song.123000.json','["歸德府，四野坡池抱重阻。", "閼伯之墟舊宋州，心爲大火占星土。", "昔我藝祖龍潛初，授鉞此地開炎圖。", "錄裳拜野休運啟，王氣鬰鬰雲扶輿。", "真人當天朝萬宇，北望帝城天尺五。", "舟車輻輳川塗交，盡說南京比三輔。", "中興天子膺赤符，又臨此地登鸞車。", "版圖一失故地隔，坐使神州淪虜區。", "金杏園邊春色早，連阡粟麥濉河道。", "景物依然似昔時，只恨居民戴胡情。", "民言我宋瀦仁深，况此舊名歸德軍。", "於今府號襲前躅，不日中原當自復。", "金人無德亡無時，大德日隆天下歸。"]'),
('4b6c5783-077a-429c-bff5-eead08f8c74e','中原民謠 過沃州','周麟之','宋','宋诗','song-poetry','','[]','過沃州，停車聽我遺民謳。',188,'全唐诗/poet.song.123000.json','["過沃州，停車聽我遺民謳。", "茲爲名邦古趙地，皇家得姓基鴻休。", "自胡雜居民在鼎，民心不改千年并。", "一日天開神火流，祥光塞空吐金景。", "胡人驚呼上畔知，曰此異兆誰當之。", "天其有意福趙氏，於斯效瑞騰炎輝。", "是歲更名州作沃，自謂火炎瑞可撲。", "不知字讖愈分明，天水灼然真吉卜。", "君看石橋十尺橫，上有蹋跡青騾行。", "當年勝概壓天下，豈忍歲久蒙氈腥。", "我有簞壺辦漿饋，未審王師何日至。", "此身終作沃州民，趙氏帝王千萬祀。"]'),
('18420f65-e724-45de-80ab-19456b4bd2a4','中原民謠 造海船','周麟之','宋','宋诗','song-poetry','','[]','造海船，海旁樸斲雷殷山。',188,'全唐诗/poet.song.123000.json','["造海船，海旁樸斲雷殷山。", "大船闢艦容萬斛，小船飛鶻何翩翩。", "傳聞潞縣燕京北，木柹翻空浪頭白。", "近年升作北通州，謂是背吭宜控扼。", "坐令斬木千山童，民間十室八九空。", "老者駕車輦輸去，壯者腰斧從鳩工。", "自期鼓檝滄溟隘，他時取道膠西寨。", "檣願相風風北來，飛航信宿趨吳會。", "誰爲此計狂且愚，南北土性天淵殊。", "北人鞍馬是長技，南人濤瀨如坦塗。", "果爾疑非萬全策，驅民忍作魚龍食。", "任渠轉海入江來，自有周郎當赤壁。"]'),
('3db15ec2-104c-4498-b587-757ff1b66903','中原民謠 渡浮橋','周麟之','宋','宋诗','song-poetry','','[]','渡浮橋，黄流噴薄翻雲濤。',204,'全唐诗/poet.song.123000.json','["渡浮橋，黄流噴薄翻雲濤。", "駢頭巨艦寸金縴，翼以巨木維虹腰。", "戍河老兵三太息，顧語行人淚霑臆。", "去年造橋民力殫，今年過橋車轂擊。", "只愁屢壞費修營，追呼無時困征役。", "前月南朝天使來，欲令踐此誇雄哉。", "無何層冰蔽流下，三十六洪中夜摧。", "當時白馬津頭渡，不下氈車上船去。", "今朝緩轡揚鞭回，笑踏長鯨指歸路。", "但願河伯常安流，斯橋不斷千古浮。", "他年過師枕席上，孰憂王旅行無舟。", "適見黎陽山下驛，驛垣破處龜趺出。", "豐碑大字天成橋，猶是宣和時相筆。"]'),
('12fc306d-6184-4ac9-a392-6fc1170fa54a','中原民謠 金臺硯','周麟之','宋','宋诗','song-poetry','','[]','金臺硯，舊日老張聞㝢縣。',188,'全唐诗/poet.song.123000.json','["金臺硯，舊日老張聞㝢縣。", "金華仙伯一品題，名高萬石羅文傳。", "南轅回次白溝河，搴裳欲渡塵沒靴。", "向此畫見限華裔，今乃接畛皆夷歌。", "忽見御莊雲蓊鬰，千章喬木參天碧。", "始知佳氣似舂陵，更喜眼前多舊物。", "伴行蕃使言侏離，髯奴鐻耳乃有知。", "叩轅斂袂出雙璧，不待馹人來致辭。", "自言所獻非荆璞，僅比澄泥與銅雀。", "雅稱揮毫白玉堂，夜掃黄麻追灝噩。", "人皆謂彼勤且誠，盍探露團分寶馨。", "歸家請辦千斛墨，異時擬勒燕山銘。"]'),
('6a26306e-f911-4f1f-89b6-f74886d9fd04','中原民謠 任契丹','周麟之','宋','宋诗','song-poetry','','[]','任契丹，太行爲家千疊山。',204,'全唐诗/poet.song.123000.json','["任契丹，太行爲家千疊山。", "此山阻絕天下脊，中有義旅蛟蛇蟠。", "任君本是良家子，身長七尺風姿偉。", "心懷忠義欲擒胡，誓與羣豪揭竿起。", "時從數騎出郊坰，所向萬人皆披靡。", "不驅丁口不攫金，只取餱糧事儲偫。", "道遮天使奪牌歸，佩牌夜易人不知。", "往來燕趙數百里，徒手不假寸鐵持。", "夜半相逢沃州北，問知南使寧相阨。", "倡言我輩抱雄圖，郎主打圍曾狙擊。", "時來左袒奮臂呼，十萬兒郎一朝得。", "勸君努力雪國讎，爲我斬取單于頭。", "功成好爵皆君有，金印垂腰大如斗。"]'),
('7ba7c0db-726c-4785-9b3c-4b589abcee11','中原民謠 雨木冰','周麟之','宋','宋诗','song-poetry','','[]','雨木冰，貫珠絡玉千葩明。',204,'全唐诗/poet.song.123000.json','["雨木冰，貫珠絡玉千葩明。", "橫鞭一拂條葉動，寶釵墮地聲鏗鍧。", "昨日登車天地墨，怪雨盲風起東北。", "俄然散雹亂飛霙，流淖滿途深沒膝。", "前車折軸不得行，後車脫輻泥翻軛。", "曉來廓氛天宇清，萬象奪目何晶瑩。", "凜如介士執矛戟，四野列陣霜雪凝。", "汴河堤上民驚詫，問是何祥木冰稼。", "平生有眼未曾看，舊說惟聞達官怕。", "車中囁嚅齊魯生，嘗學五傳窺遺經。", "因言前哲論災異，占曰庶人皆執兵。", "只應北地干戈起，草木如人刃相倚。", "莫憂胡兒飲泗水，盡道明年佛貍死。"]'),
('35ba8ff4-cede-486e-ae59-c130a846e395','破虜凱歌二十四首  其一','周麟之','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','可笑狂胡到死狂，欲投馬箠渡長江。',32,'全唐诗/poet.song.123000.json','["可笑狂胡到死狂，欲投馬箠渡長江。", "始知人語符天意，東向南朝作鬼降。"]'),
('8e354520-57e7-49c7-9bf1-bfd20df86685','破虜凱歌二十四首  其二','周麟之','宋','宋诗','song-poetry','','[]','采石江頭萬鼓鼙，祭天臺上手揮旗。',32,'全唐诗/poet.song.123000.json','["采石江頭萬鼓鼙，祭天臺上手揮旗。", "坐驅朔馬爲魚鼈，笑殺江南踏浪兒。"]'),
('f4c6ae57-dce9-4f48-8505-50eedff31c3a','破虜凱歌二十四首  其三','周麟之','宋','宋诗','song-poetry','','[]','雲航飛下北通州，弭檝膠西一戰收。',32,'全唐诗/poet.song.123000.json','["雲航飛下北通州，弭檝膠西一戰收。", "千七百艘同日盡，始知飛將有奇謀。"]'),
('ab595156-d42d-4064-9b0d-61d1b1bf3700','破虜凱歌二十四首  其四','周麟之','宋','宋诗','song-poetry','','[]','一從犬吠瞰西山，便報車輪不得還。',32,'全唐诗/poet.song.123000.json','["一從犬吠瞰西山，便報車輪不得還。", "自詭長驅如破竹，不知先衄劍門關。"]'),
('3ef05d20-081a-47bf-8fe2-bb25009a4288','破虜凱歌二十四首  其五','周麟之','宋','宋诗','song-poetry','','[]','虜餓曾無一月糧，煮弦燒箭莫充腸。',32,'全唐诗/poet.song.123000.json','["虜餓曾無一月糧，煮弦燒箭莫充腸。", "南來本恃清河粟，不意偏師夜絕綱。"]'),
('33f6e016-a383-421b-bfad-edc6c6d40753','破虜凱歌二十四首  其六','周麟之','宋','宋诗','song-poetry','','[]','胡人不識九車船，笑理輕舠狎大川。',32,'全唐诗/poet.song.123000.json','["胡人不識九車船，笑理輕舠狎大川。", "莫道老胡曾得濟，猶傳折箭誓青天。"]'),
('46731845-804c-4bdc-89b1-7e65f1425ac1','破虜凱歌二十四首  其七','周麟之','宋','宋诗','song-poetry','','[]','淝河席捲苻堅陣，赤壁灰飛孟德舟。',32,'全唐诗/poet.song.123000.json','["淝河席捲苻堅陣，赤壁灰飛孟德舟。", "二虜猶能脫身去，汝來斷送郅支頭。"]'),
('51b9ac68-7ca3-4e0b-95ed-b9c7df3f8d2a','破虜凱歌二十四首  其八','周麟之','宋','宋诗','song-poetry','','[]','自古御行用衆難，况圖深入冒多艱。',32,'全唐诗/poet.song.123000.json','["自古御行用衆難，况圖深入冒多艱。", "五百萬人存者幾，淮南白骨委如山。"]'),
('ed4f4219-a20e-43d0-b2d2-415c7feb9c39','破虜凱歌二十四首  其九','周麟之','宋','宋诗','song-poetry','','[]','燕山臺殿壓阿房，又欲移巢占大梁。',32,'全唐诗/poet.song.123000.json','["燕山臺殿壓阿房，又欲移巢占大梁。", "起就漢宮三十六，固知無德祇爲殃。"]'),
('4d6365ee-e1ed-4151-933f-45e7a4ee56f7','破虜凱歌二十四首  其一○','周麟之','宋','宋诗','song-poetry','','[]','七寶爲牀坐殿衙，金猊雙立噴飛霞。',32,'全唐诗/poet.song.123000.json','["七寶爲牀坐殿衙，金猊雙立噴飛霞。", "自緣積惡難安享，不得全軀作帝羓。"]'),
('78686403-40b8-44c0-a0c3-ffe07e26f838','破虜凱歌二十四首  其一一','周麟之','宋','宋诗','song-poetry','','[]','只憑信誓畫山河，二十餘年兩國和。',32,'全唐诗/poet.song.123000.json','["只憑信誓畫山河，二十餘年兩國和。", "解道渝盟甘踣國，若爲輕信馬韓哥。"]'),
('23872319-1666-40ee-8638-3e3543760f4d','破虜凱歌二十四首  其一二','周麟之','宋','宋诗','song-poetry','','[]','自聞三策日垂涎，急趁西風一舉鞭。',32,'全唐诗/poet.song.123000.json','["自聞三策日垂涎，急趁西風一舉鞭。", "狼子不知天數盡，據鞍猶說馬兒年。"]'),
('3d263324-b364-416d-afb2-2897e463b03b','破虜凱歌二十四首  其一三','周麟之','宋','宋诗','song-poetry','','[]','黧面長鬚桀黠兒，一生渾事殺人嬉。',32,'全唐诗/poet.song.123000.json','["黧面長鬚桀黠兒，一生渾事殺人嬉。", "莫將遺像欺羣目，曾向貞元殿裏窺。"]'),
('59538b59-ded3-416d-8268-ebeac1e64b5b','破虜凱歌二十四首  其一四','周麟之','宋','宋诗','song-poetry','','[]','何事圖形到九墀，豈容鬼質近神奎。',32,'全唐诗/poet.song.123000.json','["何事圖形到九墀，豈容鬼質近神奎。", "君王欲作諸戎戒，不惜雲章手自題。"]'),
('47a78e82-179f-491e-ba82-a006280e473f','破虜凱歌二十四首  其一五','周麟之','宋','宋诗','song-poetry','','[]','也學賦詩橫槊公，浪拋狂語倡羣凶。',32,'全唐诗/poet.song.123000.json','["也學賦詩橫槊公，浪拋狂語倡羣凶。", "由來立馬元無地，空指吳山第一峰。"]'),
('0f3f59c4-71cb-4c98-9638-69e32b302184','破虜凱歌二十四首  其一六','周麟之','宋','宋诗','song-poetry','','[]','每率羣胡共打圍，防姦惟許屬鞬隨。',32,'全唐诗/poet.song.123000.json','["每率羣胡共打圍，防姦惟許屬鞬隨。", "一朝醉卧隋堤曲，衆箭攢胸死不知。"]'),
('d95a489e-55f8-4047-a58a-2b3755ff50ac','破虜凱歌二十四首  其一七','周麟之','宋','宋诗','song-poetry','','[]','向來燒飯起中都，已覺胡星墮玉除。',32,'全唐诗/poet.song.123000.json','["向來燒飯起中都，已覺胡星墮玉除。", "罪惡貫盈天不赦，區區猶欲禱醫閭。"]'),
('19684174-1ddf-4dcd-9bcd-7a9ba478f442','破虜凱歌二十四首  其一八','周麟之','宋','宋诗','song-poetry','','[]','曾爲兵卜溷神聽，不信名山事火攻。',32,'全唐诗/poet.song.123000.json','["曾爲兵卜溷神聽，不信名山事火攻。", "今日汝魂遊岱去，不知何面向靈宮。"]'),
('843ed1fc-75c8-420b-a228-fc0a67c37c3a','破虜凱歌二十四首  其一九','周麟之','宋','宋诗','song-poetry','','[]','似聞虜帳啟行初，盡擁青氈入故都。',32,'全唐诗/poet.song.123000.json','["似聞虜帳啟行初，盡擁青氈入故都。", "便好乘機收赤縣，長纓更縛北單于。"]'),
('d911c24e-544c-4229-9576-a57f06c4b832','破虜凱歌二十四首  其二○','周麟之','宋','宋诗','song-poetry','','[]','昨從北邙山下過，旋移狼纛駐雞籠。',32,'全唐诗/poet.song.123000.json','["昨從北邙山下過，旋移狼纛駐雞籠。", "此身已是鄰尸冢，又欲飛投鼎鑊中。"]'),
('31ae7503-e100-4195-9449-ea5753870a47','破虜凱歌二十四首  其二一','周麟之','宋','宋诗','song-poetry','','[]','勝負端從曲直分，我軍屢捷氣凌雲。',32,'全唐诗/poet.song.123000.json','["勝負端從曲直分，我軍屢捷氣凌雲。", "坐聽笳鼓傳新曲，不怕蕃家鐵塔軍。"]'),
('951ac24e-7c87-4a62-a021-bb0f9e4fc13d','破虜凱歌二十四首  其二二','周麟之','宋','宋诗','song-poetry','','[]','中興天子漢宣光，自有深仁合彼蒼。',32,'全唐诗/poet.song.123000.json','["中興天子漢宣光，自有深仁合彼蒼。", "天遣百靈爭助順，神兵遍野拂雲長。"]'),
('4c5ee558-60b6-4170-9556-83ca8c3577b4','破虜凱歌二十四首  其二三','周麟之','宋','宋诗','song-poetry','','[]','此日君王自撫師，列營爭望翠華旗。',32,'全唐诗/poet.song.123000.json','["此日君王自撫師，列營爭望翠華旗。", "不失一矢戎酋斃，又勝澶淵却敵時。"]'),
('9a3717d8-3610-4335-8c73-f503b5660fa3','破虜凱歌二十四首  其二四','周麟之','宋','宋诗','song-poetry','','[]','江上春風鳳蓋旋，鬰葱佳氣靄中天。',32,'全唐诗/poet.song.123000.json','["江上春風鳳蓋旋，鬰葱佳氣靄中天。", "從今四海歸圖籍，金殿垂衣億萬年。"]'),
('d6f9f1b2-a1f8-4e42-9325-39b41126a543','景靈宮樂章 皇帝還位乾安之曲','周麟之','宋','宋诗','song-poetry','','[]','帝臨閟庭，逆釐上靈。',40,'全唐诗/poet.song.123000.json','["帝臨閟庭，逆釐上靈。", "神保安坐，肅若有承。", "嘉觴既申，德聞惟馨。", "靈光留俞，祚我億齡。"]'),
('23287fe2-a0fb-4e9d-8b60-4df40a1f6686','景靈宮樂章 尚書徹饌吉安之曲','周麟之','宋','宋诗','song-poetry','','[]','普淖既薦，苾芬孔時。',40,'全唐诗/poet.song.123000.json','["普淖既薦，苾芬孔時。", "神嗜而顧，有來宴娛。", "饗矣將徹，載欽載祗。", "展詩以侑，益臻厥熙。"]'),
('65a3e5f7-cb9e-4c59-bc61-eacc4d145e70','景靈宮樂章 皇帝降殿乾安之曲','周麟之','宋','宋诗','song-poetry','','[]','我秩元祀，上推鴻源。',40,'全唐诗/poet.song.123000.json','["我秩元祀，上推鴻源。", "展事有侐，祲威肅然。", "升墄既降，秉心益虔。", "荷天之休，于千萬年。"]'),
('731e4e2f-7fcf-4c7f-8f9e-119941354b34','景靈宮樂章 皇帝還大次乾安之曲','周麟之','宋','宋诗','song-poetry','','[]','帝將于郊，昭事上祀。',40,'全唐诗/poet.song.123000.json','["帝將于郊，昭事上祀。", "爰茲畢觴，復即于次。", "飈斿載旋，容旌沓騎。", "維皇嘉承，錫祚昌熾。"]'),
('f3ff3720-31ab-404f-b151-687715affaf1','太廟樂章 皇帝盥洗乾安之曲','周麟之','宋','宋诗','song-poetry','','[]','維皇齋精，鬷假于廟。',40,'全唐诗/poet.song.123000.json','["維皇齋精，鬷假于廟。", "觀盥之初，惟以潔告。", "衎承祖宗，恤祀昭孝。", "誠心有孚，介福斯報。"]'),
('890f6cf3-0beb-4143-8c47-edf90b0b694d','太廟樂章 皇帝還位乾安之曲','周麟之','宋','宋诗','song-poetry','','[]','於穆清廟，明禋是躬。',40,'全唐诗/poet.song.123000.json','["於穆清廟，明禋是躬。", "卿士駿奔，助我肅雝。", "灌鬯已事，精誠交通。", "却立以思，僾然其恭。"]'),
('15dc8d94-c36b-4272-ba31-ed131d39fbab','太廟樂章 奉俎豐安之曲','周麟之','宋','宋诗','song-poetry','','[]','有碩其牲，登于大房。',40,'全唐诗/poet.song.123000.json','["有碩其牲，登于大房。", "肅展以饗，庶幾迪嘗。", "匪腯是告，我民其康。", "保艾爾後，垂休無疆。"]'),
('3b500662-dcb1-4fd7-b1c7-d042cbc92b38','太廟樂章 皇帝再盥洗乾安之曲','周麟之','宋','宋诗','song-poetry','','[]','盥至于再，潔誠俞孚。',40,'全唐诗/poet.song.123000.json','["盥至于再，潔誠俞孚。", "帝用祗薦，靈咸嘉虞。", "騰歌臚驩，會于軒朱。", "觀厥顒若，受福之符。"]'),
('0cda2ef0-fb04-4280-ba9f-dec47875b8d5','天申節集英殿大宴樂語口號','周麟之','宋','宋诗','song-poetry','','[]','曉開閶闔黼帷張，五色凝雲捧玉皇。',64,'全唐诗/poet.song.123000.json','["曉開閶闔黼帷張，五色凝雲捧玉皇。", "風入舜絃聲蕩漾，日浮堯莢景舒長。", "猗蘭殿上霞飛棟，華萼樓前露滿囊。", "共指南山申善頌，太平天子萬年觴。"]'),
('3db73c8d-6d8a-4be6-8eb7-ef09bb6f29cd','春貼子詞 皇太后閣六首 其一','周麟之','宋','宋诗','song-poetry','','[]','北極璿杓轉，東朝繡戶開。',24,'全唐诗/poet.song.123000.json','["北極璿杓轉，東朝繡戶開。", "吾皇宴長樂，親捧萬年杯。"]'),
('6ef0baf8-0fca-4492-becc-73f55ce0b1d9','春貼子詞 皇太后閣六首 其二','周麟之','宋','宋诗','song-poetry','','[]','遶殿猗蘭紫，浮觴壽柏青。',24,'全唐诗/poet.song.123000.json','["遶殿猗蘭紫，浮觴壽柏青。", "瑶池演春算，倍受八千齡。"]'),
('1b2858bc-88a6-441b-9dcd-f9f288d13e0e','春貼子詞 皇太后閣六首 其三','周麟之','宋','宋诗','song-poetry','','[]','曉箭催蓮漏，君王問寢時。',24,'全唐诗/poet.song.123000.json','["曉箭催蓮漏，君王問寢時。", "光風浮玉琯，瑞靄映雲旗。"]'),
('8574cab3-bb65-4759-8e99-f575982db814','春貼子詞 皇太后閣六首 其四','周麟之','宋','宋诗','song-poetry','','[]','笑看宮額試梅粧，樓角千絲御柳黄。',32,'全唐诗/poet.song.123000.json','["笑看宮額試梅粧，樓角千絲御柳黄。", "盡道九重春色早，太平天子是東皇。"]'),
('1a18fb93-bdf2-459a-ab03-a8cf5a9b7acb','春貼子詞 皇太后閣六首 其五','周麟之','宋','宋诗','song-poetry','','[]','日照蟠桃萬點丹，花前仙佩響珊珊。',32,'全唐诗/poet.song.123000.json','["日照蟠桃萬點丹，花前仙佩響珊珊。", "他年採實供金母，會見飛瓊捧玉盤。"]'),
('64a0857f-23f9-405d-bf31-28705b7a578f','春貼子詞 皇太后閣六首 其六','周麟之','宋','宋诗','song-poetry','','[]','不用神丹嚥蘂瓊，年登八十自身輕。',32,'全唐诗/poet.song.123000.json','["不用神丹嚥蘂瓊，年登八十自身輕。", "試臨玉案繙金籙，更覺春來眼倍明。"]'),
('52c0eb5d-6fd5-47c8-96eb-06b1b5c1d97e','春貼子詞 皇帝閣六首 其一','周麟之','宋','宋诗','song-poetry','','[]','木鐸揚寬詔，雲翹舞化風。',24,'全唐诗/poet.song.123000.json','["木鐸揚寬詔，雲翹舞化風。", "垂衣金殿裏，聖德與天通。"]'),
('0c613e62-d818-4814-a3ec-3de7ff564cc4','春貼子詞 皇帝閣六首 其二','周麟之','宋','宋诗','song-poetry','','[]','紅日升暘谷，青輝應嶰筩。',24,'全唐诗/poet.song.123000.json','["紅日升暘谷，青輝應嶰筩。", "萬方陶美化，渾在泰和中。"]'),
('afb13551-b921-4578-b0a6-ec76d10fca16','春貼子詞 皇帝閣六首 其三','周麟之','宋','宋诗','song-poetry','','[]','翠水冰融盡，雕櫳日上遲。',24,'全唐诗/poet.song.123000.json','["翠水冰融盡，雕櫳日上遲。", "東風報花信，先拂萬年枝。"]'),
('c07b1fcb-4109-4b38-b8fc-a4987fcb66eb','春貼子詞 皇帝閣六首 其四','周麟之','宋','宋诗','song-poetry','','[]','已過人日迎春馭，直待階蓂十葉開。',32,'全唐诗/poet.song.123000.json','["已過人日迎春馭，直待階蓂十葉開。", "應是九門燈夕近，東皇欲駕六鼇來。"]'),
('8dc1d1b9-8e2d-47fa-85f1-fb4c21818956','春貼子詞 皇帝閣六首 其五','周麟之','宋','宋诗','song-poetry','','[]','鳳蓋龍車玉作輪，北臨紫畤謁三神。',32,'全唐诗/poet.song.123000.json','["鳳蓋龍車玉作輪，北臨紫畤謁三神。", "已將福酒添眉壽，更祝椒觴一萬春。"]'),
('027d6772-7907-4561-b410-2c6345d46454','春貼子詞 皇帝閣六首 其六','周麟之','宋','宋诗','song-poetry','','[]','聖主清心仍寡欲，惟於筆硯未忘懷。',32,'全唐诗/poet.song.123000.json','["聖主清心仍寡欲，惟於筆硯未忘懷。", "彤廷仗下春朝散，獨擁圖書坐損齋。"]'),
('3777226e-d7e9-4ee3-a83f-d4d9c02dc0b4','春貼子詞 皇后閣五首 其一','周麟之','宋','宋诗','song-poetry','','[]','沼荇微生綠，宮梅暗度香。',24,'全唐诗/poet.song.123000.json','["沼荇微生綠，宮梅暗度香。", "五雲凝紫禁，一氣轉青陽。"]'),
('4081a55e-0711-4e2b-87e2-f2cb70576418','春貼子詞 皇后閣五首 其二','周麟之','宋','宋诗','song-poetry','','[]','露沐千門柳，風縈九畹蘭。',24,'全唐诗/poet.song.123000.json','["露沐千門柳，風縈九畹蘭。", "會聽鶑出谷，行傍采桑壇。"]'),
('d094c571-5a65-4a7f-9fef-f3e7f1bcf622','春貼子詞 皇后閣五首 其三','周麟之','宋','宋诗','song-poetry','','[]','勝裏金葩喜占新，紅酥細字點宜春。',32,'全唐诗/poet.song.123000.json','["勝裏金葩喜占新，紅酥細字點宜春。", "內庭也作人間戲，自是時康樂事頻。"]'),
('09a1b538-9949-4b60-b760-c17899bc0901','春貼子詞 皇后閣五首 其四','周麟之','宋','宋诗','song-poetry','','[]','銀鈎慣學君王帖，寶軫頻聽淑女琴。',32,'全唐诗/poet.song.123000.json','["銀鈎慣學君王帖，寶軫頻聽淑女琴。", "更與六宮循節儉，釵頭不綴辟寒金。"]'),
('f8b18fbb-8153-4844-a5e8-d6884bbfeab1','春貼子詞 皇后閣五首 其五','周麟之','宋','宋诗','song-poetry','','[]','椒塗日暖燕差池，又見瑶箱受福時。',32,'全唐诗/poet.song.123000.json','["椒塗日暖燕差池，又見瑶箱受福時。", "欲使後宮歌德化，試將彤管作春詞。"]'),
('53ecc59e-68d2-4be1-9ef8-b1fa0c5139b5','端午貼子詞 皇太后閣六首 其一','周麟之','宋','宋诗','song-poetry','','[]','臯月乘天數，慈闈奉母儀。',24,'全唐诗/poet.song.123000.json','["臯月乘天數，慈闈奉母儀。", "靈芝三萬歲，樂府有新詞。"]'),
('744d5a17-c854-46b1-8e13-319303545ca3','端午貼子詞 皇太后閣六首 其二','周麟之','宋','宋诗','song-poetry','','[]','柳映金鋪麗，菰黏玉俎香。',24,'全唐诗/poet.song.123000.json','["柳映金鋪麗，菰黏玉俎香。", "六宮隨鳳輦，來獻九霞觴。"]'),
('2e80126f-02fb-4647-a573-e20ac3c84e68','端午貼子詞 皇太后閣六首 其三','周麟之','宋','宋诗','song-poetry','','[]','覆戶雙人艾，浮樽九節蒲。',24,'全唐诗/poet.song.123000.json','["覆戶雙人艾，浮樽九節蒲。", "更聞天子孝，瑞箑扇堯厨。"]'),
('7b2075fa-7f81-4d4e-96c7-587d2c7b59ff','端午貼子詞 皇太后閣六首 其四','周麟之','宋','宋诗','song-poetry','','[]','凉生浴殿藹蘭芳，玉宇深沈晝漏長。',32,'全唐诗/poet.song.123000.json','["凉生浴殿藹蘭芳，玉宇深沈晝漏長。", "試誦瓊章開蘂笈，御爐風裊辟邪香。"]'),
('642531e3-ff51-43fd-b5de-0221937996cf','端午貼子詞 皇太后閣六首 其五','周麟之','宋','宋诗','song-poetry','','[]','慈歡不爲植萱叢，聖子晨昏孝養隆。',32,'全唐诗/poet.song.123000.json','["慈歡不爲植萱叢，聖子晨昏孝養隆。", "況是九重當夏凊，偏于扇枕得清風。"]'),
('6f257861-537f-4638-94a5-4e4aa2e41fdc','端午貼子詞 皇太后閣六首 其六','周麟之','宋','宋诗','song-poetry','','[]','方開八袠慶修齡，又捧榴盃拜紫庭。',32,'全唐诗/poet.song.123000.json','["方開八袠慶修齡，又捧榴盃拜紫庭。", "一歲一添長命縷，擬將萬縷獻慈寧。"]'),
('17c38a17-f413-45de-b1a4-557221e1097d','端午貼子詞 皇帝閣六首 其一','周麟之','宋','宋诗','song-poetry','','[]','赤伏題皇運，朱明敞帝宸。',24,'全唐诗/poet.song.123000.json','["赤伏題皇運，朱明敞帝宸。", "休符知有相，此月是天申。"]'),
('bf905f82-1602-422d-ae84-55f6a4ffa6fd','端午貼子詞 皇帝閣六首 其二','周麟之','宋','宋诗','song-poetry','','[]','祝網湯仁布，垂裳舜德敷。',24,'全唐诗/poet.song.123000.json','["祝網湯仁布，垂裳舜德敷。", "五兵渾不用，安事赤靈符。"]'),
('d01bf898-faee-49ec-8f22-06c4e019beeb','端午貼子詞 皇帝閣六首 其三','周麟之','宋','宋诗','song-poetry','','[]','日永三星正，風薰萬宇凉。',24,'全唐诗/poet.song.123000.json','["日永三星正，風薰萬宇凉。", "要知垂艾意，期與庶民康。"]'),
('4cd7efe2-b355-4335-89bb-74617256adca','端午貼子詞 皇帝閣六首 其四','周麟之','宋','宋诗','song-poetry','','[]','槐綠乍迷青羽蓋，櫻紅已薦赤瑛盤。',32,'全唐诗/poet.song.123000.json','["槐綠乍迷青羽蓋，櫻紅已薦赤瑛盤。", "太平節物年年好，又見浮菖與浴蘭。"]'),
('ed791e65-3711-4d9c-a51d-db2558b615af','端午貼子詞 皇帝閣六首 其五','周麟之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖雨歇鑑奩開，江面銀濤一線來。',32,'全唐诗/poet.song.123000.json','["西湖雨歇鑑奩開，江面銀濤一線來。", "自有雲山供四座，聖君元不事池臺。"]'),
('82648d20-b175-4271-a5c4-33fb4fe92d17','端午貼子詞 皇帝閣六首 其六','周麟之','宋','宋诗','song-poetry','','[]','碧琳宮殿晝翻書，時見龍鸞落寶跗。',32,'全唐诗/poet.song.123000.json','["碧琳宮殿晝翻書，時見龍鸞落寶跗。", "一念清非能却暑，不須更展北風圖。"]'),
('16f6753d-28fa-4c9f-8fe0-bf8083592950','端午貼子詞 皇后閣五首 其一','周麟之','宋','宋诗','song-poetry','','[]','瑞靄浮龍鑑，凉颸拂燕釵。',24,'全唐诗/poet.song.123000.json','["瑞靄浮龍鑑，凉颸拂燕釵。", "瑶鍾獻冰醴，暑殿雪盈懷。"]'),
('d827040a-3ffb-4b48-8016-77b68e8654a5','端午貼子詞 皇后閣五首 其二','周麟之','宋','宋诗','song-poetry','','[]','繞臂長生縷，無非柘館絲。',24,'全唐诗/poet.song.123000.json','["繞臂長生縷，無非柘館絲。", "還因袗絺綌，深念葛覃詩。"]'),
('7b6f39be-34da-46b0-92d8-ae38216e26aa','端午貼子詞 皇后閣五首 其三','周麟之','宋','宋诗','song-poetry','','[]','甘霔令年應禱祈，屏除葷茹與君齊。',32,'全唐诗/poet.song.123000.json','["甘霔令年應禱祈，屏除葷茹與君齊。", "化行自是恩波遠，何止春郊雨一犁。"]'),
('77d9ac0f-68a3-4964-92d8-63575e044547','端午貼子詞 皇后閣五首 其四','周麟之','宋','宋诗','song-poetry','','[]','不貪鬭草事詩書，漫採香芸辟蠹魚。',32,'全唐诗/poet.song.123000.json','["不貪鬭草事詩書，漫採香芸辟蠹魚。", "永日揮毫自忘暑，滴殘宮硯玉蟾蜍。"]'),
('5d83b9d2-e3a7-49d0-927e-a1359b543208','端午貼子詞 皇后閣五首 其五','周麟之','宋','宋诗','song-poetry','','[]','剪就冰綃月影團，不須多羨女乘鸞。',32,'全唐诗/poet.song.123000.json','["剪就冰綃月影團，不須多羨女乘鸞。", "君王瑶札親題處，一樣蟾花點點丹。"]'),
('f7f2f1f8-64be-4723-a19a-c23d3cd81dfa','句  其一','周麟之','宋','宋诗','song-poetry','','[]','月摹瘦影橫窗淡，雨沐疏花照水明。',16,'全唐诗/poet.song.123000.json','["月摹瘦影橫窗淡，雨沐疏花照水明。"]'),
('4e03a284-ec18-4a55-89ff-90db8a3be51a','句  其二','周麟之','宋','宋诗','song-poetry','','[]','醉倒不辭花面笑，詩成親傍竹身題。',16,'全唐诗/poet.song.123000.json','["醉倒不辭花面笑，詩成親傍竹身題。"]'),
('418cb538-af18-430a-a4fb-b5d5eaeb910a','題鄭氏籯金堂','汪應辰','宋','宋诗','song-poetry','','[]','子雲抱遺經，寂寞饑欲死。',60,'全唐诗/poet.song.123000.json','["子雲抱遺經，寂寞饑欲死。", "誰家千金郎，車馬塞閭里。", "如何今世人，持此欲勝彼。", "要知聖賢心，不爲取青紫。", "冷暖自所知，吾言聊爾爾。"]'),
('a86b66b6-d1ac-4c16-bcfd-5953abf63d9c','題法海院龍溪亭','汪應辰','宋','宋诗','song-poetry','','[]','微茫雲兩角，屈曲路一綫。',132,'全唐诗/poet.song.123000.json','["微茫雲兩角，屈曲路一綫。", "未容快先睹，已歎行百轉。", "流溪何從來，神物昔嘗玩。", "輿梁儼堅牢，亭宇復明絢。", "豈惟濟病涉，更可供息宴。", "信哉善知識，作此巧方便。", "茂樾兩交蓋，清風四揮扇。", "祇恐境中人，却有桑下戀。", "臺山不須問，此去直如箭。", "何妨酌靈水，一洗眼花眩。", "舉頭未及眸，已知梵王殿。"]'),
('18f6df0b-5400-4ee3-8a3f-ac1e53b84a81','和遊南巖','汪應辰','宋','宋诗','song-poetry','','[]','南峰不藏善，逢人說南巖。',180,'全唐诗/poet.song.123000.json','["南峰不藏善，逢人說南巖。", "南巖亦何好，造化秘此緘。", "烟雲印全提，松竹色半酣。", "去郭十里贏，守戒僧二三。", "乞身滿一日，幽事亦可探。", "行客問征途，居者索轡銜。", "蕭條野店烟，夐靜彌勒龕。", "念非塵外侶，不分禪味甘。", "受傭作閒人，自縛亦何慙。", "于時日在房，山色染蔚藍。", "一徑盤鬰青，羣峰列空嵌。", "冷泉計涓滴，瀹鼎消塵凡。", "端如常德靜，可警疾步貪。", "聯鑣出雲門，回首憐烟嵐。", "公其吐妙語，勝事須指南。"]'),
('8eb7f2b6-65bf-4198-97ca-e501f7f03ad7','借舍人呂丈送大雅東還詩韵奉呈','汪應辰','宋','宋诗','song-poetry','','[]','典刑寄老成，師友須淵源。',84,'全唐诗/poet.song.123000.json','["典刑寄老成，師友須淵源。", "今代紫薇公，身退道益尊。", "言行無表襮，卓然中所存。", "雲雨自翻覆，誰能動毫分。", "洗垢既無垢，尚或求瘢痕。", "嗟我與徐子，昔也掃公門。", "相期膏吾車，從公畢斯文。"]'),
('74164f8f-9344-4bbb-8457-521784b1ef39','暮春','汪應辰','宋','宋诗','song-poetry','','[]','閉門聽風雨，不知門外春。',48,'全唐诗/poet.song.123000.json','["閉門聽風雨，不知門外春。", "茲辰聊散步，霽色如相親。", "日月不吾與，花柳隨時新。", "悠悠竟何事，悚然懷故人。"]'),
('2a86562b-246a-4f70-bc1c-246bbc010672','家叔沚次暮春韵呈知止祕校','汪應辰','宋','宋诗','song-poetry','','[]','一日復一日，山間已暮春。',48,'全唐诗/poet.song.123000.json','["一日復一日，山間已暮春。", "人事有怵迫，景物無疏親。", "誰知一雨後，滿目皆懷新。", "風光欠管領，付與得閒人。"]'),
('f9bd1c24-4741-415d-951c-327cea9402b9','再用前韵','汪應辰','宋','宋诗','song-poetry','','[]','駕言寫我憂，一覽無邊春。',48,'全唐诗/poet.song.123000.json','["駕言寫我憂，一覽無邊春。", "先生方閉戶，不可得而親。", "寧逐兒女戲，要觀物化新。", "不見舞雩下，冠者五六人。"]'),
('9516fdb2-815b-4dc2-9dcf-f12335b9c3c2','復次數語呈知止','汪應辰','宋','宋诗','song-poetry','','[]','斯道有張弛，如天有冬春。',48,'全唐诗/poet.song.123000.json','["斯道有張弛，如天有冬春。", "雍容貴可久，促迫終難親。", "槁枿久乃腐，流水汲逾新。", "雖云不窺圃，乘馬復何人。"]'),
('620b9256-2957-4f8b-bcc0-07473488f81a','尤美軒','汪應辰','宋','宋诗','song-poetry','','[]','巉然絕壑臨招提，仰視疑欲干晴霓。',208,'全唐诗/poet.song.123000.json','["巉然絕壑臨招提，仰視疑欲干晴霓。", "林巒獻狀還左右，烟雲變相隨高低。", "少日登高不憚遠，喘汗赬顔如夏畦。", "却憑軒檻認行處，一覽不待窮攀躋。", "愛山願作此軒客，饑火驅出仍東西。", "青衫烏帽犯塵土，夢想春綠浮鳧鷖。", "歸尋舟刻劍已往，扁榜僅能存舊題。", "道人知我若有失，更附山房拂栱梯。", "方欣勝觀還昔時，忽訝妙語來磻溪。", "茫茫六合有安宅，恍悟十年行路迷。", "甘與山僧爲逆旅，自使婦姑相勃谿。", "暗明通壅悉還汝，無所還者吾其棲。", "但慙屋上復加屋，空費囊中金褭蹄。"]'),
('42fffb2d-09ee-48ab-b817-fe6b2902e759','送刪定聞人丈歸嘉禾','汪應辰','宋','宋诗','song-poetry','','[]','漫作中都士，柴門每自扃。',48,'全唐诗/poet.song.123000.json','["漫作中都士，柴門每自扃。", "遺經究終始，奇字講聲形。", "前輩今無幾，微言世莫聽。", "扁舟轉河曲，已見故山青。"]'),
('a6c36159-3546-414c-85eb-97baea4b7416','題表上人卷舒軒','汪應辰','宋','宋诗','song-poetry','','[]','高軒聊自娛，俯仰稱幽居。',48,'全唐诗/poet.song.123000.json','["高軒聊自娛，俯仰稱幽居。", "世道有興廢，人心隨卷舒。", "圓機應有此，膠柱合何如。", "愧匪許詢輩，時來問滿虛。"]'),
('b9f6a617-16e6-4b98-a874-3c365b7cffac','陶山書院','汪應辰','宋','宋诗','song-poetry','','[]','陶山讀書處，景物自天成。',48,'全唐诗/poet.song.123000.json','["陶山讀書處，景物自天成。", "幽澗菁莪盛，高岡彩鳳鳴。", "雨餘山色秀，雲浄月華明。", "靜聽寒泉響，潺潺洙泗聲。"]'),
('90b6e2e8-84bc-47a9-81c7-3d39e234fa2d','輓侍讀龍圖學士周公','汪應辰','宋','宋诗','song-poetry','','[]','四海聲名久，中朝德齒優。',48,'全唐诗/poet.song.123000.json','["四海聲名久，中朝德齒優。", "金華方入侍，琳館遽歸休。", "全福人皆仰，孤風世莫留。", "老成零落盡，不獨爲吾州。"]'),
('87f8ad65-369d-42fa-bb93-3d01f8f5101e','輓參政王公','汪應辰','宋','宋诗','song-poetry','','[]','轍迹環吳蜀，艱難嘆委頻。',48,'全唐诗/poet.song.123000.json','["轍迹環吳蜀，艱難嘆委頻。", "秉鈞纔數月，去國竟終身。", "文武才猷遠，經綸事業新。", "襄陽耆舊傳，寧復有斯人。"]'),
('74970dc7-8c90-4912-8383-7a2f6ea0ee20','輓學士張公','汪應辰','宋','宋诗','song-poetry','','[]','俎豆平生事，逢時却論兵。',48,'全唐诗/poet.song.123000.json','["俎豆平生事，逢時却論兵。", "幄中多妙畫，閫外即長城。", "曾未登三府，何言夢兩楹。", "空餘行樂處，畫像儼如生。"]'),
('f9c706fa-dafe-49bf-bb75-1cd9b8afe1c6','輓詹事陳公','汪應辰','宋','宋诗','song-poetry','','[]','給諫皆言責，論思本從臣。',48,'全唐诗/poet.song.123000.json','["給諫皆言責，論思本從臣。", "獨公真舉職，臨事肯謀身。", "再起名尤重，全歸跡已陳。", "空嗟古遺直，無復見斯人。"]'),
('aeec55f9-5bf8-4b8c-8423-dec4639e4565','輓呂舍人二首  其一','汪應辰','宋','宋诗','song-poetry','','[]','連蹇成遺老，纔聞直禁林。',48,'全唐诗/poet.song.123000.json','["連蹇成遺老，纔聞直禁林。", "是非終不屈，進退了無心。", "萬事邯鄲夢，千秋正始音。", "心知公不朽，霣涕自難禁。"]'),
('428ff1be-e740-4752-bbac-1a60fbf561b7','輓呂舍人二首  其二','汪應辰','宋','宋诗','song-poetry','','[]','接物初無間，微言獨得聞。',48,'全唐诗/poet.song.123000.json','["接物初無間，微言獨得聞。", "相期深造道，不爲細論文。", "自有高山仰，誰知半路分。", "新阡疑可望，目斷只愁雲。"]'),
('a339cd87-e46d-4e7d-9ced-f23dfef52d21','輓宣撫吳郡王二首  其一','汪應辰','宋','宋诗','song-poetry','','[]','節義家傳久，艱難始見忠。',48,'全唐诗/poet.song.123000.json','["節義家傳久，艱難始見忠。", "一心惟徇國，百戰竟平戎。", "環列周廬肅，官儀道路同。", "細看麟閣上，誰得似初終。"]'),
('fd1af402-0a76-4a95-929e-2c9af032b9c0','輓宣撫吳郡王二首  其二','汪應辰','宋','宋诗','song-poetry','','[]','太傅元功首，汾陽異姓王。',48,'全唐诗/poet.song.123000.json','["太傅元功首，汾陽異姓王。", "恩榮兼二美，聲跡遠相望。", "名載風雲會，神遊水月鄉。", "維師空贈典，無復見鷹揚。"]'),
('e639b6b1-63cd-4c8b-aae0-b79d2c173bb5','雪中梅花','汪應辰','宋','宋诗','song-poetry','','[]','風弄蘆簾掩復開，閉門一室此徘徊。',64,'全唐诗/poet.song.123000.json','["風弄蘆簾掩復開，閉門一室此徘徊。", "故人難望扁舟至，遠信誰憑驛使回。", "窗外不知飛霰集，坐中只覺暗香來。", "新詩亟報春消息，不待天邊看斗魁。"]'),
('41b3e290-f633-43aa-b52f-efa5d55e27cc','與談命鄭柯山','汪應辰','宋','宋诗','song-poetry','','[]','柯山落魄一仙翁，二十八宿羅胸中。',64,'全唐诗/poet.song.123000.json','["柯山落魄一仙翁，二十八宿羅胸中。", "學術該通明若鑑，襟期豁達氣如虹。", "醺醺痛飲一樓月，落落高談千古風。", "一本流年無惜示，貯之他日驗窮通。"]'),
('5a44a99e-0ad1-4c70-93fc-dc53bd72678a','陳經略生朝四首  其一','汪應辰','宋','宋诗','song-poetry','','[]','喜詠高秋此日生，門閭佳氣想充盈。',64,'全唐诗/poet.song.123000.json','["喜詠高秋此日生，門閭佳氣想充盈。", "堂堂體貌千鈞重，凜凜精神一座傾。", "暫使遠民瞻玉帳，要知聖主有金城。", "兜牟却作貂蟬去，五筦難淹宋廣平。"]'),
('3d7cbd25-62e5-4246-bb85-567ac7561523','陳經略生朝四首  其二','汪應辰','宋','宋诗','song-poetry','','[]','媯姓從來莫與京，傳家初不爲金籯。',64,'全唐诗/poet.song.123000.json','["媯姓從來莫與京，傳家初不爲金籯。", "只今八桂蒼蒼處，倍覺中台兩兩明。", "南徼不聞刁斗擊，北轅行見衮衣迎。", "定知天錫公難老，端與邦家立太平。"]'),
('ee81ba0f-99cf-491f-9348-c0a6c072d196','陳經略生朝四首  其三','汪應辰','宋','宋诗','song-poetry','','[]','俛視人寰但一漚，應緣來作聖時遊。',64,'全唐诗/poet.song.123000.json','["俛視人寰但一漚，應緣來作聖時遊。", "英風蓋世桂林伯，相業傳家戶牖侯。", "號召即看持玉節，姓名已久覆金甌。", "他時欲記中書考，簡策應須汗馬牛。"]'),
('d14708d3-2949-4dd1-8bde-2693e27ea476','陳經略生朝四首  其四','汪應辰','宋','宋诗','song-poetry','','[]','欲知今歲好生朝，召節翩翩下九霄。',64,'全唐诗/poet.song.123000.json','["欲知今歲好生朝，召節翩翩下九霄。", "便入三槐新位次，空餘八桂舊歌謠。", "機神照物宜前列，質幹參天合後凋。", "他日凌烟圖畫處，方瞳炯炯映金貂。"]'),
('028ca7bd-0591-4d29-a8a8-ab961215ef8c','送陳經略二首  其一','汪應辰','宋','宋诗','song-poetry','','[]','英姿卓犖衆長兼，暫假威名鎮嶠南。',64,'全唐诗/poet.song.123000.json','["英姿卓犖衆長兼，暫假威名鎮嶠南。", "忽報郵音馳尺一，即看躔次近魁三。", "照人風采誰居右，致主功名在立談。", "遠俗豈知如許事，只言無計駐征驂。"]'),
('e85b62f3-26e2-4a6b-9c82-707a82715026','送陳經略二首  其二','汪應辰','宋','宋诗','song-poetry','','[]','清明公正復慈祥，觸眼平生見未嘗。',64,'全唐诗/poet.song.123000.json','["清明公正復慈祥，觸眼平生見未嘗。", "自幸來依驃騎幕，如何又趣舍人裝。", "雲霄去路日千里，萍梗微蹤天一方。", "獨有此心無遠近，歲寒猶欲試冰霜。"]'),
('e62b1ad7-22bc-448a-9d96-af4ebda5cd1e','分韵送胡丈歸建安','汪應辰','宋','宋诗','song-poetry','','[]','先生高卧武夷巔，一旦趨朝豈偶然。',64,'全唐诗/poet.song.123000.json','["先生高卧武夷巔，一旦趨朝豈偶然。", "報國自期如皦日，歸田曾不待來年。", "懷鉛共嘆楊雄老，鞭馬今輸祖逖先。", "冊府風流久寥落，送行始復有詩篇。"]'),
('3b3b0bd0-65cc-4c55-b107-ef2dd397c4e3','偶見文子失舉後詩次韵以廣其志','汪應辰','宋','宋诗','song-poetry','','[]','落落開談四座驚，已應俊氣壓諸生。',64,'全唐诗/poet.song.123000.json','["落落開談四座驚，已應俊氣壓諸生。", "高山意遠難知己，白雪詞高絕和聲。", "此道要須齊得喪，古人初不爲功名。", "芬芳各自隨時耳，何用臨風嗅决明。"]'),
('7fd94e54-5e24-477d-92b8-7fefbc24e491','鹿鳴宴席上詩二首奉送解元諸先輩  其一','汪應辰','宋','宋诗','song-poetry','','[]','從來人物數成都，果見英髦入薦書。',64,'全唐诗/poet.song.123000.json','["從來人物數成都，果見英髦入薦書。", "齊魯風流方演迤，淵雲文采自紆餘。", "姓名即上飛龍榜，鄉里爭迎駟馬車。", "聖世取才三尺在，但慚無地更吹噓。"]'),
('a1a1d918-fb26-4821-8f27-410c1205d0c1','鹿鳴宴席上詩二首奉送解元諸先輩  其二','汪應辰','宋','宋诗','song-poetry','','[]','嘉賓式燕正炎曦，風自南來爲解圍。',64,'全唐诗/poet.song.123000.json','["嘉賓式燕正炎曦，風自南來爲解圍。", "細聽吹笙仍鼓瑟，即看結綬却登畿。", "清朝不用齎刀布，晝日偏宜著錦衣。", "太守自憐推不去，棧羊釃酒待還歸。"]'),
('48733fd7-88a1-4c98-bb22-0caf05f3c4a4','宜春漫述','汪應辰','宋','宋诗','song-poetry','','[]','本是扶犁客，隨緣漫作官。',24,'全唐诗/poet.song.123000.json','["本是扶犁客，隨緣漫作官。", "故山應念我，薇蕨已闌干。"]'),
('9c49e172-c132-45e4-8a65-955f1858dc17','歸雲堂','汪應辰','宋','宋诗','song-poetry','','[]','浮雲本無心，人心逐雲去。',24,'全唐诗/poet.song.123000.json','["浮雲本無心，人心逐雲去。", "更作歸雲堂，雲歸竟何處。"]'),
('eef41ec0-9d02-43c2-a788-3ff23d4a7f68','送沖公謁六祖道場','汪應辰','宋','宋诗','song-poetry','','[]','直指嶺頭路，寧論幾日回。',24,'全唐诗/poet.song.123000.json','["直指嶺頭路，寧論幾日回。", "尋春有消息，寄我一枝梅。"]'),
('224015cf-3f01-4416-a914-32a145da43a9','宜春士愿樸而虛蒙珥筆之名每欲爲邦人一洗之偶筆工傅氏求詩作此','汪應辰','宋','宋诗','song-poetry','','[]','只今頭上半儒冠，誰肯公庭弄舌端。',32,'全唐诗/poet.song.123000.json','["只今頭上半儒冠，誰肯公庭弄舌端。", "試問毛錐將底用，奪標他日萬人看。"]'),
('25444946-3227-4173-87a9-aec07711656a','與酒家沈生','汪應辰','宋','宋诗','song-poetry','','[]','有客堂堂空兩手，無人爲借太阿來。',32,'全唐诗/poet.song.123000.json','["有客堂堂空兩手，無人爲借太阿來。", "與君上抉浮雲破，放出陽光萬丈開。"]'),
('257893b1-f9ec-4225-9314-8952886994d0','送王獻可歸信州','汪應辰','宋','宋诗','song-poetry','','[]','月旦于今合改評，一官謀食百無能。',32,'全唐诗/poet.song.123000.json','["月旦于今合改評，一官謀食百無能。", "君歸錦里人應問，好箇藍田崔縣丞。"]'),
('69802aa8-cc9f-46bf-bbff-f2d9ebe7d112','次漢英教授示和尹少稷韵四首  其一','汪應辰','宋','宋诗','song-poetry','','[]','五車拄腹成何事，空受才名二十年。',32,'全唐诗/poet.song.123000.json','["五車拄腹成何事，空受才名二十年。", "一壑生涯長齟齬，邇來行李已三遷。"]'),
('22b947e8-95b8-4849-872c-826d5695a4ae','次漢英教授示和尹少稷韵四首  其二','汪應辰','宋','宋诗','song-poetry','','[]','淵明心遠自無塵，豈必山涯與水濱。',32,'全唐诗/poet.song.123000.json','["淵明心遠自無塵，豈必山涯與水濱。", "雲氣日佳飛鳥樂，寥寥此意付何人。"]'),
('90e73f9f-25dd-49ea-8f2a-7415a1b43b5d','次漢英教授示和尹少稷韵四首  其三','汪應辰','宋','宋诗','song-poetry','','[]','疇昔持心欲見賢，肯容閭巷快爭先。',32,'全唐诗/poet.song.123000.json','["疇昔持心欲見賢，肯容閭巷快爭先。", "豈知咫尺隔千里，空誦白雲長在天。"]'),
('e2fecb72-6c03-4c96-aee2-502f506f333c','次漢英教授示和尹少稷韵四首  其四','汪應辰','宋','宋诗','song-poetry','','[]','頖宮夫子日扃門，厭聽兒曹說怨恩。',32,'全唐诗/poet.song.123000.json','["頖宮夫子日扃門，厭聽兒曹說怨恩。", "猶念貧交無與樂，時流妙語到荒村。"]'),
('207fd76f-ec4a-4ccc-a06f-aef53af16f7b','池荷','汪應辰','宋','宋诗','song-poetry','','[]','香分浄社色專城，冠蓋如雲照乘明。',32,'全唐诗/poet.song.123000.json','["香分浄社色專城，冠蓋如雲照乘明。", "曉露浥妝秋艷曳，凉風吹月夜經營。"]'),
('18490a99-6ed6-400a-b4c6-faee5abaa69e','琵琶洲','汪應辰','宋','宋诗','song-poetry','','[]','塞外風烟能記否，天涯落日自心知。',32,'全唐诗/poet.song.123000.json','["塞外風烟能記否，天涯落日自心知。", "眼中景物參差是，只欠江州司馬詩。"]'),
('46dce768-3728-4541-a719-c1d1f6e4a6a0','蕨初生','汪應辰','宋','宋诗','song-poetry','','[]','一拳打破地皮穿，拏住春風不放拳。',32,'全唐诗/poet.song.123000.json','["一拳打破地皮穿，拏住春風不放拳。", "直待子規啼夜月，放開青掌始朝天。"]'),
('de310e19-859d-43c1-8bf8-2cd551246abe','牽牛花','汪應辰','宋','宋诗','song-poetry','','[]','葉細枝柔獨立難，誰人擡起傍闌干。',32,'全唐诗/poet.song.124000.json','["葉細枝柔獨立難，誰人擡起傍闌干。", "一朝引上簷楹去，不許時人眼下看。"]'),
('763f8417-5ee1-4751-94b0-4726434852cd','送陳德潤赴惠州','汪應辰','宋','宋诗','song-poetry','','[]','山行五日到崇安，欲往從之尚阻艱。',32,'全唐诗/poet.song.124000.json','["山行五日到崇安，欲往從之尚阻艱。", "聞說惠州天樣遠，幾時音問落人間。"]'),
('fd69810d-744e-4df6-bc08-8fedc626cbb8','宜春書事','汪應辰','宋','宋诗','song-poetry','','[]','饑寒驅出故山來，俗事如麻撥不開。',32,'全唐诗/poet.song.124000.json','["饑寒驅出故山來，俗事如麻撥不開。", "問我此行何所得，未嘗識面有澹臺。"]'),
('808d5e3a-8feb-4417-bf67-1bb521a238a6','題常山孔塢碧照閣','汪應辰','宋','宋诗','song-poetry','','[]','門前塵土暗衣冠，池館無多意已寬。',32,'全唐诗/poet.song.124000.json','["門前塵土暗衣冠，池館無多意已寬。", "試問主人閒適味，冰蠶正自不知寒。"]'),
('c0cdf7ad-0920-4bb7-9954-21e44325f9f7','端午帖子詞皇帝閤  其一','汪應辰','宋','宋诗','song-poetry','','[]','聖德臨尊極，民心戴至仁。',24,'全唐诗/poet.song.124000.json','["聖德臨尊極，民心戴至仁。", "喜逢重午節，共祝萬年春。"]'),
('e18709d2-abc2-498f-b237-5d450046420b','端午帖子詞皇帝閤  其二','汪應辰','宋','宋诗','song-poetry','','[]','雨暘皆應節，和氣滿平疇。',24,'全唐诗/poet.song.124000.json','["雨暘皆應節，和氣滿平疇。", "欲識天顔喜，農家麥有秋。"]'),
('46622d9f-251e-495e-a8c3-6ac6e7b12142','端午帖子詞皇帝閤  其三','汪應辰','宋','宋诗','song-poetry','','[]','永日雖祥鬰，風生殿閣凉。',24,'全唐诗/poet.song.124000.json','["永日雖祥鬰，風生殿閣凉。", "聖心非獨樂，均施徧多方。"]'),
('4a0b7362-50bf-4dcc-b0a4-a8ebc38445bd','端午帖子詞皇帝閤  其四','汪應辰','宋','宋诗','song-poetry','','[]','躬行盛德基王化，密贊成謀授帝圖。',32,'全唐诗/poet.song.124000.json','["躬行盛德基王化，密贊成謀授帝圖。", "福及萬方天所相，祛邪何假佩靈符。"]'),
('96125084-c5e9-43e3-803f-aabd31ff328b','端午帖子詞皇帝閤  其五','汪應辰','宋','宋诗','song-poetry','','[]','王業艱難素所知，歲單喜見獻新絲。',32,'全唐诗/poet.song.124000.json','["王業艱難素所知，歲單喜見獻新絲。", "盤中更進長生縷，却記親蠶繭館時。"]'),
('8b5e6859-08d8-49ce-a9cf-312cfcf0636a','端午帖子詞皇帝閤  其六','汪應辰','宋','宋诗','song-poetry','','[]','萬年珍木綠陰成，殿閣微凉次第生。',32,'全唐诗/poet.song.124000.json','["萬年珍木綠陰成，殿閣微凉次第生。", "簡靜初非拘月令，懷沖履正自心清。"]'),
('8a381c84-352b-48b5-82f4-6dd8edbc3df9','太上皇帝閤端午帖子詞  其一','汪應辰','宋','宋诗','song-poetry','','[]','道大光今古，功成付聖明。',24,'全唐诗/poet.song.124000.json','["道大光今古，功成付聖明。", "超然羣物表，但見四時行。"]'),
('695f9fd7-9e2c-4ae6-bdae-61ccb2bcc37f','太上皇帝閤端午帖子詞  其二','汪應辰','宋','宋诗','song-poetry','','[]','漏轉銅壺永，風來玉殿清。',24,'全唐诗/poet.song.124000.json','["漏轉銅壺永，風來玉殿清。", "天申佳節近，比屋盡歡聲。"]'),
('d5b06107-f5d6-4069-b9d1-bfa0b526f732','太上皇帝閤端午帖子詞  其三','汪應辰','宋','宋诗','song-poetry','','[]','外物雖無累，誠心每在民。',24,'全唐诗/poet.song.124000.json','["外物雖無累，誠心每在民。", "薰風能解慍，亦足助堯仁。"]'),
('a864c86c-3de8-43a6-8e3d-a316079b9c12','太上皇帝閤端午帖子詞  其四','汪應辰','宋','宋诗','song-poetry','','[]','金碧叢中翠艾垂，正當午日一朝時。',32,'全唐诗/poet.song.124000.json','["金碧叢中翠艾垂，正當午日一朝時。", "君王自進長生縷，細剪菖蒲泛玉巵。"]'),
('c344ea17-11e3-49d6-add0-d8adacda4a74','太上皇帝閤端午帖子詞  其五','汪應辰','宋','宋诗','song-poetry','','[]','絃歌密意寄南風，豈易形容長養功。',32,'全唐诗/poet.song.124000.json','["絃歌密意寄南風，豈易形容長養功。", "地厚天高何以報，祝堯惟有壽無窮。"]'),
('6de50618-3f61-4a78-acbb-37599563878d','太上皇帝閤端午帖子詞  其六','汪應辰','宋','宋诗','song-poetry','','[]','飛來峰下水泉清，臺沼經營不日成。',32,'全唐诗/poet.song.124000.json','["飛來峰下水泉清，臺沼經營不日成。", "勝境自超塵世外，何須方士覓蓬瀛。"]'),
('ee5e2315-b3c0-4338-9ba6-7e5ac6ebf962','太上皇帝閤端午帖子詞  其七','汪應辰','宋','宋诗','song-poetry','','[]','火德方居夏，端符帝運亨。',24,'全唐诗/poet.song.124000.json','["火德方居夏，端符帝運亨。", "化工初不宰，繼照付重明。"]'),
('fb07f963-1269-4470-bd01-57b34d44d608','太上皇帝閤端午帖子詞  其八','汪應辰','宋','宋诗','song-poetry','','[]','和樂天申節，雍容物外身。',24,'全唐诗/poet.song.124000.json','["和樂天申節，雍容物外身。", "羣生蒙長養，誰復識堯仁。"]'),
('f2a76444-67b3-45c2-ab53-ca4d6520e847','太上皇帝閤端午帖子詞  其九','汪應辰','宋','宋诗','song-poetry','','[]','水殿風來細，槐庭日度遲。',24,'全唐诗/poet.song.124000.json','["水殿風來細，槐庭日度遲。", "聖心無外累，動息自隨時。"]'),
('fc98c9e8-0cbb-44ed-af02-a42fdd231673','太上皇帝閤端午帖子詞  其一○','汪應辰','宋','宋诗','song-poetry','','[]','聖治從來本好生，擬銷劍戟助農耕。',32,'全唐诗/poet.song.124000.json','["聖治從來本好生，擬銷劍戟助農耕。", "此心自與天無間，豈待丹繒始辟兵。"]'),
('ec92840d-ad86-4884-87cc-0ec17c5e6f2c','太上皇帝閤端午帖子詞  其一一','汪應辰','宋','宋诗','song-poetry','','[]','年年時節近天申，喜氣歡聲逐日新。',32,'全唐诗/poet.song.124000.json','["年年時節近天申，喜氣歡聲逐日新。", "請祝聖人如一口，定知德壽萬年春。"]'),
('5e7b3652-452b-42d4-936f-93de688f49c5','太上皇帝閤端午帖子詞  其一二','汪應辰','宋','宋诗','song-poetry','','[]','冷泉堂上湖山勝，聚景園中草木芳。',32,'全唐诗/poet.song.124000.json','["冷泉堂上湖山勝，聚景園中草木芳。", "萬物欣欣供燕樂，自然祥暑變清凉。"]'),
('8e1d1605-fdd0-4cf9-b64d-acd60ebc7611','太上皇后閤端午帖子詞  其一','汪應辰','宋','宋诗','song-poetry','','[]','周室興王業，堯圖授聖人。',24,'全唐诗/poet.song.124000.json','["周室興王業，堯圖授聖人。", "誰知皆內助，功德古無倫。"]'),
('a765d5d3-c521-43eb-8582-7ddde1c699cb','太上皇后閤端午帖子詞  其二','汪應辰','宋','宋诗','song-poetry','','[]','仁心均動植，風化正邦家。',24,'全唐诗/poet.song.124000.json','["仁心均動植，風化正邦家。", "福慶方駢集，靈符尚辟邪。"]'),
('d3bda175-1110-427e-8192-021e9d19292f','太上皇后閤端午帖子詞  其三','汪應辰','宋','宋诗','song-poetry','','[]','心境俱清浄，能令五月凉。',24,'全唐诗/poet.song.124000.json','["心境俱清浄，能令五月凉。", "芬香隨處有，不待沐蘭湯。"]'),
('ce26e5ff-3d36-4341-af07-f81083cd677f','太上皇后閤端午帖子詞  其四','汪應辰','宋','宋诗','song-poetry','','[]','坤元厚德孰能名，履正懷沖本至誠。',32,'全唐诗/poet.song.124000.json','["坤元厚德孰能名，履正懷沖本至誠。", "自是從容常中道，非因欲待晏陰成。"]'),
('9bcf137f-6807-48cf-abcd-5516396d29db','太上皇后閤端午帖子詞  其五','汪應辰','宋','宋诗','song-poetry','','[]','俯視紛華等粃糠，隨時邀樂任嬪嬙。',32,'全唐诗/poet.song.124000.json','["俯視紛華等粃糠，隨時邀樂任嬪嬙。", "宮中鬭草知多少，自有金芝冠衆芳。"]'),
('58d91903-db4a-423e-8d84-8f71bba57230','太上皇后閤端午帖子詞  其六','汪應辰','宋','宋诗','song-poetry','','[]','自然長壽又康寧，德合無疆萬物亨。',32,'全唐诗/poet.song.124000.json','["自然長壽又康寧，德合無疆萬物亨。", "聖主愛親思盡美，更羞仙朮助延生。"]'),
('014901e0-03aa-459b-97d9-9637d8cf3708','太上皇后閤端午帖子詞  其七','汪應辰','宋','宋诗','song-poetry','','[]','中興雖帝業，內治本陰功。',24,'全唐诗/poet.song.124000.json','["中興雖帝業，內治本陰功。", "天下供榮養，方知福報崇。"]'),
('f077f344-d22d-4e74-a167-f42600930a13','太上皇后閤端午帖子詞  其八','汪應辰','宋','宋诗','song-poetry','','[]','乾坤皆數五，日月正符同。',24,'全唐诗/poet.song.124000.json','["乾坤皆數五，日月正符同。", "但仰重離照，難名厚載功。"]'),
('1b331b92-befb-412f-8930-0f9725e59049','太上皇后閤端午帖子詞  其九','汪應辰','宋','宋诗','song-poetry','','[]','寶殿名康壽，皇心在祝延。',24,'全唐诗/poet.song.124000.json','["寶殿名康壽，皇心在祝延。", "願從重五日，更閲萬千年。"]'),
('06ba861f-8342-445e-bc8c-bbfb28b8a10c','太上皇后閤端午帖子詞  其一○','汪應辰','宋','宋诗','song-poetry','','[]','陽居大夏方行令，已有微陰次第生。',32,'全唐诗/poet.song.124000.json','["陽居大夏方行令，已有微陰次第生。", "細察天時知物理，常將儆戒保和平。"]'),
('4e6c6052-6a85-4680-8904-bc2ffd064ed4','太上皇后閤端午帖子詞  其一一','汪應辰','宋','宋诗','song-poetry','','[]','上古遺書究治終，長編通鑑更參同。',32,'全唐诗/poet.song.124000.json','["上古遺書究治終，長編通鑑更參同。", "端居坐照無窮事，何用江心百鍊銅。"]'),
('100a71cc-4e8d-4f88-a429-caf8cfb6411e','太上皇后閤端午帖子詞  其一二','汪應辰','宋','宋诗','song-poetry','','[]','晉國燔山求介子，荆人角黍祀靈均。',32,'全唐诗/poet.song.124000.json','["晉國燔山求介子，荆人角黍祀靈均。", "聖君念舊仍從諫，千古忠賢氣亦伸。"]'),
('597893d7-8309-489b-b050-3bb553185ae9','白雄雞','汪應辰','宋','宋诗','song-poetry','','[]','鐵爪玉龍鱗，紅冠不染塵。',24,'全唐诗/poet.song.124000.json','["鐵爪玉龍鱗，紅冠不染塵。", "五更纔報曉，驚動世間人。"]'),
('81c28803-2d7c-4e5b-86a8-bad7a9cb44a6','壬辰立春','汪應辰','宋','宋诗','song-poetry','','[]','春雪正紛紛，荒山晝掩門。',24,'全唐诗/poet.song.124000.json','["春雪正紛紛，荒山晝掩門。", "羨君筋力健，策杖過前村。"]'),
('3ef610e8-6f44-4f41-ab8d-eb61e0ca4113','水雲堂','汪應辰','宋','宋诗','song-poetry','','[]','雲本無心水自流，龍鱗鳳翼此中遊。',32,'全唐诗/poet.song.124000.json','["雲本無心水自流，龍鱗鳳翼此中遊。", "遂令巫峽桃源景，頓覺收歸在寸眸。"]'),
('fcbeb2fc-d0c6-4b72-b03e-9971a033f334','贈婺源汪氏','汪應辰','宋','宋诗','song-poetry','','[]','曾執干戈衛魯邦，潁川家世愈芬芳。',64,'全唐诗/poet.song.124000.json','["曾執干戈衛魯邦，潁川家世愈芬芳。", "扶疏枝葉連江浙，烜赫功名冠魏唐。", "卓犖高才當企及，青精一飯故宜償。", "獲通譜繫誠傾蓋，昭穆從斯永不忘。"]'),
('3d253719-b0b1-4c85-81f7-e4435dbd2df1','懷玉山','汪應辰','宋','宋诗','song-poetry','','[]','蓮宮高聳月峰坳，自與紅塵絕世交。',64,'全唐诗/poet.song.124000.json','["蓮宮高聳月峰坳，自與紅塵絕世交。", "萬頃田疇天外種，數聲鐘磬日邊敲。", "地寒春盡花方綻，寺僻僧閑疏不抄。", "禪月滿堂詩句在，恨無磚玉可相拋。"]'),
('a6541a4e-9ad1-42c2-960b-808922fcb151','太甲山','汪應辰','宋','宋诗','song-poetry','','[]','君王自古幸遊多，未必南從山澗阿。',64,'全唐诗/poet.song.124000.json','["君王自古幸遊多，未必南從山澗阿。", "龍虎真藏金鼎火，鳳凰從食玉山禾。", "雲霞落日舒旗幟，琪樹西風響珮珂。", "伊尹樂耕南畝日，想應高隠碧嵯峨。"]'),
('75b06ee3-d562-4fb6-8988-7314a7e9bde3','御殿瓦','汪應辰','宋','宋诗','song-poetry','','[]','曲曲灣灣散復收，覆如岡隴仰如溝。',64,'全唐诗/poet.song.124000.json','["曲曲灣灣散復收，覆如岡隴仰如溝。", "能教有漏成無漏，解使邪流入正流。", "鳳侶雙雙朝殿角，鴛行對對滴簷頭。", "時人莫道身骸小，蓋得君王萬萬秋。"]'),
('0fb844b4-e60d-494d-a846-a2cbcee94b8b','桂林','汪應辰','宋','宋诗','song-poetry','','[]','秦皇開郡爲桂林，古號名邦五嶺陰。',32,'全唐诗/poet.song.124000.json','["秦皇開郡爲桂林，古號名邦五嶺陰。", "山琢玉簪攢萬疊，江分羅带繞千尋。"]'),
('d478fb3b-0efb-496f-887d-80aadff51f53','題清虛庵皇甫真人坦之隠居','汪應辰','宋','宋诗','song-poetry','','[]','至人閲世若雲浮，來本無心去莫留。',64,'全唐诗/poet.song.124000.json','["至人閲世若雲浮，來本無心去莫留。", "應詔子微聊一出，如龍柱史復西遊。", "扁舟綠水霜天曉，夾岸丹楓澤國秋。", "遥想御香清醮罷，仙鸞飛繞玉華樓。"]'),
('c995750f-36b1-4952-a5b1-ec8d34bbebd2','句','汪應辰','宋','宋诗','song-poetry','','[]','龍爪拏開白白雲。',8,'全唐诗/poet.song.124000.json','["龍爪拏開白白雲。"]'),
('ca589e98-284f-4fdc-85a5-d893e8d25304','偈頌六十五首  其一','釋咸傑','宋','宋诗','song-poetry','','[]','一進一退，一動一靜，須信那伽常在定。',52,'全唐诗/poet.song.124000.json','["一進一退，一動一靜，須信那伽常在定。", "一擒一縱，一殺一活，四方八面活鱍鱍。", "嘉州大象喫鹽多，陝府鐵牛添得渴。"]'),
('d0c789c5-9f7d-4c7a-8c6c-13dafcd1f832','偈頌六十五首  其二','釋咸傑','宋','宋诗','song-poetry','','[]','滿目紛紛呈瑞雪，填溝塞壑誰辨別。',72,'全唐诗/poet.song.124000.json','["滿目紛紛呈瑞雪，填溝塞壑誰辨別。", "文殊無處頓渾身，普賢失却真妙訣。", "烏鴉變作白頭鴉，鐵樹翻成銀線結。", "報諸人，瞥不瞥，庭際無人立片時，便是太平底時節。"]'),
('e330517b-7064-42d6-a5fe-ee31452325eb','偈頌六十五首  其三','釋咸傑','宋','宋诗','song-poetry','','[]','有物先天地，無形本寂寥。',24,'全唐诗/poet.song.124000.json','["有物先天地，無形本寂寥。", "能爲萬象主，不逐四時凋。"]'),
('cdb9e517-4fe1-47f4-87d6-98568b976265','偈頌六十五首  其四','釋咸傑','宋','宋诗','song-poetry','','[]','久雨忽晴，天清地寧。',30,'全唐诗/poet.song.124000.json','["久雨忽晴，天清地寧。", "寒山撫掌，拾得忻忻。", "恁麽會得，旱地遭釘。"]'),
('064b629d-7278-4f09-984b-f94937937f55','偈頌六十五首  其五','釋咸傑','宋','宋诗','song-poetry','','[]','幽禽噪破那伽定，便見文星入寺來。',32,'全唐诗/poet.song.124000.json','["幽禽噪破那伽定，便見文星入寺來。", "倒屣門迎開笑面，林泉陡覺起風雷。"]'),
('7325ff30-61ed-4ace-bfc1-8b6b13178eb1','偈頌六十五首  其六','釋咸傑','宋','宋诗','song-poetry','','[]','即心即佛，鐵牛無骨。',20,'全唐诗/poet.song.124000.json','["即心即佛，鐵牛無骨。", "非心非佛，空山突兀。"]'),
('b8c15cae-ee11-486e-8e59-e382e54c4f87','偈頌六十五首  其七','釋咸傑','宋','宋诗','song-poetry','','[]','有句無句，如藤倚樹。',30,'全唐诗/poet.song.124000.json','["有句無句，如藤倚樹。", "石裂崖崩，毒蛇當路。", "樹倒藤枯，悉哩蘇嚧。"]'),
('9158f7c5-e9b0-4a17-a231-1938f06094a8','偈頌六十五首  其八','釋咸傑','宋','宋诗','song-poetry','','[]','雲開千嶂出，木落一枝分。',24,'全唐诗/poet.song.124000.json','["雲開千嶂出，木落一枝分。", "相見又無事，不來還憶君。"]'),
('8e1f17c1-f3db-41a5-9e29-d3048f3e78ae','偈頌六十五首  其九','釋咸傑','宋','宋诗','song-poetry','','[]','今朝六月十五，祝聖陞堂擊鼓。',62,'全唐诗/poet.song.124000.json','["今朝六月十五，祝聖陞堂擊鼓。", "木童火裏吹笙，石女雲中作舞。", "也大奇，也大奇，天無四壁，地絕八維。", "五湖四海來入貢，衲僧聞見眼如眉。"]'),
('25b4e62e-a58e-4f73-86eb-61d9889b9adf','偈頌六十五首  其一○','釋咸傑','宋','宋诗','song-poetry','','[]','烏巨今日解夏，乃遵黄面老子二千年前話霸。',62,'全唐诗/poet.song.124000.json','["烏巨今日解夏，乃遵黄面老子二千年前話霸。", "驗蠟人徹底冰清，護戒珠了無縫罅。", "唯有露柱燈籠，不肯入遮保社。", "從來心似鐵，端不受差排。"]'),
('985b91d2-236f-41c1-911e-8fd65e93c7d6','偈頌六十五首  其一一','釋咸傑','宋','宋诗','song-poetry','','[]','一葉飄空萬木秋，翻思光境急川流。',32,'全唐诗/poet.song.124000.json','["一葉飄空萬木秋，翻思光境急川流。", "若人識得其中意，坐斷千差向上頭。"]'),
('0438a78f-6bef-4099-b342-7dc8f04d6464','偈頌六十五首  其一二','釋咸傑','宋','宋诗','song-poetry','','[]','天上月圓，人間月半。',30,'全唐诗/poet.song.124000.json','["天上月圓，人間月半。", "槌鼓陞堂，理舊公案。", "車不橫推，理無曲斷。"]'),
('c86e0e83-3bff-4105-9fab-b074af9c2974','偈頌六十五首  其一三','釋咸傑','宋','宋诗','song-poetry','','[]','世尊拈花，勾賊破家。',70,'全唐诗/poet.song.124000.json','["世尊拈花，勾賊破家。", "迦葉微笑，聲前失照。", "雪峰輥毬，雙放雙收。", "玄沙未徹，眼中拔屑。", "雲門顧鑑，遞相脫賺。", "俱胝豎指，全無巴鼻。", "遮一隊漢，敵國家財。"]'),
('79e7651e-6785-493c-9a32-a7eafe2c9dad','偈頌六十五首  其一四','釋咸傑','宋','宋诗','song-poetry','','[]','少室單傳，衲僧巴鼻。',56,'全唐诗/poet.song.124000.json','["少室單傳，衲僧巴鼻。", "碓觜生花，馿鳴狗吠。", "厠坑籌子念摩訶，驚起法身無處避。", "無處避，若爲論，我行荒草裏，汝又入深村。"]'),
('d66d2ad4-9ed8-4901-9537-3409ce1fc29d','偈頌六十五首  其一五','釋咸傑','宋','宋诗','song-poetry','','[]','在眼曰見，在耳曰聞。',36,'全唐诗/poet.song.124000.json','["在眼曰見，在耳曰聞。", "在手執捉，在足運奔。", "豁開則東西南北，把住則毫髮不存。"]'),
('0148fa6f-107c-4040-b1b4-c56e05f9a898','偈頌六十五首  其一六','釋咸傑','宋','宋诗','song-poetry','','[]','靜悄悄處跳得出，閙浩浩處可橫身。',32,'全唐诗/poet.song.124000.json','["靜悄悄處跳得出，閙浩浩處可橫身。", "閙浩浩處挨得行，靜悄悄處堪駐足。"]'),
('16f3e7f9-031c-4ac5-884d-5ba2139f2b56','偈頌六十五首  其一七','釋咸傑','宋','宋诗','song-poetry','','[]','月生一，無角鐵牛眠少室。',54,'全唐诗/poet.song.124000.json','["月生一，無角鐵牛眠少室。", "月生二，赤脚波斯入閙市。", "月生三，冰生於水，青出於藍。", "文殊堂裏萬菩薩，夜來盡向此中參。"]'),
('e3245f47-cdc7-4f28-9d91-d5676333e49c','偈頌六十五首  其一八','釋咸傑','宋','宋诗','song-poetry','','[]','一新一舊，跳出窠臼。',44,'全唐诗/poet.song.124000.json','["一新一舊，跳出窠臼。", "一出一入，胡餠裏呷汁。", "一擒一縱，開眼作夢。", "一照一用，鱔魚走入麻油甕。"]'),
('b7cf16e2-8b55-4bc0-9cf5-2bb2009ac094','偈頌六十五首  其一九','釋咸傑','宋','宋诗','song-poetry','','[]','日南長至，慶無不利。',40,'全唐诗/poet.song.124000.json','["日南長至，慶無不利。", "石笋暗抽條，寒巖增暖氣。", "東村王老半醉半醒，林下道人沒巴沒鼻。"]'),
('2eba88d0-bf77-41be-94a9-6ce940c8ecd5','偈頌六十五首  其二○','釋咸傑','宋','宋诗','song-poetry','','[]','元正一旦，萬事成辦。',35,'全唐诗/poet.song.124000.json','["元正一旦，萬事成辦。", "大乘小乘，井索錢貫。", "更問佛法如何，也是秦時𨍏轢鑽。"]'),
('8afdc555-f84f-4beb-b84d-ed99a751633d','偈頌六十五首  其二一','釋咸傑','宋','宋诗','song-poetry','','[]','賢劫千佛數，末後最慇懃。',52,'全唐诗/poet.song.124000.json','["賢劫千佛數，末後最慇懃。", "倒握降魔杵，高標利物拳。", "心肝無屈曲，腸胃有區分。", "神通願力雖無盡，且爲山僧護法門。"]'),
('3b316de2-8d02-4a59-adcb-739935973f59','偈頌六十五首  其二二','釋咸傑','宋','宋诗','song-poetry','','[]','生鐵鑄牛頭，牽犁還拽杷。',40,'全唐诗/poet.song.124000.json','["生鐵鑄牛頭，牽犁還拽杷。", "智者笑忻忻，愚人驚怪差。", "古往今來幾百年，更向鬼門重貼卦。"]'),
('db27762d-2915-4856-85ad-809fa69a9013','偈頌六十五首  其二三','釋咸傑','宋','宋诗','song-poetry','','[]','因我得禮你，窮源親到底。',24,'全唐诗/poet.song.124000.json','["因我得禮你，窮源親到底。", "禮拜了燒香，自倒還自起。"]'),
('26816f6d-48e1-44f9-852c-62687e013be3','偈頌六十五首  其二四','釋咸傑','宋','宋诗','song-poetry','','[]','諸佛不說說，祖師不聞聞。',24,'全唐诗/poet.song.124000.json','["諸佛不說說，祖師不聞聞。", "留下一轉語，千古鎮乾坤。"]'),
('eab0af92-e592-4dc2-b7a3-4de0faf198a2','偈頌六十五首  其二五','釋咸傑','宋','宋诗','song-poetry','','[]','今佛放光明，助發實相義。',24,'全唐诗/poet.song.124000.json','["今佛放光明，助發實相義。", "希有諸比丘，是中難比况。"]'),
('f9f1b76f-3189-4cce-8d05-ad953f060ea9','偈頌六十五首  其二六','釋咸傑','宋','宋诗','song-poetry','','[]','月生一，萬像不能逃影質。',36,'全唐诗/poet.song.124000.json','["月生一，萬像不能逃影質。", "月生二，東行不見西行利。", "月生三，無言童子口喃喃。"]'),
('d2ece135-ef9f-4092-8450-4f90dd7d6d04','偈頌六十五首  其二七','釋咸傑','宋','宋诗','song-poetry','','[]','一葉落，天下秋，南來北往竟悠悠。',80,'全唐诗/poet.song.124000.json','["一葉落，天下秋，南來北往竟悠悠。", "一句通，萬機息，上下四維無等匹。", "西天人不會唐言，獨坐少林癡面壁。", "带累兒孫不丈夫，被人喚作白拈賊。", "雲門念七好參詳，寶公不是閑和尚。"]'),
('4f7a04af-f93c-460a-b24e-0504b966a03b','偈頌六十五首  其二八','釋咸傑','宋','宋诗','song-poetry','','[]','月圓月缺，循途守轍。',20,'全唐诗/poet.song.124000.json','["月圓月缺，循途守轍。", "打破牢關，天寬地寬。"]'),
('87425b27-f7af-4bf8-84bd-26a529bf6917','偈頌六十五首  其二九','釋咸傑','宋','宋诗','song-poetry','','[]','雖與我同條生，不與我同條死。',42,'全唐诗/poet.song.124000.json','["雖與我同條生，不與我同條死。", "稔聞在七閩，揚塵兼簸土。", "凌茂宗風不奈何，今朝喜見清平路。"]'),
('1c5833b3-b176-4dcd-844b-8246c9afc516','偈頌六十五首  其三○','釋咸傑','宋','宋诗','song-poetry','','[]','一切數句非數句，與吾靈覺何交涉。',32,'全唐诗/poet.song.124000.json','["一切數句非數句，與吾靈覺何交涉。", "毒蛇鑽入你鼻孔，蝦蟆咬破你眼睛。"]'),
('de4a0c99-ace0-47ff-9d5a-7b3d6edc2ab7','偈頌六十五首  其三一','釋咸傑','宋','宋诗','song-poetry','','[]','方脫鍾山階級難，却來遮裏養殘軀。',32,'全唐诗/poet.song.124000.json','["方脫鍾山階級難，却來遮裏養殘軀。", "那知蹤跡難遮掩，又見驅馳走使符。"]'),
('fd25c17f-469a-443c-8d8b-2f48c3f803b6','偈頌六十五首  其三二','釋咸傑','宋','宋诗','song-poetry','','[]','獅子教兒迷子訣，擬前跳擲早翻身。',32,'全唐诗/poet.song.124000.json','["獅子教兒迷子訣，擬前跳擲早翻身。", "羅紋結角交鋒處，鶻眼臨時失却蹤。"]'),
('5172e15d-3da2-4a58-9dc4-c06f92450380','偈頌六十五首  其三三','釋咸傑','宋','宋诗','song-poetry','','[]','莫除荆棘建伽藍，七佛常來此處參。',32,'全唐诗/poet.song.124000.json','["莫除荆棘建伽藍，七佛常來此處參。", "地久天長功不墜，天花時復雨毿毿。"]'),
('995b1c33-a79a-4dbe-b148-007079b069fa','偈頌六十五首  其三四','釋咸傑','宋','宋诗','song-poetry','','[]','利劍斬虛空，萬象鳴嚗嚗。',24,'全唐诗/poet.song.124000.json','["利劍斬虛空，萬象鳴嚗嚗。", "年年向斯辰，令人倍發惡。"]'),
('74494e9c-1df8-41e4-94fe-ecd63c6e8514','偈頌六十五首  其三五','釋咸傑','宋','宋诗','song-poetry','','[]','秋江清淺時，白鷺和烟島。',24,'全唐诗/poet.song.124000.json','["秋江清淺時，白鷺和烟島。", "良哉觀世音，全身入荒草。"]'),
('419c0583-6cfb-42c7-b3c6-42826482ddc7','偈頌六十五首  其三六','釋咸傑','宋','宋诗','song-poetry','','[]','拳來拳應，踢來踢應。',36,'全唐诗/poet.song.124000.json','["拳來拳應，踢來踢應。", "拳踢交參，孰負孰勝。", "摇頭擺尾過牢關，刖足之言誰肯信。"]'),
('f47da486-eeb1-4a64-8315-7455b87366f4','偈頌六十五首  其三七','釋咸傑','宋','宋诗','song-poetry','','[]','呼猿洞口，虛空迸裂。',20,'全唐诗/poet.song.124000.json','["呼猿洞口，虛空迸裂。", "鴉飛不度，如行如說。"]'),
('727972ea-da37-4ef9-9cdb-dd2f351fff51','偈頌六十五首  其三八','釋咸傑','宋','宋诗','song-poetry','','[]','輔弼宗門有老成，一番提掇一番新。',32,'全唐诗/poet.song.124000.json','["輔弼宗門有老成，一番提掇一番新。", "咬薑呷醋知醎淡，便是叢林過量人。"]'),
('1f6c9e31-d809-4367-91c3-05053b8b7759','偈頌六十五首  其三九','釋咸傑','宋','宋诗','song-poetry','','[]','一手不獨拍，衆手鳴摑摑。',28,'全唐诗/poet.song.124000.json','["一手不獨拍，衆手鳴摑摑。", "豁開三要三玄門，堪與人天爲軌則。"]'),
('1a649e12-d852-4bc2-9d8c-65d743ca1e42','偈頌六十五首  其四○','釋咸傑','宋','宋诗','song-poetry','','[]','今朝十五日，叢林皆結制。',66,'全唐诗/poet.song.124000.json','["今朝十五日，叢林皆結制。", "徑山有條攀條，無條攀例。", "逼拶露柱燈籠，盡要心空及第。", "現前普請證明，不妨神通游戲。", "下座各敘時暄，便是靈山受記。"]'),
('9f326a31-b8db-46d6-8919-0ef884c32922','偈頌六十五首  其四一','釋咸傑','宋','宋诗','song-poetry','','[]','佛法無人說，雖慧不能了。',24,'全唐诗/poet.song.124000.json','["佛法無人說，雖慧不能了。", "去却上頭關，面南看北斗。"]'),
('0a908041-d640-4e45-8756-ddc7ce049ec3','偈頌六十五首  其四二','釋咸傑','宋','宋诗','song-poetry','','[]','心同虛空界，示等虛空法。',24,'全唐诗/poet.song.124000.json','["心同虛空界，示等虛空法。", "證得虛空時，無是無非法。"]'),
('856b9228-05af-4c2d-b370-5056e8aa7245','偈頌六十五首  其四三','釋咸傑','宋','宋诗','song-poetry','','[]','六月炎炎如火熱，誰知冷處勝冰雪。',64,'全唐诗/poet.song.124000.json','["六月炎炎如火熱，誰知冷處勝冰雪。", "紅塵閙市等箇人，七佛軌儀都漏泄。", "報龍王，須福護，大千捏聚爲檀度。", "一言劄住萬機通，自然光壯少林風。"]'),
('00046be8-87be-4170-9057-de376e2f100c','偈頌六十五首  其四四','釋咸傑','宋','宋诗','song-poetry','','[]','吞却與吐却，算來無處著。',24,'全唐诗/poet.song.124000.json','["吞却與吐却，算來無處著。", "要見滑稽人，便是黄幡綽。"]'),
('81d8232e-1215-4c60-9bb1-78a9a9ac95f8','偈頌六十五首  其四五','釋咸傑','宋','宋诗','song-poetry','','[]','昔年相見談真諦，今日陞堂話去來。',32,'全唐诗/poet.song.124000.json','["昔年相見談真諦，今日陞堂話去來。", "一念廓然無向背，春光鐵樹自花開。"]'),
('aaf6713e-aaab-4d52-b1d4-fb12745c4af0','偈頌六十五首  其四六','釋咸傑','宋','宋诗','song-poetry','','[]','油煎石磉盤，風吹毛毬走。',28,'全唐诗/poet.song.124000.json','["油煎石磉盤，風吹毛毬走。", "虛空背上白毛生，拈得鼻孔失却口。"]'),
('008f1ff6-4bd1-4025-b53e-ccadc9f7038d','偈頌六十五首  其四七','釋咸傑','宋','宋诗','song-poetry','','[]','修造未逾兩箇月，叢林便覺日荒凉。',32,'全唐诗/poet.song.124000.json','["修造未逾兩箇月，叢林便覺日荒凉。", "今朝重整舊洪範，鐵佛須教盡放光。"]'),
('71b51233-0211-41f7-9698-beb537705f11','偈頌六十五首  其四八','釋咸傑','宋','宋诗','song-poetry','','[]','五月五日端午節，陰雲靉靆，甘雨未决。',56,'全唐诗/poet.song.124000.json','["五月五日端午節，陰雲靉靆，甘雨未决。", "君王降賜寶香，林下祈求懇切。", "孚祐龍，善時節，好將一雨潤焦枯，帀地清凉消惱熱。"]'),
('3f1e2484-1821-4400-a7f3-dd7fafe76eeb','偈頌六十五首  其四九','釋咸傑','宋','宋诗','song-poetry','','[]','有佛處，不得住，陝府鐵牛雙角露。',48,'全唐诗/poet.song.124000.json','["有佛處，不得住，陝府鐵牛雙角露。", "無佛處，急走過，南海波斯鼻孔大。", "三千里外摘楊花，種豆由來生稻麻。"]'),
('8da6721a-02c0-4122-b751-9372e7434f78','偈頌六十五首  其五○','釋咸傑','宋','宋诗','song-poetry','','[]','虎驟龍驤與麽來，驀然平地起風雷。',32,'全唐诗/poet.song.124000.json','["虎驟龍驤與麽來，驀然平地起風雷。", "棒頭正眼明如日，凜凜清風廓九垓。"]'),
('089699e1-8054-4b05-a8d2-1c3653790133','偈頌六十五首  其五一','釋咸傑','宋','宋诗','song-poetry','','[]','四月十五日結，七月十五日解。',30,'全唐诗/poet.song.124000.json','["四月十五日結，七月十五日解。", "六隻骰子滿盆紅，大都只是看頭米。"]'),
('4c7bf5d5-4418-4b71-8dc5-9451a857330c','偈頌六十五首  其五二','釋咸傑','宋','宋诗','song-poetry','','[]','虛空可量風可繫，無能盡說佛功德。',32,'全唐诗/poet.song.124000.json','["虛空可量風可繫，無能盡說佛功德。", "佛功德海既難量，吾君聖壽亦如是。"]'),
('b56c5a2b-a4a9-4a38-8e28-c0161331119b','偈頌六十五首  其五三','釋咸傑','宋','宋诗','song-poetry','','[]','持鉢去，持鉢歸。',48,'全唐诗/poet.song.124000.json','["持鉢去，持鉢歸。", "草鞋根斷通消息，玲瓏八面盡光輝。", "遊魔宮，入虎穴。", "當機撞著惡聱頭，直教心地頓休歇。"]'),
('b370b6e3-8844-4527-bcb4-3978aea588f3','偈頌六十五首  其五四','釋咸傑','宋','宋诗','song-poetry','','[]','一手不獨拍，兩手鳴摑摑。',42,'全唐诗/poet.song.124000.json','["一手不獨拍，兩手鳴摑摑。", "豁開三要三玄，捏碎佛祖標格。", "村歌社舞得人憎，勝似當年白拈賊。"]'),
('776a0bd4-e771-41d1-8cac-74b177e496b7','偈頌六十五首  其五五','釋咸傑','宋','宋诗','song-poetry','','[]','今朝三月十五，天色半晴半雨。',50,'全唐诗/poet.song.124000.json','["今朝三月十五，天色半晴半雨。", "十分春色在枝頭，滿眼覷見沒可覩。", "報諸人，莫莽鹵，甜瓜徹蒂甜，苦瓠連根苦。"]'),
('4d21a5e4-cbf9-466d-85d6-990b3cf7563d','偈頌六十五首  其五六','釋咸傑','宋','宋诗','song-poetry','','[]','南泉起模畫樣，長慶披砂揀金。',28,'全唐诗/poet.song.124000.json','["南泉起模畫樣，長慶披砂揀金。", "雲門鼻孔先穿，雪竇據款結案。"]'),
('b718c975-bd30-46c5-9686-f6be31986b9b','偈頌六十五首  其五七','釋咸傑','宋','宋诗','song-poetry','','[]','只此見聞非見聞，無餘聲色可呈君。',32,'全唐诗/poet.song.124000.json','["只此見聞非見聞，無餘聲色可呈君。", "箇中若了元無事，體用何妨分不分。"]'),
('52035fcd-c580-40d7-89d7-b320a74dc1af','偈頌六十五首  其五八','釋咸傑','宋','宋诗','song-poetry','','[]','即心即佛也揖出，非心非佛也揖出。',60,'全唐诗/poet.song.124000.json','["即心即佛也揖出，非心非佛也揖出。", "地轉天回豈等閑，即知此物非他物。", "以此顯追崇，決定當超越。", "次回陰隲保家堂，自然福壽永無雙。"]'),
('a1940378-6c9b-4410-b594-75805e370ccd','偈頌六十五首  其五九','釋咸傑','宋','宋诗','song-poetry','','[]','達磨不來東土，二祖不往西天。',36,'全唐诗/poet.song.124000.json','["達磨不來東土，二祖不往西天。", "石室行者蹈碓忘却移步，玄沙討魚賣峭蹈翻釣船。"]'),
('497a4efe-144a-4b80-85de-c040469da708','偈頌六十五首  其六○','釋咸傑','宋','宋诗','song-poetry','','[]','一箇葫蘆纔倒地，滿地葫蘆盡傾倒。',32,'全唐诗/poet.song.124000.json','["一箇葫蘆纔倒地，滿地葫蘆盡傾倒。", "欲識單傳直指禪，今日鬭湊得恰好。"]'),
('f7dd8224-0e39-447d-b23e-9f0089bae911','偈頌六十五首  其六一','釋咸傑','宋','宋诗','song-poetry','','[]','四年居此日波波，累及禪和不奈何。',32,'全唐诗/poet.song.124000.json','["四年居此日波波，累及禪和不奈何。", "今感聖恩林下去，一輪秋月照天河。"]'),
('13e024c2-7db7-43f8-904b-d9919389e5d4','偈頌六十五首  其六二','釋咸傑','宋','宋诗','song-poetry','','[]','去年八月間，得旨與安閑。',136,'全唐诗/poet.song.124000.json','["去年八月間，得旨與安閑。", "擺動水雲性，縱步到陽山。", "元宅諸子弟，忻然力追攀。", "菴居三箇月，開懷宇宙寬。", "忽接四明信，來書意盤桓。", "天童虛法席，使君語猶端。", "迢迢遣專使，不問路行難。", "山僧臨晚景，不敢自相瞞。", "搥鼓樂與行，四衆亦欣歡。", "先師未了底，應是起波瀾。", "一回飲水一回噎，臨濟德山俱汗顔。"]'),
('b06bbbf9-f570-4919-b4e1-b079e689b0c6','偈頌六十五首  其六三','釋咸傑','宋','宋诗','song-poetry','','[]','二千年前舊公案，今日拈來重剖判。',32,'全唐诗/poet.song.124000.json','["二千年前舊公案，今日拈來重剖判。", "任是鐵眼與銅睛，也須更入紅爐煅。"]'),
('a03fe280-175f-48c4-b968-e272229bc7c2','偈頌六十五首  其六四','釋咸傑','宋','宋诗','song-poetry','','[]','居於富貴中，不爲富貴誤。',64,'全唐诗/poet.song.124000.json','["居於富貴中，不爲富貴誤。", "赤手挨開解脫門，四方八面俱獨步。", "佛祖不知由，憑誰立本據。", "咄咄咄，力㘞希，聞見覺知齊合掌，鐵牛生得鳳凰兒。"]'),
('92808bca-d578-4e3c-846e-50732afd9c28','偈頌六十五首  其六五','釋咸傑','宋','宋诗','song-poetry','','[]','日日是好日，時時是好時。',28,'全唐诗/poet.song.124000.json','["日日是好日，時時是好時。", "惟有十月二十二，吉星垂照最希奇。"]'),
('c4bec208-3635-43ce-9eef-491f17d77daa','偈頌四首  其一','釋咸傑','宋','宋诗','song-poetry','','[]','釋迦不說說，迦葉不聞聞。',24,'全唐诗/poet.song.124000.json','["釋迦不說說，迦葉不聞聞。", "天河風浪靜，星斗位區分。"]'),
('b2a947b0-ae9a-4d3b-b9d1-736e8fad5b07','偈頌四首  其二','釋咸傑','宋','宋诗','song-poetry','','[]','山河大地不是幻，日月星辰不是幻。',48,'全唐诗/poet.song.124000.json','["山河大地不是幻，日月星辰不是幻。", "明暗色空不是幻，四聖六凡不是幻。", "山僧說底不是幻，諸人聽底不是幻。"]'),
('90a2a560-becd-4666-acd9-6a028dbca112','偈頌四首  其三','釋咸傑','宋','宋诗','song-poetry','','[]','眼裏耳裏絕纖塵，鐵眼銅睛覷不破。',48,'全唐诗/poet.song.124000.json','["眼裏耳裏絕纖塵，鐵眼銅睛覷不破。", "蚊子排頭咬鐵釘，上下四維俱匌匝。", "只將此語報深恩，朵朵紅蓮火裏發。"]'),
('c088c9bb-7db4-4cb5-b774-d118a5aca078','偈頌四首  其四','釋咸傑','宋','宋诗','song-poetry','','[]','一年三百六十日，今宵正是結交頭。',32,'全唐诗/poet.song.124000.json','["一年三百六十日，今宵正是結交頭。", "移身換步無多子，六合清風來未休。"]'),
('50b81a2e-3379-41aa-80f6-533515d210a9','頌古十一首  其一','釋咸傑','宋','宋诗','song-poetry','','[]','斫却月中桂，清光轉更多。',24,'全唐诗/poet.song.124000.json','["斫却月中桂，清光轉更多。", "狐狸俱屏迹，獅子奮金毛。"]'),
('6ec99bb6-14ab-4ccd-aec3-f57cf09b38ca','頌古十一首  其二','釋咸傑','宋','宋诗','song-poetry','','[]','狗子無佛性，殺人便償命。',24,'全唐诗/poet.song.124000.json','["狗子無佛性，殺人便償命。", "楚痛百千般，因邪却打正。"]'),
('d562a77f-b2ce-4595-81a0-f7ced5627806','頌古十一首  其三','釋咸傑','宋','宋诗','song-poetry','','[]','出得何如未出時，瞎馿成隊喪全機。',32,'全唐诗/poet.song.124000.json','["出得何如未出時，瞎馿成隊喪全機。", "而今四海平如砥，蘆管迎風撩亂吹。"]'),
('7c03e12b-01b9-4457-8348-05d51e5681d3','頌古十一首  其四','釋咸傑','宋','宋诗','song-poetry','','[]','粥了令教洗鉢盂，鐵船無底要人扶。',32,'全唐诗/poet.song.124000.json','["粥了令教洗鉢盂，鐵船無底要人扶。", "片帆高掛乘風便，截海須還大丈夫。"]'),
('90955343-1a3b-440c-ad0a-391da325ab38','頌古十一首  其五','釋咸傑','宋','宋诗','song-poetry','','[]','一頓渾家盡滅門，更加兩頓累兒孫。',32,'全唐诗/poet.song.124000.json','["一頓渾家盡滅門，更加兩頓累兒孫。", "銀山鐵壁俱穿透，萬里無雲宇宙分。"]'),
('6eaa7ad1-b935-4026-8ff9-b51d555cdcd7','頌古十一首  其六','釋咸傑','宋','宋诗','song-poetry','','[]','五百生前失却，五百生後太錯。',25,'全唐诗/poet.song.124000.json','["五百生前失却，五百生後太錯。", "錯錯，誰道祥麟只一角。"]'),
('d7ab5f35-ea86-4445-8cc2-7c97c15ae247','頌古十一首  其七','釋咸傑','宋','宋诗','song-poetry','','[]','西江一吸了無餘，突出堂堂大丈夫。',32,'全唐诗/poet.song.124000.json','["西江一吸了無餘，突出堂堂大丈夫。", "盡道世間胡鬚赤，須知更有赤鬚胡。"]'),
('beafd43c-646d-4741-bd4a-dc3a06e4c87e','頌古十一首  其八','釋咸傑','宋','宋诗','song-poetry','','[]','大海波濤闊，千峰氣象雄。',24,'全唐诗/poet.song.124000.json','["大海波濤闊，千峰氣象雄。", "古今無間斷，南北路頭通。"]'),
('b2da7544-6df7-4cf5-9fe3-6a492ac7bbd1','頌古十一首  其九','釋咸傑','宋','宋诗','song-poetry','','[]','天高地厚人難見，海闊山遥只自知。',32,'全唐诗/poet.song.124000.json','["天高地厚人難見，海闊山遥只自知。", "勘破却回休借問，得便宜是落便宜。"]'),
('e11654db-34bd-4d57-a1f5-fac82cbcc984','頌古十一首  其一○','釋咸傑','宋','宋诗','song-poetry','','[]','百戰場中舞纛旗，將軍立處十分危。',32,'全唐诗/poet.song.124000.json','["百戰場中舞纛旗，將軍立處十分危。", "游人只看錐頭利，失却吹毛總不知。"]'),
('ad15d0bb-c6bf-44d4-bdc2-495da43645da','頌古十一首  其一一','釋咸傑','宋','宋诗','song-poetry','','[]','屋裏販揚州，水深山更幽。',24,'全唐诗/poet.song.124000.json','["屋裏販揚州，水深山更幽。", "終年無客到，明月自相投。"]'),
('678ca73b-5eeb-4641-b190-3f783f1a9e9b','讚布袋和尚','釋咸傑','宋','宋诗','song-poetry','','[]','禪不參，道不會，終日忙忙。',50,'全唐诗/poet.song.124000.json','["禪不參，道不會，終日忙忙。", "弄箇布袋，十字街頭道等人。", "阿誰知渠綣繢，稽首彌勒世尊。", "國有憲章，三千條罪。"]'),
('f3fd808f-4e4c-4144-8e22-4abc52b86093','讚開明禪師','釋咸傑','宋','宋诗','song-poetry','','[]','江郎入定，烏巨開山。',36,'全唐诗/poet.song.124000.json','["江郎入定，烏巨開山。", "林深路迥，火冷雲寒。", "道大不知誰辨的，帝王親手付金襴。"]'),
('122cc586-df67-4ae0-a3e2-1bff042270bc','讚綉寶公','釋咸傑','宋','宋诗','song-poetry','','[]','針鋒上直入，線縫裏跳出。',28,'全唐诗/poet.song.124000.json','["針鋒上直入，線縫裏跳出。", "剪刀尺子自隨身，號令乾坤齊萬物。"]'),
('4c79bc55-2181-4708-804d-dc5c795d771c','讚大慧和尚','釋咸傑','宋','宋诗','song-poetry','','[]','戳瞎頂門三隻眼，是非佛法一齊剗。',32,'全唐诗/poet.song.124000.json','["戳瞎頂門三隻眼，是非佛法一齊剗。", "竹篦頭上放無端，正是徐六擔片板。"]'),
('8dd4dca5-eae9-4b38-8f89-f70cb3869563','讚應菴和尚','釋咸傑','宋','宋诗','song-poetry','','[]','眼大如環，頭匾似扇。',58,'全唐诗/poet.song.124000.json','["眼大如環，頭匾似扇。", "從來不省己非，偏笑漳泉福建。", "著實處用無七縱八橫，脫空時曰有萬化千變。", "焚香稽首讚揚，也是神頭鬼面。"]'),
('3a691a6e-4840-4977-88b3-66c3c079a55a','讚木庵和尚','釋咸傑','宋','宋诗','song-poetry','','[]','面目森嚴，語言希差。',58,'全唐诗/poet.song.124000.json','["面目森嚴，語言希差。", "不出飛猿嶺，道聲藹天下。", "活嬾菴不傳之宗，死衲僧虛頭話霸。", "五坐道場，叢林增價。", "稽首拜手，虛空貼卦。"]'),
('1103090d-40b7-4ee6-a77b-d698bd3f1045','讚徑山音首座','釋咸傑','宋','宋诗','song-poetry','','[]','氣宇雲閑，身心木槁。',76,'全唐诗/poet.song.124000.json','["氣宇雲閑，身心木槁。", "頂門正眼，紅日杲杲。", "早投長蘆剗草之機，晚分雙徑人天之座。", "名山屢招而不赴，一菴超然其高卧。", "夫是謂叢林前輩典刑，宜與趙州同年而並操者也。"]'),
('01afc81a-7350-4940-89c8-f57be0433697','約齋張直閣畫師頂相請讚','釋咸傑','宋','宋诗','song-poetry','','[]','挨開不二門，千聖須却步。',66,'全唐诗/poet.song.124000.json','["挨開不二門，千聖須却步。", "直下便承當，略通一線路。", "佛也不奈何，誰敢當頭道。", "道著頭角生，一點黑如皂。", "盡情分付約齊大居士，一等人間任揚播。"]'),
('d5023780-5159-44f7-a3f7-071636945687','真際道人請讚','釋咸傑','宋','宋诗','song-poetry','','[]','一句全提，了無向背。',46,'全唐诗/poet.song.124000.json','["一句全提，了無向背。", "臨濟正宗，恣意破碎。", "彌天過犯，不容懺悔。", "丹青畫出向人前，他家自有通人愛。"]'),
('32e67e4d-09e2-4f05-9e78-ca13335e0e0f','禪人請讚  其一','釋咸傑','宋','宋诗','song-poetry','','[]','五戒不持，威儀破盡。',36,'全唐诗/poet.song.124000.json','["五戒不持，威儀破盡。", "空腹高心，言不足信。", "徒將朽木亂塗糊，衲僧添得膏肓病。"]'),
('2f106934-9b1f-45d1-af4c-885281ffa9d7','禪人請讚  其二','釋咸傑','宋','宋诗','song-poetry','','[]','天無私蓋，地無私載。',60,'全唐诗/poet.song.124000.json','["天無私蓋，地無私載。", "如何形容，生此奇怪。", "爲僧不稟僧儀，學佛力破佛戒。", "鼓舌摇唇，叢林殃害。", "若無伽梨裹渾身，便是當年屈突蓋。"]'),
('2954465a-fa99-4f71-9ecf-6774ef53d703','禪人請讚  其三','釋咸傑','宋','宋诗','song-poetry','','[]','在家不讀書，行脚不參禪。',40,'全唐诗/poet.song.124000.json','["在家不讀書，行脚不參禪。", "隨流閑打閧，掘地覓青天。", "而今老矣方知悔，捏人痛處力加鞭。"]'),
('b1df65b4-dd59-40a6-86de-509a9d64f49a','禪人請讚  其四','釋咸傑','宋','宋诗','song-poetry','','[]','眼橫鼻直村僧，肚裏渾無一窖。',42,'全唐诗/poet.song.124000.json','["眼橫鼻直村僧，肚裏渾無一窖。", "兩奉詔旨住持，添得叢林熱閙。", "若論直指單傳，正是睡夢未覺。"]'),
('5a67f75c-d78b-4e6f-b008-7c4246cae874','禪人請讚  其五','釋咸傑','宋','宋诗','song-poetry','','[]','入室愛用拳頭，佛來也不放過。',40,'全唐诗/poet.song.124000.json','["入室愛用拳頭，佛來也不放過。", "知他是聖是凡，便敢如此亂做。", "識得破，海壇馬子似馿大。"]'),
('606011de-22a4-4bf0-925e-969700963819','禪人請讚  其六','釋咸傑','宋','宋诗','song-poetry','','[]','德山臨濟，棒喝交馳。',36,'全唐诗/poet.song.124000.json','["德山臨濟，棒喝交馳。", "雲門顧鑑，總是愚癡。", "唯有徑山無伎倆，握拳端坐眼如眉。"]'),
('771eecc1-7ffb-4b1c-b0f4-d1551c6465ba','禪人請讚  其七','釋咸傑','宋','宋诗','song-poetry','','[]','水黑染成，恰似真箇。',40,'全唐诗/poet.song.124000.json','["水黑染成，恰似真箇。", "據坐胡床，胡揮亂做。", "三十年後，此話大行。", "籍沒乃翁，膠黏滯貨。"]'),
('70880f8a-74a6-4754-9f0c-4c1d0ae252da','佛日常長老請讚','釋咸傑','宋','宋诗','song-poetry','','[]','赤手全提，金圈栗棘。',51,'全唐诗/poet.song.124000.json','["赤手全提，金圈栗棘。", "跳出三要三玄，破蕩佛祖窠窟。", "試問有何神通，盡力吐露不出。", "咄咄，佛日長老，與麽拈出。"]'),
('cad40204-fe1f-4ff7-b1e7-55e487257784','隆報著長老請讚','釋咸傑','宋','宋诗','song-poetry','','[]','據虎頭，收虎尾，第一句下明宗旨。',56,'全唐诗/poet.song.124000.json','["據虎頭，收虎尾，第一句下明宗旨。", "了無禪道與人參，滴水便見波瀾起。", "太醒醒，難比擬。", "分付隆報著長老，好向叢林振綱紀。"]'),
('4e54d844-425f-4fce-9baa-99c799248735','皇太子妃請就徑山陞座末後說偈','釋咸傑','宋','宋诗','song-poetry','','[]','佛身無爲，不墮諸數。',58,'全唐诗/poet.song.124000.json','["佛身無爲，不墮諸數。", "隨機示現，應無所住。", "如月行空，光照寰宇。", "廓徹信心，莊嚴福聚。", "記得先賢曾有言，皇天無親，唯德是輔。"]'),
('ecba61a6-9dd0-4564-ba53-82fe1c0d338a','張直閣請陞座末後說偈','釋咸傑','宋','宋诗','song-poetry','','[]','一句全提法界寬，大千收拾掌中觀。',32,'全唐诗/poet.song.124000.json','["一句全提法界寬，大千收拾掌中觀。", "橫該豎抹超三際，迦葉徒勞强破顔。"]'),
('16192d02-5eed-4f27-9790-beb5b4ccdd7e','贈閩清黄釋褐初赴上庠','釋咸傑','宋','宋诗','song-poetry','','[]','驀劄相逢笑臉開，也知平地起風雷。',32,'全唐诗/poet.song.124000.json','["驀劄相逢笑臉開，也知平地起風雷。", "好將一滴梅溪水，爲雨爲霖遍九垓。"]'),
('ce6db967-2e18-47ae-9c4e-365b5965dc80','和無著讚大慧齒髮舍利','釋咸傑','宋','宋诗','song-poetry','','[]','背觸全提話已圓，孤風凜凜播皇天。',32,'全唐诗/poet.song.124000.json','["背觸全提話已圓，孤風凜凜播皇天。", "無端更把閑毛齒，惹得叢林口耳傳。"]'),
('6e70f66f-cb01-48a3-bb33-a13345279e1a','送昂維那出嶺兼呈應庵  其一','釋咸傑','宋','宋诗','song-poetry','','[]','福城得得來相訪，象骨巖前話別時。',32,'全唐诗/poet.song.124000.json','["福城得得來相訪，象骨巖前話別時。", "驚起石人開鐵眼，倚筇遥聽老猿啼。"]'),
('677c14e6-3d4b-4f88-9a55-c6db0d385255','送昂維那出嶺兼呈應庵  其二','釋咸傑','宋','宋诗','song-poetry','','[]','雲黄山下老禪庵，凌蔑宗風罪過多。',32,'全唐诗/poet.song.124000.json','["雲黄山下老禪庵，凌蔑宗風罪過多。", "君若到門深問訊，看渠伎倆復如何。"]'),
('f45d7d32-4fde-4a17-b000-f9681adf4507','送拙菴住洪福','釋咸傑','宋','宋诗','song-poetry','','[]','瞎馿生得瞎馿兒，齷齪聲名徹四維。',32,'全唐诗/poet.song.124000.json','["瞎馿生得瞎馿兒，齷齪聲名徹四維。", "更把少林無孔笛，逢人應是逆風吹。"]'),
('18a8866f-302e-41d2-8e43-d253a1a63280','送會侍者開應庵塔銘','釋咸傑','宋','宋诗','song-poetry','','[]','三十餘年沙魘，一十五處脫空。',28,'全唐诗/poet.song.124000.json','["三十餘年沙魘，一十五處脫空。", "欲彰從前家醜，何妨刻石流通。"]'),
('c542a184-8fd2-4584-8af2-5b85b06fdd55','送權維那歸道場','釋咸傑','宋','宋诗','song-poetry','','[]','風攪平林萬木秋，臨歧送別思悠悠。',32,'全唐诗/poet.song.124000.json','["風攪平林萬木秋，臨歧送別思悠悠。", "也知八德池中水，不比尋常溪磵流。"]'),
('99a8fdb2-3089-4614-a3ea-7438f574d059','送聰首座兼簡陳寺丞','釋咸傑','宋','宋诗','song-poetry','','[]','十載相從話歲寒，刀山劍樹慣躋攀。',32,'全唐诗/poet.song.124000.json','["十載相從話歲寒，刀山劍樹慣躋攀。", "風雲會合機輪轉，行看知音笑展顔。"]'),
('8cc49b50-cb59-4a38-b5ca-9ed2981320b1','送如水頭','釋咸傑','宋','宋诗','song-poetry','','[]','如如方解說，此說若爲通。',48,'全唐诗/poet.song.124000.json','["如如方解說，此說若爲通。", "戳瞎摩醯眼，掀翻宇宙空。", "枯柴聊作用，活火展家風。", "去去休言別，智音一笑同。"]'),
('39c139b4-1213-451b-b239-805445cb95b0','徑山出鄉舟中寄二偈示衆  其一','釋咸傑','宋','宋诗','song-poetry','','[]','三冬水上打鞦韆，百尺竿頭棹釣船。',32,'全唐诗/poet.song.124000.json','["三冬水上打鞦韆，百尺竿頭棹釣船。", "寄語滿堂龍象衆，無勞掘地覓青天。"]'),
('95009051-a622-4c28-bd80-8688e6cb6587','徑山出鄉舟中寄二偈示衆  其二','釋咸傑','宋','宋诗','song-poetry','','[]','大丈夫兒合自知，得便宜是落便宜。',32,'全唐诗/poet.song.124000.json','["大丈夫兒合自知，得便宜是落便宜。", "無心用處急回首，莫待天明失却鷄。"]'),
('63527f06-900e-4606-87f4-679b30d1d842','贈何神童','釋咸傑','宋','宋诗','song-poetry','','[]','父母未生時，文章在何許。',116,'全唐诗/poet.song.124000.json','["父母未生時，文章在何許。", "及乎跳出來，光明照寰宇。", "傍觀眼難瞞，收錄奏明主。", "一覽贊希奇，楊晏堪爲伍。", "賜笏與綠袍，以顯其宗祖。", "人生天地間，休將年紀數。", "縱饒生百歲，無聞亦何補。", "偉哉英特大丈夫，君臣嘉會今合符。", "行看赤手扶宗社，大千捏聚一蘧廬。"]'),
('37b8a749-55a4-44fa-9b24-04b0030a91df','送先知客','釋咸傑','宋','宋诗','song-poetry','','[]','萬里南來川藞苴，奔流度刃扣玄關。',32,'全唐诗/poet.song.124000.json','["萬里南來川藞苴，奔流度刃扣玄關。", "頂門戳瞎金剛眼，去住還同珠走盤。"]'),
('c40dcf3d-8885-47b7-bb48-bdaecf641c57','送璘首座住定水','釋咸傑','宋','宋诗','song-poetry','','[]','一棒一條痕，一摑一掌血。',104,'全唐诗/poet.song.124000.json','["一棒一條痕，一摑一掌血。", "不是向上機關，亦非單傳妙訣。", "佛祖見之攢眉，魔外聞之膽折。", "建立此綱宗，當陽貴直截。", "璘侍吾十年，氣宇迥超絕。", "信手斫方圓，初不泥唇舌。", "青天霹靂轟，風雲會時節。", "行看定水起波濤，始信來源出處高。"]'),
('dfc45f5d-1316-4ef5-9162-9ae3346869f5','送恢侍者','釋咸傑','宋','宋诗','song-poetry','','[]','戴角擎頭與麽來，當機一拶頂門開。',32,'全唐诗/poet.song.124000.json','["戴角擎頭與麽來，當機一拶頂門開。", "行行勿謂無知己，閫外威權善自裁。"]'),
('95635376-0ac9-4034-8b10-e5e1dbcfbe9c','送雪峰化主','釋咸傑','宋','宋诗','song-poetry','','[]','手托庵門便放憨，千鈞重擔要人擔。',32,'全唐诗/poet.song.124000.json','["手托庵門便放憨，千鈞重擔要人擔。", "寥寥坐斷孤峰頂，雲衲相從晝夜參。"]'),
('3ac7e74d-ee28-47aa-b2ac-de02ee72c378','和璧書記','釋咸傑','宋','宋诗','song-poetry','','[]','擲劍揮空不住空，空輪無跡劍無鋒。',32,'全唐诗/poet.song.124000.json','["擲劍揮空不住空，空輪無跡劍無鋒。", "無鋒無跡憑誰會，會得金沙墮眼中。"]'),
('406f3f74-1664-4287-a2dd-21a1b50167da','送珣禪人還海壇','釋咸傑','宋','宋诗','song-poetry','','[]','家鄉到日許誰知，默默相逢絕路岐。',32,'全唐诗/poet.song.124000.json','["家鄉到日許誰知，默默相逢絕路岐。", "莫謂海門風浪惡，干戈元是太平基。"]'),
('c83c0054-403a-4909-9c1b-eaaf2e03094b','送慧知客還蜀','釋咸傑','宋','宋诗','song-poetry','','[]','踏破劍門關，十方無壁落。',48,'全唐诗/poet.song.124000.json','["踏破劍門關，十方無壁落。", "信步復南來，將錯還就錯。", "霜風刮面寒，梅梢初破蕚。", "去去又何言，寧負孤雲約。"]'),
('1495c05a-8b7c-46fa-9169-bcc31f71d953','示智悟道人','釋咸傑','宋','宋诗','song-poetry','','[]','智悟悟自心，不在一切處。',24,'全唐诗/poet.song.124000.json','["智悟悟自心，不在一切處。", "回首時觀瞻，便是佛國土。"]'),
('a66fc53d-8564-40a0-94af-c66e781d9a81','示善應道人','釋咸傑','宋','宋诗','song-poetry','','[]','善應無私，當陽有準。',20,'全唐诗/poet.song.124000.json','["善應無私，當陽有準。", "直下承當，入佛祖閫。"]'),
('76db05a2-44aa-40cd-a54e-218a1fcb9598','徑山茶湯會首求頌二首  其一','釋咸傑','宋','宋诗','song-poetry','','[]','徑山大施門開，長者慳貪俱破。',42,'全唐诗/poet.song.124000.json','["徑山大施門開，長者慳貪俱破。", "烹煎鳳髓龍團，供養千箇萬箇。", "若作佛法商量，知我一狀領過。"]'),
('9b6bfb44-9d5e-4425-a2ac-1f542ab56e2e','徑山茶湯會首求頌二首  其二','釋咸傑','宋','宋诗','song-poetry','','[]','有智大丈夫，發心貴真實。',64,'全唐诗/poet.song.124000.json','["有智大丈夫，發心貴真實。", "心真萬法空，處處無蹤跡。", "所謂大空王，顯不思議力。", "況復念世間，來者正疲極。", "一茶一湯功德香，普令信者從茲入。"]'),
('368ac488-9207-4afe-9fc3-08d4a3f04b06','示曾秘校','釋咸傑','宋','宋诗','song-poetry','','[]','天童得力句，不摇三寸舌。',60,'全唐诗/poet.song.124000.json','["天童得力句，不摇三寸舌。", "父母未生前，令已行摩竭。", "直下便承當，敢保猶未徹。", "放下百不知，腦門重著楔。", "唯是過量人，一拳無二說。"]'),
('99cb33dc-6dce-404f-a693-59441bb072c5','祥符建僧堂周都料求頌','釋咸傑','宋','宋诗','song-poetry','','[]','妙處如何論淺深，應之於手得於心。',64,'全唐诗/poet.song.124000.json','["妙處如何論淺深，應之於手得於心。", "方圓不用機謀力，長短休將語默尋。", "一斧便成真活計，三思始就費光陰。", "山僧直截重重說，須信真鍮不博金。"]'),
('a70ce1c2-256b-4c6d-8f59-e59f860d0ae0','頌古六首  其一','釋咸傑','宋','宋诗','song-poetry','','[]','三處移場定是非，頑心全不改毫釐。',32,'全唐诗/poet.song.124000.json','["三處移場定是非，頑心全不改毫釐。", "胡言漢語憑誰會，鐵額銅頭也皺眉。"]'),
('2570d3a3-ab09-4813-8a84-d1b527dffbad','頌古六首  其二','釋咸傑','宋','宋诗','song-poetry','','[]','賢聖法來未曾殺，而今斷這一刀休。',32,'全唐诗/poet.song.124000.json','["賢聖法來未曾殺，而今斷這一刀休。", "果然葛怛胸中落，笑殺靈山老比丘。"]'),
('99dc4da2-65df-4992-a50b-edd998edb594','頌古六首  其三','釋咸傑','宋','宋诗','song-poetry','','[]','一橈劈腦沒遮攔，大海波濤徹底乾。',32,'全唐诗/poet.song.124000.json','["一橈劈腦沒遮攔，大海波濤徹底乾。", "盡謂單傳并直指，誰知總被祖師謾。"]'),
('f815bfe7-9317-43e5-83bc-270a0ad8cf8a','頌古六首  其四','釋咸傑','宋','宋诗','song-poetry','','[]','驀就膏肓打一鍼，當時無處著渾身。',32,'全唐诗/poet.song.124000.json','["驀就膏肓打一鍼，當時無處著渾身。", "呵呵笑入嚴陽去，蛇虎爲鄰不可尋。"]'),
('1cd2cc16-41de-45d0-a5c6-008c4e7134b6','頌古六首  其五','釋咸傑','宋','宋诗','song-poetry','','[]','臘月蓮花菡萏香，三回賞手不尋常。',32,'全唐诗/poet.song.124000.json','["臘月蓮花菡萏香，三回賞手不尋常。", "直饒會得鬚眉落，早是龜毛數丈長。"]'),
('08eb2853-765d-4ee5-9db4-b08789c15b56','頌古六首  其六','釋咸傑','宋','宋诗','song-poetry','','[]','有問冬來事，京師出大黄。',24,'全唐诗/poet.song.124000.json','["有問冬來事，京師出大黄。", "貪他一粒粟，失却半年糧。"]'),
('a4ad4574-0a6e-4688-ac65-45359cf852df','羈鳳辭','韓元吉','宋','宋诗','song-poetry','','[]','我家既遠兮苕水爲鄉，中有羈鳳兮飛頡頏。',100,'全唐诗/poet.song.124000.json','["我家既遠兮苕水爲鄉，中有羈鳳兮飛頡頏。", "朱爲冠兮黼爲裳，五色炳兮耀文章。", "音律呂兮韵宮商，竹不實兮梧則僵。", "翳蒹葭兮飫稻粱，虞舜作樂夔在堂。", "集阿閣兮麗朝陽，胡爲去我兮天一方。", "友鳬雁兮侶鶖鶬，吁嗟鳳兮其來翔。"]'),
('f48362a4-a83f-4429-9c41-19455b89469e','遠遊十首  其一','韓元吉','宋','宋诗','song-poetry','','[]','我行蓬萊巔，俛首見月窟。',60,'全唐诗/poet.song.124000.json','["我行蓬萊巔，俛首見月窟。", "誰言滄海深，涉之不濡襪。", "頺波驚魚龍，起舞相蕩潏。", "衆真爲一笑，黄霧生絳闕。", "獨乘風中天，蹙踏波上月。"]'),
('d403f612-b39d-4d8a-be2d-c99a9d67f856','遠遊十首  其二','韓元吉','宋','宋诗','song-poetry','','[]','東隅有神人，被髮兩目丹。',60,'全唐诗/poet.song.124000.json','["東隅有神人，被髮兩目丹。", "手擎扶桑枝，騰光射乾坤。", "朱鳥爲前驅，火龍駕後軒。", "祝融不敢瞬，衛以千炎官。", "誓當掃霜霰，九宇常不寒。"]'),
('aa4d7ca1-bf9a-4fa0-ba72-d4a47101beba','遠遊十首  其三','韓元吉','宋','宋诗','song-poetry','','[]','雷出九地底，化爲萬鼓鼙。',60,'全唐诗/poet.song.124000.json','["雷出九地底，化爲萬鼓鼙。", "豕首柄石斧，剨然四海馳。", "夔魖與罔象，辟除靡有遺。", "無私乃帝令，風雨多隨之。", "苟能仆夷伯，何怨兒女爲。"]'),
('a64dd9fb-4bbb-40b4-9171-50ddadb484b8','遠遊十首  其四','韓元吉','宋','宋诗','song-poetry','','[]','紫皇宴瓊臺，鳳舞鸞且歌。',60,'全唐诗/poet.song.124000.json','["紫皇宴瓊臺，鳳舞鸞且歌。", "翠鬟兩仙女，倚歌奏雲和。", "秀色炯雙璧，晴雲灧秋波。", "曲終顧我笑，奈此人間何。", "贈以白玉環，綢繆期匪他。"]'),
('97c13d01-a3a8-4d88-aed4-c5c2bfdf65ef','遠遊十首  其五','韓元吉','宋','宋诗','song-poetry','','[]','大鈞轉一氣，急轂無停轅。',60,'全唐诗/poet.song.124000.json','["大鈞轉一氣，急轂無停轅。", "是非與生死，膠擾于其間。", "朝昏互變滅，倏已千萬年。", "豈知達道人，直作須臾觀。", "天地本無物，置之奚足言。"]'),
('0a9e0690-2fb9-4cf6-b70b-74032201fd14','遠遊十首  其六','韓元吉','宋','宋诗','song-poetry','','[]','海水赴大壑，雷奔墮空虛。',60,'全唐诗/poet.song.124000.json','["海水赴大壑，雷奔墮空虛。", "火輪煽金剛，蕩然爲尾閭。", "一闔復一闢，乾坤猶戶樞。", "萬生保靈根，至神守虛無。", "嘗以物所歸，返觀天地初。"]'),
('d39ac774-6750-4435-855b-e79e488c2f0b','遠遊十首  其七','韓元吉','宋','宋诗','song-poetry','','[]','崑崙九萬里，磅礴天地根。',60,'全唐诗/poet.song.124000.json','["崑崙九萬里，磅礴天地根。", "其下有玄圃，茲惟衆仙門。", "翩然兩白鶴，道我前飛翻。", "問津牽牛星，濯足洪河源。", "九關幸方闢，乘之遊紫垣。"]'),
('9e6e6870-8fad-4c30-b6dd-96ec60152c45','遠遊十首  其八','韓元吉','宋','宋诗','song-poetry','','[]','巨軸載厚地，沈沈惟九幽。',60,'全唐诗/poet.song.124000.json','["巨軸載厚地，沈沈惟九幽。", "日月所不燭，鬼神或拘囚。", "負臣與支祁，亦爲舜禹憂。", "靦彼世上兒，對面行奸偷。", "國章幸可脫，天刑此焉投。"]'),
('cb337f14-6a5c-4a07-b7cf-2348df764413','遠遊十首  其九','韓元吉','宋','宋诗','song-poetry','','[]','生死一大夢，夢覺誰當分。',60,'全唐诗/poet.song.124000.json','["生死一大夢，夢覺誰當分。", "夢中既不了，雖覺何足云。", "天光發吾宇，澹然無朝曛。", "至樂不外假，至貴斯無文。", "求仙與學佛，舉世徒紛紛。"]'),
('941df793-4669-4361-958e-aa10057a7e8f','遠遊十首  其一○','韓元吉','宋','宋诗','song-poetry','','[]','呼吸爲陰陽，動靜乃天地。',60,'全唐诗/poet.song.124000.json','["呼吸爲陰陽，動靜乃天地。", "猶然一身間，至理無弗備。", "蒼龍駕白虎，晝夜分六氣。", "坎離會精神，否泰本仁義。", "吾師不吾欺，持以御一世。"]'),
('700b5070-d298-43b3-a3e1-d83451261a7d','戊辰三月清明後三日見葉丈于石林承命賦詩作古風一首','韓元吉','宋','宋诗','song-poetry','','["\u897f\u6e56"]','東風易陰晴，一雨曉便止。',192,'全唐诗/poet.song.124000.json','["東風易陰晴，一雨曉便止。", "捨舟欣徐行，烏鵲聲爲喜。", "岧嶢石林谷，蒼翠間紅紫。", "丈人厭調元，玩意丘壑裏。", "鄭公化鄉閭，鄴侯盛圖史。", "千載發詞源，一點詣真理。", "霞裾月中仙，珠履天下士。", "時從詩酒樂，不負湖山美。", "方瞳照玄髮，眉壽端自此。", "緬懷西湖春，荆棘迷故里。", "兩髦看公遊，玉節旋屢弭。", "風塵三十載，碌碌類餘子。", "晚登載欣堂，謦欬聞正始。", "榆枋望天池，奮迅思决起。", "當謀白雲居，敢援赤松比。", "臨流整游觀，三沐聊洗耳。"]'),
('a65aac74-d511-4126-a02a-b9dc87303eaa','子雲兄命賦祿隠','韓元吉','宋','宋诗','song-poetry','','[]','子牟居江湖，而有魏闕心。',120,'全唐诗/poet.song.124000.json','["子牟居江湖，而有魏闕心。", "方朔待金馬，與世相浮沈。", "古來曠達士，豈必棲山林。", "吾兄官湖南，一室橫古今。", "朝披祝融高，暮涉湘水深。", "閒爲漫郎飲，戲效愚溪吟。", "聖賢雖云邈，彝訓夙所欽。", "斗水幸見收，西江等蹄涔。", "吁嗟咸陽市，敝帚希千金。", "應携忘言子，一和無絃琴。"]'),
('96da654a-31a9-4d27-a348-a3f0637b1b59','題畫卷','韓元吉','宋','宋诗','song-poetry','','[]','少年喜登臨，兩脚不憚軟。',120,'全唐诗/poet.song.124000.json','["少年喜登臨，兩脚不憚軟。", "支筇上雲山，得酒輒三返。", "一從老將至，所向意先懶。", "豈惟心事乖，要自脚力短。", "不如空齋坐，此畫一舒卷。", "超然函丈間，意作千里遠。", "漁舟已逍遥，茅屋更蕭散。", "江干所遊歷，物色猶在眼。", "浮生固幻景，況乃幻中幻。", "低頭顧吾廬，何如住山澗。"]'),
('5a1c4377-7f83-488d-a833-e375096c7566','梵隆大師乞詩隆能琴阮爲鼓數行','韓元吉','宋','宋诗','song-poetry','','[]','扁舟望涵山，一塔白雲裏。',120,'全唐诗/poet.song.124000.json','["扁舟望涵山，一塔白雲裏。", "東西互迎送，目盡三十里。", "下有布金園，軒窗面流水。", "上人富願力，物物盡經始。", "莊嚴萬人緣，功就只彈指。", "空齋了無事，鳴琴對清泚。", "游魚應朱絃，萬籟入流徵。", "我來不忍去，一聽賞幽耳。", "雨餘新月上，雲物紛可喜。", "莫作箕山吟，秋風坐中起。"]'),
('c851b0ce-c1d9-41bd-87cd-1c3366aa8c37','逢人','韓元吉','宋','宋诗','song-poetry','','[]','逢人似相識，初不辨名字。',96,'全唐诗/poet.song.124000.json','["逢人似相識，初不辨名字。", "折腰致寒暄，但道久暌異。", "歸來省眉目，彷彿猶夢寐。", "自非知心交，君輩定難記。", "將無半面別，正恐呼聲似。", "中年況多忘，錯認固無意。", "典刑要深思，摸索豈難事。", "尚想睢陽公，一見了奴隸。"]'),
('03911182-5442-4b73-b09a-707fba04db1b','寒食前三日携家至丁山','韓元吉','宋','宋诗','song-poetry','','[]','春事已過半，豫懷風雨憂。',168,'全唐诗/poet.song.124000.json','["春事已過半，豫懷風雨憂。", "苦無親朋樂，自携兒女遊。", "丁山峙城南，老稚載一舟。", "狹徑登詰曲，軒窗居上頭。", "遐觀接去鳥，俯視臨清流。", "溪花正爛漫，堤柳綠且柔。", "杳靄煙雲間，前瞻帝王州。", "田野亂棋布，山川莽相繆。", "病妻不能飲，取酒自勸酬。", "鮮妝誰家婦，造席爲我謳。", "風光亦可醉，景物似見留。", "惜無百金資，買此林壑幽。", "歲月實易得，里閭尚沈浮。", "歸來暮鐘響，蘋風動滄洲。"]'),
('59b736e5-2c26-482a-a8cd-b2b043b3ba9a','上巳日王仲宗趙德溫見過因招趙仲縝任卿小集以流水放杯行分韵得行字','韓元吉','宋','宋诗','song-poetry','','[]','春事倏已晚，飛花送啼鶑。',216,'全唐诗/poet.song.124000.json','["春事倏已晚，飛花送啼鶑。", "長安三月三，水邊盡傾城。", "緬懷杜陵老，感之見歌行。", "青鳥忽飛去，素鱗盤水精。", "往事誰復識，夢繞白玉京。", "朅來官閩陬，江湖渺餘情。", "嘉節閉門卧，客愁隨日生。", "風光入樽酒，使我嗟獨傾。", "良友慰寂寞，惠然成會并。", "金枝三雋才，千里未可程。", "王郎烏衣舊，高論玉麈橫。", "相逢寄觴詠，樂此天氣清。", "不知山陰會，絕唱疇能賡。", "庭隅有幽花，粲若萬玉纓。", "好風亦知人，微月相與明。", "蕭蕭城東路，頗復歌吹聲。", "景物正自佳，天涯意難平。", "不須恨陳迹，且用催詩成。"]'),
('1d14859b-f531-428f-918b-e035d0043914','上巳日與客遊張園','韓元吉','宋','宋诗','song-poetry','','[]','簿書有餘閒，春日亦已永。',168,'全唐诗/poet.song.124000.json','["簿書有餘閒，春日亦已永。", "況逢佳節休，朱墨得暫屏。", "名園跨江郊，危檻俯千頃。", "平蕪雨初勻，弱柳風自整。", "芳尋寄蕭散，意適忘醉醒。", "持觴挹花色，散策步林影。", "雖無歌舞妍，所愛亭館靜。", "佳辰天氣清，泉水助幽冷。", "緬懷山陰會，脩竹带崇嶺。", "應知佳客臨，懷抱均一騁。", "君看結綺地，茨棘翳眢井。", "當時擘牋人，正復對此景。", "江山幾興廢，歲月侵老境。", "但願中聖賢，疇能計鐘鼎。"]'),
('9507c378-1f70-4e65-8bf6-5a8c4b3992c2','避暑靈泉分韵得水字','韓元吉','宋','宋诗','song-poetry','','[]','閒居亦無營，歲月駛流水。',144,'全唐诗/poet.song.124000.json','["閒居亦無營，歲月駛流水。", "適聞新蟬鳴，袢暑遽如此。", "佳哉二三友，久要復鄰里。", "憐我疾病除，慰我懷抱喜。", "居然肯見顧，岑寂聊啟齒。", "空山百無有，翠阜映清泚。", "幽泉俯伴月，盎盎真石髓。", "坐久得清凉，山瓶還屢恥。", "一杯樂所遇，靜勝有真理。", "誰能走懸箔，赭門趁朝市。", "炎歊不可觸，暑雨欣漸止。", "幸有故人風，相過時洗耳。"]'),
('b873f580-91b0-4d88-989d-a725191f6756','七夕與孟婿約湯朝美率徐行中遊鶴山','韓元吉','宋','宋诗','song-poetry','','[]','城市競時節，幽尋固難同。',240,'全唐诗/poet.song.124000.json','["城市競時節，幽尋固難同。", "舊聞鶴山奇，欲往歲屢窮。", "茲辰尚殘暑，夙駕乘西風。", "楚俗候飛鵲，階庭閙兒童。", "誰能事針縷，覓巧瓜果中。", "起携東牀友，況得下榻翁。", "青蒲有傑客，放懷適相從。", "一招雲中仙，共呼潭底龍。", "翠壁聳崷崒，龜魚澹遊空。", "泉源幾萬斛，石竇藏豐隆。", "久知神物交，解致零雨濛。", "我田甚無多，例思年穀豐。", "公才正類此，時至會有庸。", "竹間小招提，閴靜無鼓鐘。", "枕石潄甘井，荔丹啟筠籠。", "若據兩石羊，摩挲古狄銅。", "高談劇霏屑，壯氣吹長虹。", "可無樽酒綠，遂使老頰紅。", "醉語或不省，嘯歌亦舂容。", "歸歟興難盡，月明照風松。"]'),
('eb9692ef-323a-45ad-8323-7126aebd974d','雪中以獨釣寒江雪分韵得獨字','韓元吉','宋','宋诗','song-poetry','','[]','常年待三白，此語未免俗。',168,'全唐诗/poet.song.124000.json','["常年待三白，此語未免俗。", "誰言歲將徂，一雪自云足。", "魃妖與癘鬼，不待巫茢逐。", "初喜沒馬蹄，還驚上牛目。", "三日雪不休，冰澌被茆屋。", "我貧固無事，尚賦一囊粟。", "長饑望年登，政恐麥不宿。", "天公豈相撩，饋以萬頃玉。", "朝來一堪煮，茗椀薦新菊。", "窗中有佳致，一水卧寒綠。", "城闉閴在眼，況復見巖谷。", "相過二三子，共喜醅甕熟。", "狂歌且暫醉，夜半還秉燭。", "猶勝杜陵翁，山中掘黄獨。"]'),
('74fb4444-8daf-4c25-b7df-dcf73082a2d7','雪中從邢懷正乞酒','韓元吉','宋','宋诗','song-poetry','','[]','櫑具高拄頰，風塵客長安。',240,'全唐诗/poet.song.124000.json','["櫑具高拄頰，風塵客長安。", "長安不宜客，歲暮仍苦寒。", "夜聞陰風喧，曉看雪漫漫。", "天公非惡劇，笑我貂裘單。", "坐令歌南山，白石空巑岏。", "正不妨我嘯，憑高事遐觀。", "四海同一雲，更覺天地寬。", "平湖發遠景，松竹如龍鸞。", "巉然兩峰高，玉峙峨瓊冠。", "緬懷邢公子，重城有家園。", "水石带林沼，幽亭厭雲端。", "仙粧映疏梅，秀色若可餐。", "璇題散冰筯，晶鹽貯牙盤。", "清歌出絕唱，筆閒走波瀾。", "幾欲泥君飲，持杯聽幽蘭。", "君家碧琳腴，到手無復殘。", "正豈須羔兒，尚能追清歡。", "蹇馿不敢出，强作哦詩酸。", "詩成不能寐，起舞清夜闌。", "儻可致麴生，當築白玉壇。"]'),
('e12b4bdc-2301-468d-814e-a3ec7932c211','自國清寺至石橋','韓元吉','宋','宋诗','song-poetry','','[]','出郭天氣陰，驅車日亭午。',96,'全唐诗/poet.song.124000.json','["出郭天氣陰，驅車日亭午。", "漫漫山中雲，猶作衣上雨。", "仙山八百里，勝槩隨步武。", "稽首金地尊，棲心玉京侶。", "浮空方廣寺，樓殿若可睹。", "石梁瀉懸流，下有老蛟怒。", "我來浄焚香，千花發茶乳。", "擬訪林下仙，飛來但金羽。"]'),
('a38f62bf-660a-4ad2-abc9-84d0570555a4','巖泉道中','韓元吉','宋','宋诗','song-poetry','','[]','出郭心易清，看山眼難飽。',48,'全唐诗/poet.song.124000.json','["出郭心易清，看山眼難飽。", "疏疏水中梅，殘雪相與好。", "歲華云已晚，官況良自笑。", "日暮城東門，霜風動衰草。"]'),
('7cc675a0-9f0b-450c-99c8-345af0ddab53','豅豁巖','韓元吉','宋','宋诗','song-poetry','','[]','蒼崖兩分張，絕壁千丈起。',120,'全唐诗/poet.song.124000.json','["蒼崖兩分張，絕壁千丈起。", "溪流忽奔注，萬石相披靡。", "跳波作驚雷，跬步清見底。", "攀藤上巉巖，却立半空裏。", "幾年天師廟，欄柱岌無址。", "幽禽答遠響，山花亂紅蘤。", "我來不知疲，危棧劣容屣。", "同僚具壺觴，脚軟正須此。", "塵埃得遐矚，真賞契心耳。", "只應潭中龍，見客亦驚喜。"]'),
('dd6881b4-8171-4dea-923c-624314f6a652','寒巖分韵得水字','韓元吉','宋','宋诗','song-poetry','','[]','青山如幽人，不肯住城市。',192,'全唐诗/poet.song.124000.json','["青山如幽人，不肯住城市。", "客從城市來，一見消吝鄙。", "平時與周旋，況復非俗士。", "我初見南山，秀色紛可喜。", "謂言官塵埃，洗滌端在此。", "經時未一至，引望若千里。", "昨朝得休暇，佳興難自已。", "秋原麗新晴，景物爲清美。", "獨遊已不惡，更約二三子。", "初從澗壑危，稍入巖石倚。", "白雲隨杖藜，蒼烟生屐齒。", "主翁亦好事，結茆脩竹底。", "庭空百無有，屈曲但流水。", "客來了不問，花草自紅紫。", "豈無一樽酒，欲飲還遽止。", "歸鞍不可速，吾亦聊洗耳。"]'),
('1bc36a0e-06f6-42de-8ac8-af35988afe1d','松江感懷','韓元吉','宋','宋诗','song-poetry','','[]','忽忽倦行役，栖栖問窮途。',120,'全唐诗/poet.song.124000.json','["忽忽倦行役，栖栖問窮途。", "生涯能幾何，所抱詩與書。", "淒涼吳淞路，不到十載餘。", "當年路傍柳，半已陰扶疏。", "繫舟上高橋，春水正滿湖。", "鷗鳥如有情，見人遠相呼。", "境豁目爲縱，興長心特舒。", "尚想張季鷹，此焉賦歸歟。", "生前與身後，底用論區區。", "但當酌美酒，一鱠江中鱸。"]'),
('1920d828-b224-4e62-b2ea-8827f3364cee','丁丑仲春將渡浙江從者請盤沙予畏而不許既登舟乘潮以濟中流膠焉捐十金募數力竟至沙上僅達西興狼狽殊甚從者笑之感而賦詩','韓元吉','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','桑田變東海，此語聞自昔。',192,'全唐诗/poet.song.124000.json','["桑田變東海，此語聞自昔。", "嗟我百年人，耳目詎能識。", "誰言錢塘江，遂有車馬跡。", "漲沙莽雲屯，衣带僅尋尺。", "我初未渠信，束襜俟潮汐。", "是時月既望，春晴好風色。", "同舟二三子，擊楫意頗適。", "中流類坳堂，竟作膠柱瑟。", "褰裳亂濤波，植杖負囊笈。", "居然濯我足，長堤慰行客。", "西興忽在眼，喚渡猶頃刻。", "鯤鵬定何之，魚龍豈遷宅。", "斜陽照高岸，得酒餞寒濕。", "平生忠信懷，對此徒感激。", "翻成僕奴笑，撫事吁莫測。", "莫問曲池平，空悲峴山側。"]'),
('ef92ac81-0c34-4fad-8610-c16d851d14cf','望靈山','韓元吉','宋','宋诗','song-poetry','','[]','嶽鎮古所錄，茲山諒其遺。',216,'全唐诗/poet.song.124000.json','["嶽鎮古所錄，茲山諒其遺。", "憶從西江來，恍惚欣見之。", "初疑春雨晴，雲物出怪奇。", "稍稍對巖壁，森森面嶺奇。", "紛紜類列障，散漫如連帷。", "磅礴千里間，衆景皆奔馳。", "頗訝地軸湧，未覺天柱虧。", "不讓崑崙高，遂使泰華移。", "諸峰七十二，磊砢略可推。", "駢觀擁佛髻，遠睇凝蛾眉。", "大或覆鐘鼎，細亦銛刀錐。", "石柜一何高，梯天此爲墀。", "崩騰鐵馬羣，中有大將旂。", "身居萬石貴，氣壓累卵危。", "雄傑亦莫狀，清深亦餘姿。", "蛟螭護絕磴，草木忘四時。", "豈知水晶宮，閟藏神所司。", "陰崖彼何靈，頸斷不敢悲。"]'),
('1484c3a2-85a4-4f22-bdf4-2bfd57b6a7d1','南澗  其一','韓元吉','宋','宋诗','song-poetry','','[]','朱墨日過眼，溪山誰復遊。',72,'全唐诗/poet.song.124000.json','["朱墨日過眼，溪山誰復遊。", "夜聞西風喧，起看天地秋。", "王事有休沐，駕言指林丘。", "新晴鳥烏樂，路入南澗幽。", "高峰左右列，野水縱橫流。", "問舍苦不早，求田亦良謀。"]'),
('5864a5a1-9d1a-4cc3-a20c-b14f804a085f','南澗  其二','韓元吉','宋','宋诗','song-poetry','','[]','高巖跨層巔，一徑入蒼翠。',72,'全唐诗/poet.song.124000.json','["高巖跨層巔，一徑入蒼翠。", "三休徹上頭，却立睨平地。", "當年寶藏興，中夜出光氣。", "至今石縫裂，篝火尚能記。", "盈虛誰可測，開闔神自秘。", "空房有殘僧，骨冷夜無寐。"]'),
('c6229dac-472b-4c47-bc92-a4f0dbea6e76','南澗  其三','韓元吉','宋','宋诗','song-poetry','','[]','入山衣屨寒，出山衣屨濕。',72,'全唐诗/poet.song.124000.json','["入山衣屨寒，出山衣屨濕。", "初迷烟雨來，稍識雲氣集。", "空濛掠面過，可玩不可執。", "不知市廛地，去此凡幾級。", "青松入長望，白鳥伴危立。", "冷然笑身世，萬事何汲汲。"]'),
('9db179a4-3b65-4bd1-b849-8d75c6eba8b0','南澗  其四','韓元吉','宋','宋诗','song-poetry','','[]','有酒不得飲，呼船過溪南。',72,'全唐诗/poet.song.124000.json','["有酒不得飲，呼船過溪南。", "溪南亦何好，古寺依晴嵐。", "上有百尺樓，下有千丈潭。", "城闉一目盡，晚山日相銜。", "烹茶弔陸子，蠟屐登巉巖。", "相逢作行樂，猶勝空坐談。"]'),
('742999cb-12de-4128-a18b-8fe657f54354','南澗  其五','韓元吉','宋','宋诗','song-poetry','','[]','秋風何時來，午暑忽已散。',72,'全唐诗/poet.song.124000.json','["秋風何時來，午暑忽已散。", "娟娟木犀花，弄蘂亦璀璨。", "清香不自惜，擁鼻得奇觀。", "古來達道人，至樂在山澗。", "藝蘭與種蕙，採掇契幽願。", "置此勿復言，吾方困遊宦。"]'),
('96157cad-4d1c-46a0-95e4-8b145b1f8d23','李仲鎮懶窠','韓元吉','宋','宋诗','song-poetry','','[]','我性天下懶，自謂世莫雙。',240,'全唐诗/poet.song.124000.json','["我性天下懶，自謂世莫雙。", "朅來官中都，懶極濟以憃。", "有如千黑魚，東西轉橋矼。", "又如橐駝卧，厭逐羣吠尨。", "鼻洟任縱橫，胞轉徒胮肛。", "紛紛夸奪兒，見我語輒哤。", "平生李公子，老大同鄉邦。", "奈何奪我有，收斂付一窗。", "作窠寓以名，異音乃同腔。", "金馬可避世，何殊鹿門龐。", "君看富貴塗，機危甚緣橦。", "爭榮僅錙銖，力欲九鼎扛。", "金朱擁丹轂，視之亦螻蛖。", "愛君陽羨居，有田種蘭茳。", "溪山带城郭，松竹環旌幢。", "連娟幾脩眉，清歌艷明釭。", "客至即盡醉，不待金石撞。", "尚餘詩語工，詞源倒三江。", "好懶得真懶，使我心益降。", "何時半作分，臨流聽琤淙。"]'),
('a3eba96a-897d-447a-b0bf-2782b9dfddc7','趙仲縝梅川','韓元吉','宋','宋诗','song-poetry','','["\u8861\u5c71"]','堂前面羣山，堂下俯流水。',168,'全唐诗/poet.song.124000.json','["堂前面羣山，堂下俯流水。", "揚雄一區宅，歲晚何在此。", "將無山水佳，更爲風物美。", "城隅三家渡，華屋照清泚。", "舉手招梅仙，低頭叫陸子。", "前松後梧竹，左桂右蘭芷。", "江花漾茶甌，巖樹排棐几。", "客來索無有，樽酒間圖史。", "不作隠士廬，合號君子里。", "吾人天潢秀，時至當决起。", "飽餐南嶽芋，閒曳東郭履。", "山名不負儂，因之得名字。", "彈冠可前卜，問舍真早計。", "笑殺陶淵明，酒資良未遂。"]'),
('4cff551b-6490-45f8-b6bf-95aa976bae5a','題鄭舜舉蔗庵','韓元吉','宋','宋诗','song-poetry','','[]','吾州富佳山，脩竹連峻嶺。',204,'全唐诗/poet.song.124000.json','["吾州富佳山，脩竹連峻嶺。", "居然縛塵埃，一見輒心醒。", "豈知刺史宅，跬步閟清景。", "古木盤城隅，石徑幽且迥。", "當年徐常侍，坐愛雲水冷。", "溪南羣峰秀，矗矗錐出穎。", "鄭公閉閣暇，獨步毘廬頂。", "曰此氣象殊，逍遥步方永。", "喚客倒清樽，燃薰煮奇茗。", "庭空無一事，賓吏絕干請。", "佳處由漸入，斯語煩記省。", "淵明嘗有語，結廬向人境。", "恍如白蓮社，揮麈對宗炳。", "誰云忙裏閒，要識動中靜。", "我來款妙論，散策步林影。", "心田豁叢茅，氣馬罷征騁。", "他時記棠陰，老意亦深肯。"]'),
('9a085fe2-d148-4ef9-80ac-27145db6f20c','朱元晦清湍亭','韓元吉','宋','宋诗','song-poetry','','[]','青山足佳遊，遠睇欲無路。',96,'全唐诗/poet.song.124000.json','["青山足佳遊，遠睇欲無路。", "稍尋絕澗入，始辨雲間樹。", "泉聲若招客，倚杖得夷步。", "驚湍瀉亂石，激激有清趣。", "風微鳥哢幽，日徹魚影聚。", "居然魚鳥樂，正欠幽人住。", "野僧豈忘機，作亭以茲故。", "因君賦新詩，我亦夢其處。"]'),
('a8098935-6d15-4552-a86e-30f9dc5ba2a6','題潘叔玠家達觀亭','韓元吉','宋','宋诗','song-poetry','','[]','車塵蔽重城，俯首但闤闠。',120,'全唐诗/poet.song.124000.json','["車塵蔽重城，俯首但闤闠。", "誰知達觀亭，自與空闊對。", "青山接簷楹，白塔見雲外。", "迢遥眼界浄，妙處心境會。", "平生九垓期，洗耳聽天籟。", "一爲簿領縛，局促無可奈。", "每憑君家欄，曠若解鈴釱。", "躋攀得遐矚，頓覺天宇大。", "頗慚北山移，欲賦楚臺快。", "泰然發天光，閒目了無礙。"]'),
('15966b6b-c55c-471e-85bb-068c01fb2205','列岫亭用范伯升韵','韓元吉','宋','宋诗','song-poetry','','[]','自我來南溪，池塘幾春草。',144,'全唐诗/poet.song.124000.json','["自我來南溪，池塘幾春草。", "結茅依雲端，愛此山回抱。", "奇峰七十二，羅列景逾好。", "豈殊謝公窗，澄江更縈繞。", "孤城千家邑，一目可盡了。", "植葵思夏深，種菊待秋杪。", "物華靜中見，至理得深造。", "東山與魯郊，底用評大小。", "平生丘壑心，計拙詎能巧。", "亭臯遠俗客，曳杖日頻到。", "簞瓢樂未改，在澗槃亦考。", "況有吾人詩，飄然異郊島。"]'),
('aa51987e-f871-4aa7-836d-fc38014cfdf1','凌風亭','韓元吉','宋','宋诗','song-poetry','','[]','西山如層城，壁立有堅對。',120,'全唐诗/poet.song.124000.json','["西山如層城，壁立有堅對。", "逶迤雉堞出，一水相縈带。", "誅茅發頹垣，偶與嘉景會。", "天風無邊來，雲日爲破碎。", "誰能了蘋末，直欲跨鵬背。", "飄然壓塵土，九壤真一塊。", "王喬幸齊驅，禦寇亦同載。", "不知吏役縛，且樂公事退。", "春光到花木，欄檻愜清快。", "相期睨南溟，整我飛霞佩。"]'),
('ead21fc0-7756-4d47-9663-221b4ccdbba9','丹青閣','韓元吉','宋','宋诗','song-poetry','','[]','傑閣跨虛壑，危欄轉層峰。',120,'全唐诗/poet.song.124000.json','["傑閣跨虛壑，危欄轉層峰。", "城郭麗朝暉，山水涵秋容。", "幽尋適暇日，況有佳客從。", "微官厭趨走，野性便疏慵。", "少攄泉石願，一洗塵埃胸。", "却上陸羽亭，褰裳踏風松。", "東軒俯喬木，高花爛芙蓉。", "感此節物換，愧爾樵漁蹤。", "清談且蕭散，酌飲亦時供。", "興闌勿遽嘆，勝遊當復重。"]'),
('1e6d423e-f788-4131-97e9-14a088af6ac1','清暉閣','韓元吉','宋','宋诗','song-poetry','','[]','臺府填都會，乃與山水期。',192,'全唐诗/poet.song.124000.json','["臺府填都會，乃與山水期。", "青溪带秦淮，渺若萬頃陂。", "主公金閨舊，官曹日追隨。", "閉閣理萬事，朱欄俯漣漪。", "晴波納遠景，摇蕩扶桑枝。", "浩然江湖興，頗與魚釣宜。", "風月朝暮佳，軒窗有餘姿。", "向來非無人，未發此段奇。", "嗟我老病軀，時來矚須眉。", "停杯待舉網，屢醉倒接䍦。", "意適反無語，欠公壁間詩。", "只今入幽夢，官居類雞栖。", "公亦那久留，濯纓詠來思。", "不知鳳凰沼，何如習家池。", "新霜著羣木，歸舟颺旌旗。", "寄言坐上客，酒至幸勿辭。"]'),
('639e3e52-5641-481b-a5e3-60869c93378d','溪山堂次韵','韓元吉','宋','宋诗','song-poetry','','[]','幽人誰與娛，作堂面溪灣。',156,'全唐诗/poet.song.124000.json','["幽人誰與娛，作堂面溪灣。", "堂中有山色，朝暮來雲間。", "正作杜老狂，頗異韓子奸。", "超然物外景，便覺非人寰。", "登臨得遐矚，似破天壤慳。", "詩成隠几笑，溪山亦開顔。", "繚繞明鏡中，參差峨髻鬟。", "苦無俗客語，但聞鳥間關。", "出門曳藜杖，頼有此往還。", "虛名兩蝸角，自鬭觸與蠻。", "時平衆賢聚，君胡得長閒。", "會從車騎出，勒石燕然山。", "正恐萬里塗，高轅不容攀。"]'),
('4c352b99-e71f-4c6d-927c-75863b001ac2','歸樂堂','韓元吉','宋','宋诗','song-poetry','','[]','百歲自逆旅，微官更周流。',144,'全唐诗/poet.song.124000.json','["百歲自逆旅，微官更周流。", "應知歸來樂，不減萬戶侯。", "淵明一縣尹，折腰憎督郵。", "松菊繞東籬，田園事西疇。", "素琴酌樽酒，稚子相獻酬。", "朱侯青雲士，頗復有此不。", "方爲功名驅，乃與賢達侔。", "築堂寄閒暇，笑談指林丘。", "蕉黄間荔丹，蠔山薦新篘。", "嗟我實何人，市朝亦淹留。", "因君動佳興，擬作汗漫遊。", "安得二頃田，可卧百尺樓。"]'),
('38bd767c-4621-4354-a3d5-f356f66a5af5','護國寺次前婺州韵','韓元吉','宋','宋诗','song-poetry','','[]','雙蛾渺雲端，流水但空谷。',96,'全唐诗/poet.song.124000.json','["雙蛾渺雲端，流水但空谷。", "尚喜雲外山，娟娟作眉綠。", "佳人不可見，夜半風滿竹。", "竹聲入清夢，夜客慰孤宿。", "山中富蘭若，欲往寧畏獨。", "老僧亦知人，逢場共竿木。", "林芳得清心，幽澗供濯足。", "便可賦歸歟，簞瓢勝鼎肉。"]'),
('dd15fe6b-4a2b-4e15-99f1-8562b2832c9a','喜呂令防歸','韓元吉','宋','宋诗','song-poetry','','[]','閒居玩編簡，蕭然罕朋儔。',168,'全唐诗/poet.song.124000.json','["閒居玩編簡，蕭然罕朋儔。", "古士信可佳，欲語不見酬。", "豈如平生交，臭味能相投。", "別久得會面，笑談解人憂。", "況君復比鄰，共此一壑幽。", "招邀接步武，文字資討求。", "昨朝喜君來，快若沈疴瘳。", "開口四五笑，亹亹談未休。", "鷄鳴任風雨，疇能記窮愁。", "因知名教地，至樂真天游。", "新凉動梧竹，柴門掩清秋。", "三徑無雜華，茙葵散金甌。", "年豐魚蟹熟，樽酒亦易謀。", "相過勿厭數，此外俱悠悠。"]'),
('981409ba-85bb-48ad-b53f-5c78f691ddd0','毛文仲惠文編','韓元吉','宋','宋诗','song-poetry','','[]','平生毛公詩，訓傳固已久。',240,'全唐诗/poet.song.124000.json','["平生毛公詩，訓傳固已久。", "紛紜齊魯失，浪自開戶牖。", "至哉一言蔽，可用嚴墨守。", "淵源見雲仍，夢澤吞八九。", "雕章與棘句，錦繡間瓊玖。", "嶷如犀始擢，粲若蚌初剖。", "肉食乃聞韶，晝日或見斗。", "三百篇未忘，七十子何有。", "應如摩天刃，要是修月手。", "時來豈無用，妙處端不朽。", "君看夸奪兒，在後熟顧叟。", "喧啾蛩負戶，嘈囋蟬蔭柳。", "誰令口鳴悲，正使心欲嘔。", "豈無熊羆士，底問牛馬走。", "岧嶢金閨門，豪傑自先後。", "而君尚窮滯，履敝衿見肘。", "才名三十年，骯髒驚白首。", "我慚拜嘉賜，幼婦連虀臼。", "相望百里遠，曾未共樽酒。", "期君頌中興，步出次山右。"]'),
('b2fc550c-92c5-4642-873a-28e97580176a','寄趙德莊以過去生中作弟兄爲韵七首  其一','韓元吉','宋','宋诗','song-poetry','','[]','悠悠功名期，苒苒歲月過。',48,'全唐诗/poet.song.124000.json','["悠悠功名期，苒苒歲月過。", "勞生閲半百，僅爾脫寒餓。", "山林有夷塗，此責當萬坐。", "閉門歌陽春，非君諒誰和。"]'),
('57e2802a-3241-40f8-acd3-026880f715d2','寄趙德莊以過去生中作弟兄爲韵七首  其二','韓元吉','宋','宋诗','song-poetry','','[]','憶昨鍾山來，君亦湓浦去。',48,'全唐诗/poet.song.124000.json','["憶昨鍾山來，君亦湓浦去。", "今年赴湓浦，鍾山復君住。", "出處每相似，屢觸衆狙怒。", "毀譽久自定，子賢吾亦庶。"]'),
('7befb3a9-f75e-4312-adb4-e996e7b82f03','寄趙德莊以過去生中作弟兄爲韵七首  其三','韓元吉','宋','宋诗','song-poetry','','[]','士苦不自重，貪名乃忘生。',48,'全唐诗/poet.song.124000.json','["士苦不自重，貪名乃忘生。", "向來望塵子，得車定何榮。", "浮雲蔽天壤，豈礙日月明。", "惟餘金石交，可論藏與行。"]'),
('ea36183a-0d12-4b98-8b24-9eda308ad01c','寄趙德莊以過去生中作弟兄爲韵七首  其四','韓元吉','宋','宋诗','song-poetry','','[]','築城始議戍，寓兵復言攻。',48,'全唐诗/poet.song.124000.json','["築城始議戍，寓兵復言攻。", "二年大江南，兵戈在目中。", "憂時亦千慮，惟子與我同。", "詣闕請長纓，終軍本兒童。"]'),
('8e1d24e3-f6cd-44d4-ba5b-9b75de494ecc','寄趙德莊以過去生中作弟兄爲韵七首  其五','韓元吉','宋','宋诗','song-poetry','','[]','我初見君詩，謂世無此作。',48,'全唐诗/poet.song.124000.json','["我初見君詩，謂世無此作。", "飄零三十年，文思各衰落。", "俱持使者節，恨別還作惡。", "未置白玉堂，端須著巖壑。"]'),
('86a11360-78e6-41e7-8747-5771d4d22afc','寄趙德莊以過去生中作弟兄爲韵七首  其六','韓元吉','宋','宋诗','song-poetry','','[]','我生少孤貧，四海兩兄弟。',48,'全唐诗/poet.song.124000.json','["我生少孤貧，四海兩兄弟。", "拊嫗頼母慈，離別幾揮涕。", "宦遊與夫子，中外輒相值。", "所恨姓氏殊，孰云情好異。"]'),
('f1c768e6-c660-4efc-8370-921d592075d8','寄趙德莊以過去生中作弟兄爲韵七首  其七','韓元吉','宋','宋诗','song-poetry','','[]','處世那近名，居官敢言清。',48,'全唐诗/poet.song.124000.json','["處世那近名，居官敢言清。", "平生阿堵物，疇能字之兄。", "春風一杯酒，與君花下傾。", "窮秋動摇落，江湖渺離情。"]'),
('7cd791e1-e32b-467a-bc22-7099c211e9ff','送湯朝美還金壇','韓元吉','宋','宋诗','song-poetry','','[]','騰駒輕卧駝，野蔓欺落木。',240,'全唐诗/poet.song.124000.json','["騰駒輕卧駝，野蔓欺落木。", "舉頭便干霄，春至亦重綠。", "人生百年內，萬事紛過目。", "得爲蠖步伸，失作蠵頸縮。", "古來曠達士，一視等蠻觸。", "功名本時命，用舍豈榮辱。", "湯公涉南荒，歲月猶轉轂。", "幾年卧新州，寧肯事雞卜。", "身安一瓢飲，志大五車讀。", "朅來靈山隈，跫然慰虛谷。", "濯足山下泉，愛我泉上竹。", "相從一長笑，忍效阮生哭。", "胸中經濟略，欲語動驚俗。", "誰知天意回，歸棹如許速。", "春風正浩蕩，江水清可掬。", "海濤拍千峰，挂席下浮玉。", "遥欣倚門念，三徑歡僮僕。", "送君得無恨，我步嗟局促。", "要看萬里途，更試參雲足。", "家山幸毋留，吾皇思陳牘。"]'),
('bab760e5-b137-4ede-ad0d-7f0ed7192b2d','送楊安止罷信幕赴調','韓元吉','宋','宋诗','song-poetry','','["\u897f\u6e56"]','後生仰前輩，今世思古人。',216,'全唐诗/poet.song.124000.json','["後生仰前輩，今世思古人。", "豈重歲月久，所懷風俗淳。", "昔我家閩中，龜山實其鄰。", "出門尚羣盜，欲往志不伸。", "相從朋舊間，得語盡可珍。", "俯仰今幾何，遺編半埃塵。", "白頭入幕府，始與夫子親。", "夫子龜山裔，麕䴥見祥麟。", "晚同柱後史，無心問平津。", "典刑在眉睫，溫然異羣倫。", "向來簿領中，挾書聽諄諄。", "豈不開我塞，異聞此其真。", "亦或舉樽酒，笑談忘賤貧。", "同僚各分散，世事日以新。", "遥憐鄭公鄉，俎豆猶莘莘。", "彈冠定不苟，家庭有書紳。", "道學固未泯，吾謀復誰陳。", "尚想金馬門，西湖醉餘春。"]'),
('58cb6389-f051-4d14-9669-d72b8bfda11e','送趙任卿蕪湖丞','韓元吉','宋','宋诗','song-poetry','','[]','青山照濡須，江駛不可渡。',192,'全唐诗/poet.song.124000.json','["青山照濡須，江駛不可渡。", "當年黄鬚兒，跨馬識其處。", "奸雄有遺跡，草木尚西顧。", "孤城千家邑，政爾橫故戍。", "翩翩佳公子，儒雅稱風度。", "金門向蓬萊，曾未試闊步。", "疇令一官卑，僅乃高尉簿。", "得非多言窮，定坐能詩故。", "相從十年間，了不見喜怒。", "千金第深韞，至寶可輕付。", "江山落君手，判斷得佳句。", "誰歟招得仙，我欲起謝傅。", "似聞王師出，鼙鼓近營駐。", "老生固常談，愚者亦千慮。", "一樽別時酒，且用慰遲暮。", "去去無久留，功名有夷路。"]'),
('08e31851-edfe-4685-b5d1-e9beac544861','送杜少卿起萃知遂寧府以高名千古重如山爲韵七首  其一','韓元吉','宋','宋诗','song-poetry','','[]','男兒生世間，身名要俱高。',48,'全唐诗/poet.song.124000.json','["男兒生世間，身名要俱高。", "苟不得其所，富貴輕鴻毛。", "古來獻言士，忠嘉極夔臯。", "尚友千載餘，斯心豈徒勞。"]'),
('478398fb-3766-4d8b-8360-b87ed7a50a7d','送杜少卿起萃知遂寧府以高名千古重如山爲韵七首  其二','韓元吉','宋','宋诗','song-poetry','','[]','十年天壤間，久矣聞公名。',48,'全唐诗/poet.song.124000.json','["十年天壤間，久矣聞公名。", "詞華少陵系，臭味修水甥。", "一著獬廌冠，讜論驚縱橫。", "九卿固美秩，不如偃專城。"]'),
('107aeb7c-aef0-4e6d-ba47-517f7c84152b','送杜少卿起萃知遂寧府以高名千古重如山爲韵七首  其三','韓元吉','宋','宋诗','song-poetry','','[]','國朝御史府，一代名多傳。',48,'全唐诗/poet.song.124000.json','["國朝御史府，一代名多傳。", "暫退或久庸，始愚亦終賢。", "得失安足論，俯仰歲已遷。", "但存愛君心，豈憂時命邅。"]'),
('9cca8254-0bcb-41be-a99d-31e8851fa649','送杜少卿起萃知遂寧府以高名千古重如山爲韵七首  其四','韓元吉','宋','宋诗','song-poetry','','[]','厚味得無毒，良藥信多苦。',48,'全唐诗/poet.song.124000.json','["厚味得無毒，良藥信多苦。", "毒留患滋生，苦過疾自愈。", "吾君堯舜資，事業方復古。", "公行幸遲遲，去國猶去魯。"]'),
('0034b801-4137-409c-97c2-a8e935f7a5e5','送杜少卿起萃知遂寧府以高名千古重如山爲韵七首  其五','韓元吉','宋','宋诗','song-poetry','','[]','靈旂出江淮，犀甲下秦隴。',48,'全唐诗/poet.song.124000.json','["靈旂出江淮，犀甲下秦隴。", "天聲斃狂酋，百戰有餘勇。", "手斂權貴避，膽落將士愯。", "誰歟任司直，用舍繫輕重。"]'),
('b7a683a1-fa6b-4ba6-b974-ef5fc726d22d','送杜少卿起萃知遂寧府以高名千古重如山爲韵七首  其六','韓元吉','宋','宋诗','song-poetry','','[]','西京蜀都望，淵雲暨相如。',48,'全唐诗/poet.song.124000.json','["西京蜀都望，淵雲暨相如。", "節誼知不足，文章焉取餘。", "凜然見風采，吾非斯人徒。", "峨峨眉山陽，不但聞三蘇。"]'),
('c625853e-3469-4cc5-a6b5-d7a6fb6dabe0','送杜少卿起萃知遂寧府以高名千古重如山爲韵七首  其七','韓元吉','宋','宋诗','song-poetry','','[]','征帆轉吳楚，涉江指岷山。',48,'全唐诗/poet.song.124000.json','["征帆轉吳楚，涉江指岷山。", "富貴歸故鄉，昔人以爲難。", "大府固可樂，高風亦難攀。", "豈必待政成，甘泉行賜環。"]'),
('4f16efaa-de59-4cb0-97b4-6cd1eadf2768','清曠亭送子雲得有字','韓元吉','宋','宋诗','song-poetry','','[]','歡期苦難逢，離別乃易久。',120,'全唐诗/poet.song.124000.json','["歡期苦難逢，離別乃易久。", "天涯老兄弟，況復親白首。", "田園固不足，功名亦何有。", "今年送兄行，正爾作太守。", "池陽古名郡，地控大江口。", "舟來武昌魚，車載桑落酒。", "登臨得齊山，端不負重九。", "公餘亦堪樂，尚有此客否。", "天威動江淮，狂寇行授首。", "努力幸馳驅，腰看印如斗。"]'),
('4772201c-ba67-486a-a96e-2b0a0061f459','別子雲','韓元吉','宋','宋诗','song-poetry','','[]','離觴不解醉，愁多令酒醒。',48,'全唐诗/poet.song.124000.json','["離觴不解醉，愁多令酒醒。", "別懷亦云惡，況此兄弟情。", "春風釀寒雨，十日未肯晴。", "回頭易千里，江南短長亭。"]'),
('62903645-e90d-46a8-9879-b3241983951f','次韵韓子師遊三洞過赤松','韓元吉','宋','宋诗','song-poetry','','[]','山城一雨足，水滿高下塘。',216,'全唐诗/poet.song.124000.json','["山城一雨足，水滿高下塘。", "好風從西來，蕭然終夕凉。", "孌彼池間蓮，當軒洗紅粧。", "官事無時休，涉筆雁鶩行。", "豈知青雲客，夙駕遊寶坊。", "坐厭市井塵，步尋松桂香。", "陰崖有靈湫，玉簡帝所藏。", "摘石收澗碧，梯空擷林芳。", "金盤薦麟脯，冰壺注瑶漿。", "更語妙道根，寶篆開函琅。", "路轉九曲溪，著足千仞岡。", "舊聞井中丹，清宵發神光。", "直欲餌碧霞，誰能擣玄霜。", "朝來得君詩，險韵句復長。", "使我鴻鵠心，欻爲天際翔。", "仙人亦舉手，笑我徒奔忙。", "語默付一笑，物我當兩忘。", "獨携非有生，但醉無何鄉。"]'),
('070f1982-99c4-4223-88c5-2e833c82882b','次韵祐父秋懷','韓元吉','宋','宋诗','song-poetry','','[]','詩人固多窮，飲水但饑卧。',96,'全唐诗/poet.song.124000.json','["詩人固多窮，飲水但饑卧。", "誰能趨權門，殘冷分涕唾。", "爭名與馳利，到眼不一過。", "居然流俗罪，我爾乃同坐。", "得爲荀郎弔，失作蒯生賀。", "却笑貨殖翁，高談六雄破。", "愁來挹黄嬭，悲至邀白墮。", "感時忽秋吟，蟋蟀正相和。"]'),
('9b06c502-4476-4903-99e0-22fd1d1495a8','依韵恭和御製秋懷','韓元吉','宋','宋诗','song-poetry','','[]','商飆起璿霄，爽氣靜瑶海。',72,'全唐诗/poet.song.124000.json','["商飆起璿霄，爽氣靜瑶海。", "聖皇撫時運，喜色動眉彩。", "蠭旗佇西指，乘轅行北改。", "濤聲鼓萬壑，夜半響竽籟。", "漢儀欣復見，周鼎知德在。", "猗歟沛中歌，雲飛風正大。"]'),
('b15637e7-adf0-4e3f-8085-9cdd834dd356','次韵升之叔秋懷','韓元吉','宋','宋诗','song-poetry','','[]','客至得濁酒，共飲消百憂。',60,'全唐诗/poet.song.124000.json','["客至得濁酒，共飲消百憂。", "凉飆颯短景，感此歲已秋。", "忽驚草木隕，尚喜禾黍收。", "九鼎豈不慕，二頃亦良謀。", "往聖實有言，未覺富可求。"]'),
('3178224d-5b09-4607-87ff-c2fb8d379ee6','平生八見女而存者五人比又得女少稷作詩見寬次韵謝之','韓元吉','宋','宋诗','song-poetry','','[]','漸老思似續，撫懷良惘然。',288,'全唐诗/poet.song.124000.json','["漸老思似續，撫懷良惘然。", "空餘歲寒心，凜凜松柏堅。", "平生孔明婦，貧賤房且專。", "生女不生男，造物寧我偏。", "孌彼五嬌兒，弄瓦相隨肩。", "人言可禦盜，無乃繆以千。", "囊金不辦嫁，擇婿那敢全。", "今年又增一，比比安求旃。", "覺貧與覺富，可笑還可憐。", "向來兩童烏，泡幻隨變遷。", "應門固未計，疇復與我玄。", "我家豈無人，文章紹編箋。", "經心不能釋，欲語氣已填。", "筮言晚當見，默禱資明蠲。", "行年且四十，那得慰眼前。", "陶公謂勝無，此論吾師焉。", "舒宣儻可待，弓裘猶足傳。", "今者事方殷，煩君費詩篇。", "君詩妙難敵，巨刃迎小鮮。", "炯炯明月珠，一一照眼圓。", "吁嗟人生事，歲月如奔川。", "豈不舒我憂，熊羆夢豐年。", "蓬門亦何祥，但見巾帨懸。", "會當亦添丁，荷鋤賦歸田。"]'),
('4621ecce-7228-4aad-8ef1-689981f5879c','明遠次韵超然談道因以謔語爲戲將無同耶','韓元吉','宋','宋诗','song-poetry','','[]','忘機亦忘言，政作口挂壁。',96,'全唐诗/poet.song.124000.json','["忘機亦忘言，政作口挂壁。", "因君强一語，習氣乃乘隙。", "昨夕飲君家，看朱忽成碧。", "醉歸城南路，不記足所歷。", "尚想兩紅粧，翠袖香襞積。", "我歌君爲舞，舉手還恨窄。", "詩成漫不省，歎我真惡客。", "賸肯來看山，未厭一水隔。"]'),
('15e1f127-018d-4223-aa1e-7506c212f851','次韵子雲送兒女至昭亭見寄','韓元吉','宋','宋诗','song-poetry','','[]','巖巖昭亭山，度歲一再行。',240,'全唐诗/poet.song.124000.json','["巖巖昭亭山，度歲一再行。", "吾親在其下，有路如砥平。", "風物歲時佳，豈問楚與荆。", "胡爲不得往，使我涕泗橫。", "出身備王官，敢自頹家聲。", "聖皇察庶獄，小大必以情。", "哀矜且勿喜，死當使之生。", "念昔棲閩陬，孤童共營營。", "菽水曾幾何，青紫望一經。", "弟兄亦云幸，假節仍專城。", "別離乃頻有，僕奴費邀迎。", "安仁賦閒居，要自賢西征。", "板輿日歡侍，兒女森在庭。", "豈比隔山岳，空書問安寧。", "薄田可負郭，不歸定誰令。", "壯士志中原，邊塵暗幽并。", "擬躡冒頓居，端謀渭南耕。", "書生復何事，三入老承明。", "應知當饋歎，廊廟資扶傾。", "忍作寒蟬喑，願爲威鳳鳴。"]'),
('5e8d260b-8dee-492c-9fd4-da3fcfe7c0e3','次韵子雲種竹','韓元吉','宋','宋诗','song-poetry','','[]','官居地多隙，種竹及春早。',192,'全唐诗/poet.song.124000.json','["官居地多隙，種竹及春早。", "蕭然三畝園，便可事幽討。", "層巒寓巖石，一目惜盡了。", "移根互掩映，取徑作深杳。", "飛來幾烏鵲，相喚亦栖繞。", "微風與新月，屢舞欣嫋嫋。", "乃知亭館閒，有竹自能好。", "堂前藝梅花，堂後列萱草。", "叩門有俗客，未至跡已掃。", "遥憐敬亭下，巷僻客仍少。", "庭隅方解籜，相對亦社保。", "吟哦五字句，飲水良不飽。", "春雷發頭角，繭栗未應小。", "卜居如有得，破地出池沼。", "胸中千畝計，豈顧萬事擾。", "他年醉林間，準擬成二老。"]'),
('f88d10e6-1624-4c5f-a9ce-196ef54c5061','連日得雜花數株藝之池亭感而有作','韓元吉','宋','宋诗','song-poetry','','[]','七十已過半，所向意不如。',168,'全唐诗/poet.song.124000.json','["七十已過半，所向意不如。", "一官計大州，僕僕畏簡書。", "酒薄不可醉，歌舞見已疏。", "亦有淡生活，詩成自相紓。", "池面數尺地，荆棘試翦除。", "爲覓桃李花，養根待春初。", "日暮公事已，呼童細耘鋤。", "稍稍浄朽壤，依依列荒墟。", "歲月能幾何，坐見紅綺舒。", "更須土脈動，藝柳分芙蕖。", "賞心固難事，寓目良有餘。", "即此且痛飲，三年冀安居。", "勿言傳舍耳，吾生亦蘧廬。", "苟無名利著，朝市均樵漁。"]'),
('907b19d1-bdab-4475-bb41-1cbf6edbc0b6','對梅','韓元吉','宋','宋诗','song-poetry','','[]','吏事紛俗語，新詩固難成。',120,'全唐诗/poet.song.124000.json','["吏事紛俗語，新詩固難成。", "朝來見梅花，詩興還自生。", "江頭十日雨，雲色開小晴。", "高山带微雪，北客眼爲明。", "應憐此花開，與雪猶爭衡。", "天公翦六出，未敵枝上英。", "蕭然北窗下，冰壺看斜橫。", "坐想南山中，晚風千樹清。", "平生一尊酒，肯爲桃李傾。", "幽香莫零落，送我扁舟行。"]'),
('211af351-fa5b-4166-9306-83eaa727a4a7','食田螺','韓元吉','宋','宋诗','song-poetry','','[]','幾年客勾吳，盤饌索無有。',264,'全唐诗/poet.song.124000.json','["幾年客勾吳，盤饌索無有。", "鯹鹹咀彭蜞，臭腐羹石首。", "牛心與熊掌，夢寐不到口。", "朅來靈山下，空腸尚雷吼。", "苜蓿映朝餐，杞菊富肴簌。", "相過有賢士，無以侑巵酒。", "跰𨇤樽俎間，見此青裙婦。", "百金買市城，競拾不論斗。", "枵中本離化，黝質真坤耦。", "稍稍被寒泉，纍纍付清滫。", "舒觴頗甘豢，窒戶還畏剖。", "芼薑摘其元，璀璨置瓦缶。", "中年消渴病，快若塵赴帚。", "含漿與文蛤，未易較先後。", "吾生亦何爲，甘此味豈厚。", "醢之自周官，況我乃田叟。", "尚殊鼠供蘇，復類蟆餉柳。", "北風飫竹實，南俗夸針取。", "雖非綠紋酌，僅免青泥嘔。", "據龜定應用，噉鰒良可醜。", "誰能事顔色，此腹嗟敢負。", "詩成調兒曹，吾意真亦偶。"]'),
('e254c813-5847-4f34-9017-5ebf2d0b6e9a','雲洞','韓元吉','宋','宋诗','song-poetry','','[]','揮策度絕壑，撐空見樓臺。',120,'全唐诗/poet.song.124000.json','["揮策度絕壑，撐空見樓臺。", "丹崖幾千仞，中有佛寺開。", "老僧如遠公，譍門走蒿萊。", "下馬問所適，褰衣指崔嵬。", "飛闌倚石磴，曠蕩無纖埃。", "坐久意頗愜，爽氣生樽罍。", "仙棺是何人，蛻骨藏莓苔。", "舉酒一酌之，慨然興我懷。", "丹砂固未就，白鶴何時來。", "不如生前樂，長嘯且銜盃。"]'),
('eb8692c1-a8b2-4baa-9049-cbf1a61496d5','跋北齊校書圖','韓元吉','宋','宋诗','song-poetry','','[]','高齊校讎誰作圖，一時紬書亦名儒。',195,'全唐诗/poet.song.124000.json','["高齊校讎誰作圖，一時紬書亦名儒。", "網羅卷軸三千餘，俗儒非真類迂愚。", "雌黄是正定不無，虛文末學徒區區。", "豈識治道通唐虞，文林高館希石渠。", "後來御覽嗟何書，修文偃武事益誣。", "轉頭鄴城已丘墟，峨冠廣袖長眉鬚。", "丹書寫此猶不渝，高鬟侍女曳紅裾。", "兩騅帕鞍立奚奴，罷琴涉筆傾酒壺。", "蘭臺供擬信樂歟，不知畫手安用摹。", "無乃逞巧聊自娛，千年視之一欷歔。", "君不見文皇學士十八人，謀猷事業皆功臣。", "瀛洲舊圖應更真，諸君尋觀爲拂塵。"]'),
('bfd7f678-fbd6-456a-8689-809c713a3c54','陸務觀寄著色山水屏','韓元吉','宋','宋诗','song-poetry','','[]','我居面山俯潺湲，憑軒卧牖皆見山。',262,'全唐诗/poet.song.124000.json','["我居面山俯潺湲，憑軒卧牖皆見山。", "山光水影入懷袖，秀色爽氣非人寰。", "故人憐我新結屋，猶恐看山未能足。", "丹青寫作何許圖，不礙閉門聊縱目。", "千峰繚繞生白雲，小舟蕩漾橫江濱。", "樓臺高下出蘭若，杳渺似有鐘磬聞。", "坐驚巖壑環四壁，寥落高秋變春色。", "方壺瀛洲遠不隔，武陵桃花定誰識。", "君不見韋侯絕筆畫古松，黑雨白日摧虬龍。", "杜陵老翁三歎息，況有山木洪濤風。", "又不見玉堂真仙草詔罷，靜愛春山郭熙畫。", "文章信美身不閒，青嶂白波眼中借。", "我今乘間身未衰，杖藜獨步哦新詩。", "出門見山入見畫，佳興自喜來無時。", "卧龍山腰鏡湖尾，知有高齋照清泚。", "功名逼子未得休，歸坐玉堂應記此。"]'),
('0b45fdce-14d5-41cd-b29c-bcea6edca53b','檢詳出示所賦陳季陵戶部巫山圖詩仰窺高作歎息彌襟范成大嘗考宋玉談朝雲事漫稱先王時本無據依及襄夢之命玉爲賦但云頩薄怒以自持曾不可乎犯干後世弗察一切溷以媟語曹子建賦宓妃亦感此而作此嘲誰當解者輒用此意次韵和呈以資拊掌','韓元吉','宋','宋诗','song-poetry','','[]','瑶姬家山高插天，碧叢奇秀古未傳。',195,'全唐诗/poet.song.124000.json','["瑶姬家山高插天，碧叢奇秀古未傳。", "向來題目經楚客，名字徑度岷峨前。", "是耶非耶莽誰識，喬林石廟常秋色。", "暮去行雨朝行雲，翠帷瑶席知何人。", "峽船一息且千里，五兩竿頭見幡尾。", "仰窺仙館至今疑，行人問訊居人指。", "千年遺恨何時伸，陽臺愁絕如荒村。", "高唐賦裏人如畫，玉色頩顔元不嫁。", "後來饑客眼長寒，浪傳樂府吹復彈。", "此事牽連到溫洛，更憐塵襪有無間。", "君不見天孫住在銀河滸，塵間猶作兒女語。", "公家春風錦瑟傍，莫爲此圖虛斷腸。"]'),
('47eb02fc-8886-4122-902a-f87ee4417e69','題陳季陵家巫山圖一首','韓元吉','宋','宋诗','song-poetry','','[]','蓬萊水弱波連天，五城十二樓空傳。',192,'全唐诗/poet.song.124000.json','["蓬萊水弱波連天，五城十二樓空傳。", "行人欲至風引船，不知路出巫山前。", "巫山仙子世莫識，十二高峰作顔色。", "暮去朝來雨復雲，却將幽恨感行人。", "江流東下幾千里，日日饑鴉噪船尾。", "靈帳風生酹酒漿，古廟煙青客遥指。", "崧高漫說甫與申，道旁況有昭君村。", "蛾眉妙手不能畫，枉學瑶姬夢中嫁。", "黄牛白馬江聲寒，昭君傳入琵琶彈。", "漢庭無人楚宮遠，陽臺寂寞空雲間。", "君家此畫來何許，照水煙鬟欲相語。", "要須媠服令侍旁，不用作賦迴枯腸。"]'),
('a48ff957-90b7-4785-b9f5-d4bcbfdcb4eb','鄭仲南五梅圖','韓元吉','宋','宋诗','song-poetry','','[]','江南酒美樽不空，十年醉倒梅花中。',192,'全唐诗/poet.song.124000.json','["江南酒美樽不空，十年醉倒梅花中。", "經行所見略可譜，一一秀骨含仙風。", "不將鉛華污真色，亦有醉臉勻春紅。", "重英千葉兩何好，玉立但喜肌微豐。", "紅綃金縷變新樣，品異獨許天香同。", "花開到處即吾圃，水寒月淡煙空濛。", "醉來踏雪更起舞，長歌目送南飛鴻。", "自後春歸厭寂寞，坐覺桃李難爲容。", "忽驚橫軸入吾手，世上猶有丹青工。", "扶疏清影卧空碧，一笑似喜曾相逢。", "君家亭館安用此，此物自昔添詩窮。", "詩成妙手儻不惜，畫我曳杖穿芳叢。"]'),
('ee1b0629-cb19-4767-bbfd-5d1a8dfd839d','龜峰行','韓元吉','宋','宋诗','song-poetry','','["\u8861\u5c71"]','吾聞靈龜不願死有用于清廟，但願曳尾安泥塗。',414,'全唐诗/poet.song.124000.json','["吾聞靈龜不願死有用于清廟，但願曳尾安泥塗。", "所以漆園吏，坐歎清江使者逢豫且。", "龜峰之龜定何物，不在泥塗之下，乃在萬仞之上高突兀。", "是耶非耶遠莫測，安然不動藏其穴。", "伊昔帝堯有聖德，此龜無乃負圖出。", "圖成授帝埋其骨，猶使琢石志之存彷彿。", "又疑神禹碑，刊在衡山巔。", "碑高上與日月並。", "此猶其趺棄不取，神鬼守護踰千年。", "我欲詰其端，此事恍惚無迹，往往皆在太古前。", "斗中神人被髮立，蜿蜒佐之從汝蟄。", "九陰司存當在此，今汝巢南失其職。", "又聞巢縣事，頗似伊尹生空桑。", "母嫗避水欲徙去，待汝兩眼生赤光。", "遂令萬室之邑化作魚與鱉，汝乃遁走至此藏。", "上天震威趣汝壽，使汝扶服死且僵。", "醜形質磔在石筍上，不可以鑽，不可以灼，不可以搘牀。", "奈何猶復不自斂，荒崖斷壑反以名字彰。", "因思支祁鎖頸泗水中，帝以巨鎮岌峨壓其宮。", "名之以山不以峰，豈有形狀與此同。", "吁嗟此山氣象槃礴亦雄偉，奇峰羅列三十二。", "或如威鳳昂其喙，或如俊貓立且戲。", "石鍾孤撐危欲墜，蜃樓矗起見天外。", "大眺么麽不足記，神旗鐵壁非一類。"]'),
('15c356f4-abdc-4168-8ff9-c3416ea51d49','永豐行','韓元吉','宋','宋诗','song-poetry','','[]','丹陽湖中好風色，晴日波光漾南北。',288,'全唐诗/poet.song.124000.json','["丹陽湖中好風色，晴日波光漾南北。", "湖岸人家榆柳行，風颭低昂似迎客。", "繫船並岸聊一呼，老農指是官田圩。", "長衫紫領數百輩，見我羅拜長嗟吁。", "政和回頭五十載，官長築圩宛然在。", "東西相望五百圩，有利由來得無害。", "官圩民圩奚所拘，此地無田但有湖。", "圍湖作田事應爾，底用徹地還龜魚。", "民圩不堅自招水，水潦何常鎮如此。", "官圩六十里如城，削平爲湖定何理。", "請看今來禾上場，七百頃地雲堆黄。", "縣官糴米三萬斛，度僧給牒能商量。", "我聞此語汗生面，千聞豈如目一見。", "吾君神聖坐九重，輕易獻言誰復辨。", "却憶吳中初夏時，畚鍤去决湖田圍。", "雞驚上籬犬上屋，水至不得携妻兒。", "無田赴水均一死，善政養民那得爾。", "寄言父老且深耕，爲汝馳書報天子。"]'),
('eff2cedf-12f5-4212-83e1-e1112e4f7085','建德道中','韓元吉','宋','宋诗','song-poetry','','[]','風雨回頭已十日，野花狼籍春可惜。',64,'全唐诗/poet.song.124000.json','["風雨回頭已十日，野花狼籍春可惜。", "水深泥滑行路難，但見千山好顔色。", "青青稻畦初布秧，人家掩扇蠶事忙。", "駕言有程不可駐，鶗鴂一聲歸夢長。"]'),
('e36ba962-1235-472e-8e2d-da46c8219d1d','桐柏觀三井龍潭下爲瀑布','韓元吉','宋','宋诗','song-poetry','','[]','一水赴壑如奔雷，兩山壁立堅誰開。',160,'全唐诗/poet.song.124000.json','["一水赴壑如奔雷，兩山壁立堅誰開。", "山高石限水不去，萬古鬭怒何轟豗。", "盤渦散作鍾與釜，往往石上相縈迴。", "泓渟歲久深莫測，人言海眼良可猜。", "不知蛟龍底無用，局促石竇真窮哉。", "未能九土霈一雨，尚與千里清炎埃。", "往時金虯墜玉簡，中使奉詔從天來。", "百年舊事今寂寞，但有雪浪飛崔嵬。", "杜鵑花開蘭正發，雙闕萬丈晴雲堆。", "寒聲徹耳心骨爽，凌風一上吹笙臺。"]'),
('37350810-e4ba-44f8-bf20-2ef49b7f29f0','玩鞭亭','韓元吉','宋','宋诗','song-poetry','','[]','黄鬚鮮卑勇無策，自馳駿馬來窺賊。',128,'全唐诗/poet.song.124000.json','["黄鬚鮮卑勇無策，自馳駿馬來窺賊。", "賊奴但怪日繞營，起看飛塵已無跡。", "寶鞭不惜棄道傍，坐令老嫗知興亡。", "百年社稷有天意，奸鋒逆焰徒鴟張。", "孤城遺跡森在目，平湖無波春草綠。", "却對青山憶謝公，公老猶嫌人姓木。", "邊兵已重朝士輕，中原有路何由行。", "柙中虎兕不可制，江左夷吾浪得名。"]'),
('d8bcf1a6-a466-4e60-911a-e7d2455de378','魯公堂','韓元吉','宋','宋诗','song-poetry','','[]','魯公之節非一死，其誰碑之子曾子。',128,'全唐诗/poet.song.124000.json','["魯公之節非一死，其誰碑之子曾子。", "魯公之德人未知，其誰堂之張紫微。", "繼公作郡五百載，登堂思公宛如在。", "江南遺墨處處傳，魯公去作麻姑仙。", "一杯相與借風月，但見雲碧開池蓮。", "紫微聲名今第一，歸上鸞臺應不日。", "笑談千里無兵戎，臨川草木生春風。", "他年道傍兒女說，不思魯公思張公。"]'),
('9615ebf9-885c-4529-a31a-bb2be5a96cb8','歸耕堂','韓元吉','宋','宋诗','song-poetry','','[]','退之手板愧丞相，淵明束带羞督郵。',160,'全唐诗/poet.song.124000.json','["退之手板愧丞相，淵明束带羞督郵。", "紛紛雀鼠待一飽，豈若植杖耘西疇。", "劉郎大耳最叵信，剛道田園不可求。", "摩挲髀肉事鞍馬，堅卧百尺營高樓。", "安知南陽扶耒手，談笑爲君分九州。", "我來龜溪二三載，此策未辦誠淹留。", "喜君負郭有餘地，百金賣劍歸換牛。", "樹頭布穀曉相應，築室坐占林塘幽。", "詩成使我佳興動，叩角便作商聲謳。", "他年釜甑得長滿，區區肯顧監河侯。"]'),
('0365a320-f707-4a99-a716-c5aeca83199d','李編修器之惠詩卷','韓元吉','宋','宋诗','song-poetry','','[]','塵埃僕僕日走趨，胸中倒懸一字無。',160,'全唐诗/poet.song.124000.json','["塵埃僕僕日走趨，胸中倒懸一字無。", "迫人簿領推不去，眼明忽見千驪珠。", "矍然驚呼此詩歟，如醒乍解病獲蘇。", "歸來明燈喜無寐，手不忍釋自卷舒。", "語新格健意有餘，風骨峭硬中含腴。", "猛如橫陣舞刀槊，清若雅宴調笙竽。", "我窮已極君益迂，學此似費千金屠。", "前有太白後長吉，君家詩名宜復初。", "明明天子開石渠，歎我短後追長裾。", "時平合第從臣頌，請君早上承明廬。"]'),
('19f17b94-31c9-41c7-9e33-4f4b15413cd1','少稷勸飲每作色明遠忽拂袖去戲呈','韓元吉','宋','宋诗','song-poetry','','[]','無多酌我蓋司隸，不能滿觴田將軍。',96,'全唐诗/poet.song.124000.json','["無多酌我蓋司隸，不能滿觴田將軍。", "坐中幸免沐猴舞，且復周旋非貴人。", "人言勸飲無惡意，君胡作惡使客起。", "少陵亦遭田父肘，況我忘形友君子。", "從今勿勸亦勿辭，我欲眠時君自歸。", "先生一斗一石醉，莫問喧爭與嘲戲。"]'),
('c66c91aa-36be-41ac-820c-8e2a3716b8d9','戲韓子師','韓元吉','宋','宋诗','song-poetry','','[]','讀書堂前霜月明，讀書堂後霜風聲。',160,'全唐诗/poet.song.124000.json','["讀書堂前霜月明，讀書堂後霜風聲。", "主人讀書已萬卷，足踏省戶還專城。", "朅來掩關卧不出，左擁韋編右瑶瑟。", "似聞天女亦愛靜，便喜蘭房長英物。", "我舍應門纔一兒，趙子尤作仙果遲。", "白頭相看輒浩歎，玉樹獨滿君家墀。", "我歌聲長君且聽，不特交遊幸同姓。", "極知玉盎有新醅，每恨金觴乃無柄。", "從君泥飲不作難，景物過清天復寒。", "犀錢湯餠未免俗，琵琶與箏當合彈。"]'),
('28ed9388-ed6e-41f3-8880-79b843aa4517','戲贈范元卿','韓元吉','宋','宋诗','song-poetry','','[]','憶昔苕溪醉中語，屈指淒涼十寒暑。',192,'全唐诗/poet.song.124000.json','["憶昔苕溪醉中語，屈指淒涼十寒暑。", "紛紜世事去如雲，兩鬢蒼蒼各如許。", "春風學省數會面，抗袂吁嗟走塵土。", "我慚屢戰不能奇，袖手歸來仆旗鼓。", "喜君射策有新功，雙鵠聯翩仍一舉。", "胡爲不上金馬門，簿領卑棲猶噲伍。", "風前未厭鷫鸘敝，筆下懸玄鳳凰吐。", "閩山千里要佳句，應弔雙龍一懷古。", "元戎好士見此客，定肅弓刀按歌舞。", "素英丹荔雖已過，海珍正可羅樽俎。", "鷓鴣勾舟木葉墮，秋晚上寒更風雨。", "請君彊飯趣歸程，莫爲梅花思羈旅。"]'),
('f61d25ee-2336-45e1-a3f3-3ceb44be881e','次韵沈信臣遊龍焙','韓元吉','宋','宋诗','song-poetry','','[]','武夷仙人厭塵埃，金鞭白馬飛崔嵬。',192,'全唐诗/poet.song.124000.json','["武夷仙人厭塵埃，金鞭白馬飛崔嵬。", "丹砂已就不可識，尚有瑶草分靈栽。", "千花剪巧綴密露，秀色不待春風催。", "東溪路入三千里，山如舞鳳連翩來。", "槍旗未動供採掇，壘鼓夜作空山雷。", "蒼虬繞圭龍護璧，面爲鐵石口瓊瑰。", "烹煎鬭水出好事，珠瓔玉字相縈迴。", "已嗟雙井甘退步，况復日注真難儕。", "我來竊食端爲此，把玩一日三徘徊。", "手𣂏清泉弔陸子，底用濁酒窮歡咍。", "頭風快愈春睡散，老眼尚爲羣書開。", "知君此遊更不惡，坐有纖纖時捧杯。"]'),
('be6518b5-5b5d-4f72-8ab0-20bd1cdeb774','重九日中甫子雲二兄會別龍山','韓元吉','宋','宋诗','song-poetry','','[]','秋風作霜楓葉丹，扁舟未發龍山灣。',224,'全唐诗/poet.song.124000.json','["秋風作霜楓葉丹，扁舟未發龍山灣。", "山頭窣堵半天出，十年笑我幾往還。", "今年結束值重九，愛此山水照高寒。", "親朋話別情總厚，兄弟白首仍蒼顔。", "相留一笑不易得，爭挈美酒羅盤餐。", "登高正爾在高許，下視擾擾真塵寰。", "追思姑孰有故事，雅宴亦復同此山。", "雖云小異得佳客，主人鬚蝟懷胸奸。", "滄波至今洗遺恨，豈若我輩同清歡。", "是時郊原新雨足，歷歷煙樹明江干。", "放懷自知人境異，極目頓覺天宇寬。", "惜無五絃寄妙手，已有征雁橫雲端。", "南飛休論九萬里，東游更渡五百灘。", "明宵酒醒會相憶，夢繞百級憑飛欄。"]'),
('29fc3515-e48d-4f69-9f5c-7dab6ef74abc','送朱元晦','韓元吉','宋','宋诗','song-poetry','','[]','前年恨君不肯來，今年惜君不肯住。',160,'全唐诗/poet.song.124000.json','["前年恨君不肯來，今年惜君不肯住。", "朝廷多事四十年，愚智由來各千慮。", "君來正值求言日，三策直前真諫疏。", "詆訶百事推聖學，請復國讎施一怒。", "天高聽遠語不酬，袖手翩然尋故步。", "我知君是諫諍才，主上聰明得無悞。", "一紙底用教鶡冠，百戰應當啟戎輅。", "江山千里正風雪，歲月崢嶸倏將暮。", "有田可耕屋蓋頭，君計未疏吾亦去。", "君歸爲謝武夷君，白馬摇鞭定何處。"]'),
('6da1e538-4858-434f-b54c-312b5858417d','送許侍郎知宣州','韓元吉','宋','宋诗','song-poetry','','[]','我公名滿東西川，一持使節幾十年。',208,'全唐诗/poet.song.124000.json','["我公名滿東西川，一持使節幾十年。", "橋經萬里坂九折，兒童學語知公賢。", "上皇詔下嗟見晚，歸來荷橐趨甘泉。", "平生所學欲盡試，新語僅奏囊中篇。", "兩淮破碎頼整理，百工蠱敝資鑱鎸。", "念公雖老猷自壯，何謂宜去請益堅。", "玉音三諭不可挽，一麾且復臨江壖。", "宣城景物今更妍，木瓜如瓠栗如拳。", "敬亭山下躡遊屐，疊嶂樓中呼酒船。", "謝公已往詩句在，公有妙語真齊肩。", "却招李白弔杜牧，收攬風月酬雲煙。", "中原未復敵未滅，政成請公須著鞭。", "吾君有意詢黄髮，廟堂之謀當萬全。"]'),
('405d8e52-4ee5-4d3f-9a1c-f2d9d7491039','送蘇季真赴湖北憲司屬官','韓元吉','宋','宋诗','song-poetry','','["\u8861\u5c71", "\u6d1e\u5ead\u6e56"]','憶昔聞君未相識，春雨繫船吳市側。',160,'全唐诗/poet.song.124000.json','["憶昔聞君未相識，春雨繫船吳市側。", "逆風白浪不成行，坐聽親朋談歷歷。", "豈意飄零晚相見，俱捧江東從事檄。", "拙鳩未省厭榆枌，威鳳誰令安枳棘。", "今年喜君若有遇，去我還爲遠行役。", "一樽忍話故園事，童穉吁嗟髮今白。", "君家聲名塞宇宙，翰墨縱橫富奇策。", "未容世職踐明光，聊佐輶車司郡國。", "衡山洞庭忽在眼，禹牒黄車有遺跡。", "詩成不用弔靈均，爲訪桃花招隠客。"]'),
('f23f3f42-0d72-43a6-81dd-804f3f3929e4','偶得佳酒懷尹少稷聞其連日致齋在臺作長句寄之','韓元吉','宋','宋诗','song-poetry','','[]','孔君一月二十九日醉，太常一年三百五十九日齋。',334,'全唐诗/poet.song.124000.json','["孔君一月二十九日醉，太常一年三百五十九日齋。", "人生百歲駒過隙，直與外物勞形骸。", "君非太常何用爾，監祭有令時當差。", "朝廷禮備百神秩，不比媚奧猶燔柴。", "念君幾日得閒暇，歸胙饜飫妻奴哇。", "重門咫尺不得見，使我有酒空相懷。", "憶昔過從水南寺，風廊雪屋靡不偕。", "靈山懷玉了在眼，蒼翠突兀石筍鐵柱如籤排。", "醉來起舞對山水，狂歌亦和襄陽𥱼。", "一時取樂未云足，後會回首何其乖。", "今者相逢號朝士，僕僕聽鼓趨天街。", "欲觀禮樂問文物，但見鼙鼓鳴江淮。", "喜君頭上冠作廌，文筆愈健詩愈佳。", "青雲萬里要直氣，幸勿觸狐當觸豺。", "我今勃窣百僚後，自覺迂鈍難爲儕。", "一杯耳熱不共醉，夜長獨坐燒寒稭。", "隔牆降將新授節，絲竹間響駢金釵。", "時逢富貴雖可羨，擾擾得失真蠅蝸。", "江山到處有佳趣，故應赤舄輸青鞵。", "明年春風我欲賦歸去，佇君功成作頌磨蒼崖。"]'),
('84c524c8-edfb-42f8-9ab8-da9b35b36af4','方務德元夕不張燈留飲賞梅務觀索賦古風','韓元吉','宋','宋诗','song-poetry','','[]','昨日風雨今日晴，綠水橋南春水生。',224,'全唐诗/poet.song.124000.json','["昨日風雨今日晴，綠水橋南春水生。", "使君元夕罷高宴，亭午邀客花間行。", "危亭直上花幾許，水仙夾徑梅縱橫。", "不須沈水薰畫戟，簾幕自有香風清。", "門前紛紛鳥鵠亂，隠几坐愛寒江明。", "憶昨淮南戎馬動，豈謂景物還新正。", "遺民歸公十萬口，鼙鼓日日嚴刀兵。", "眼看指麾盡摩撫，閭里愁歎成歡聲。", "酬功端合侍玉輦，安得坐嘯江干城。", "景龍燈火公尚記，耆舊出語兒童驚。", "我來兩月濫賓客，況有別駕能詩名。", "相從一笑說萬事，重費美酒勤杯觥。", "東風摇蕩入煙柳，歌管錯雜催離情。", "詔書徵拜那可後，爲公前馬遥相迎。"]'),
('be0da253-5a0b-4a5c-997e-40b1e54c0d9c','次韵少稷梅花','韓元吉','宋','宋诗','song-poetry','','[]','君不見江城梅花春欲動，剪冰仙人作花供。',179,'全唐诗/poet.song.124000.json','["君不見江城梅花春欲動，剪冰仙人作花供。", "客來酒盡甘啜醨，常恨公田無秫種。", "雪晴梅蘂更可愛，百匝來看地猶凍。", "杖藜一笑答春風，豈必鳴鸞與歌鳳。", "幽香要自己心清，冷艷不禁還目送。", "興來往往得佳句，落紙揮毫字尤縱。", "却驚車陣有勍敵，旋結趙叟盟衡雍。", "孤芳未省須刻畫，百卉應先厭嘲弄。", "我如蟋蟀鳴苦遲，君似驊騮驟難控。", "相如上林晚奏雅，靈均喜橘工記諷。", "不妨聊繼廣平公，東閣疏枝與君共。"]'),
('56fda5ba-efb3-4cdb-8635-31ad8a86d418','土人池中有新荷戴錢而出者少稷明遠相率賦詩戲作長句','韓元吉','宋','宋诗','song-poetry','','[]','君不見紫髯將軍射無敵，志目中眉猶動色。',163,'全唐诗/poet.song.124000.json','["君不見紫髯將軍射無敵，志目中眉猶動色。", "晚年驚見賣油翁，一綫穿錢曾不失。", "人言手熟會當爾，世事由來真一劇。", "紛紛刻楮技已窮，厭看人力須天工。", "湘妃撫掌漢女笑，爲我試手馮夷宮。", "芙渠生葉不自展，胡爲正在阿堵中。", "青銅翠羽光相映，莫遣游魚動荷柄。", "芳心滿眼誰得知，坐使詩人發嘲詠。", "我言羞澀囊久空，井中飛蚨那得逢。", "不如青鴨爲銜去，賸買明月酬清風。"]'),
('80836764-9cf0-44fa-96b4-4ff08c651f48','觀蓮','韓元吉','宋','宋诗','song-poetry','','[]','廣寒仙子衣作裳，夜從宓妃款英皇。',144,'全唐诗/poet.song.124000.json','["廣寒仙子衣作裳，夜從宓妃款英皇。", "朝游洛浦暮瀟湘，紅粧翠羽森成行。", "仙姿不作時世妝，或凝朝霞豔秋霜。", "臨流顧影濯滄浪，游魚屬玉雙鴛鴦。", "長庚北斗相低昂，笑中如花語如香。", "徘徊醉著清漏長，炯然開奩照湖光。", "湖風吹水洒面凉，明珠落佩千鳴璫。", "碧筩宛宛中可觴，爲君行歌酌天漿。", "瑶池玉井遥相望，歸舟浮空月茫茫。"]'),
('e5afb6cc-4579-414c-af3f-142140d50e72','同尹少稷賦巖桂','韓元吉','宋','宋诗','song-poetry','','[]','江南秋盡猶無菊，只有幽香滿巖谷。',128,'全唐诗/poet.song.124000.json','["江南秋盡猶無菊，只有幽香滿巖谷。", "紛紛千樹散黄金，翠葉離披剪寒玉。", "繁枝疑從缺月墮，嫩葉不受微風觸。", "芳枝冷淡誰與妍，霧雨陰晴自膏沐。", "不妨松竹共行伍，要使芝蘭盡臣僕。", "小山有句嗟未盡，騷經已斷誰能續。", "每至凋零足惆悵，尚喜爐薰駐餘馥。", "爲君掃地斗量歸，猶勝胡椒夸百斛。"]'),
('9333b6a5-000b-4261-9cbc-6830d102f236','隆興甲申歲閏月游焦山','韓元吉','宋','宋诗','song-poetry','','[]','荒村日晴雪猶積，繫纜焦公山下石。',128,'全唐诗/poet.song.124000.json','["荒村日晴雪猶積，繫纜焦公山下石。", "江翻斷崖石破碎，瘞鶴千年有遺跡。", "瘦藤百級躋上方，浮玉南北江中央。", "檣竿如林出煙浦，酒船遠與帆低昂。", "老鴟盤風舞江面，殺氣淮南望中見。", "神龍只合水底眠，爲洗乾坤起雷電。", "觀音巖前竹十尋，大士不死知此心。", "醉歸更喚殷七七，賸種好花開鶴林。"]'),
('a7f31293-0fed-4b3f-a4a3-3468cfa828e4','南劍道中','韓元吉','宋','宋诗','song-poetry','','[]','喚渡春潭側，堤彎踏曉晴。',48,'全唐诗/poet.song.124000.json','["喚渡春潭側，堤彎踏曉晴。", "回舟動山影，映日見魚行。", "墅遠孤烟出，江深白鷺明。", "塵勞消底計，對此覺身輕。"]'),
('8768fe9c-e0f2-4bf2-b3c5-0c1c93d9c285','步月','韓元吉','宋','宋诗','song-poetry','','[]','山靜水逾響，我行清夜中。',48,'全唐诗/poet.song.124000.json','["山靜水逾響，我行清夜中。", "月華霜著地，雲影浪摇空。", "有酒不惜醉，無人誰與同。", "嫦娥搗仙藥，應厭廣寒宮。"]'),
('657a6c00-3234-4702-9528-37b01bab74ff','端午日張園分題','韓元吉','宋','宋诗','song-poetry','','[]','輦路逢端午，今年始賜休。',48,'全唐诗/poet.song.124000.json','["輦路逢端午，今年始賜休。", "不知人世暑，還有水軒秋。", "花氣晴薰坐，湖光晚逼舟。", "明朝又奔走，賸作片時留。"]'),
('f46ba31a-ea83-4382-978b-5696a4bcae39','秋日雜詠六首  其一','韓元吉','宋','宋诗','song-poetry','','[]','客少無塵語，官閒省吏文。',48,'全唐诗/poet.song.124000.json','["客少無塵語，官閒省吏文。", "醉眠千嶂日，危坐一窗雲。", "酒戶時通籍，詩壇漸策勳。", "平生不龜手，郢客渾揮斤。"]'),
('483e85bb-aa47-4302-8e8c-f95787c4d2bb','秋日雜詠六首  其二','韓元吉','宋','宋诗','song-poetry','','[]','草草重陽節，黄花惜未開。',48,'全唐诗/poet.song.124000.json','["草草重陽節，黄花惜未開。", "故人猶有酒，行客且銜盃。", "日落蛩聲苦，雲低雁影來。", "南山足佳氣，獨立意徘徊。"]'),
('5dce6069-fb17-416e-9815-c7514650564d','秋日雜詠六首  其三','韓元吉','宋','宋诗','song-poetry','','[]','醉著山堂夢，初凉枕簟清。',48,'全唐诗/poet.song.124000.json','["醉著山堂夢，初凉枕簟清。", "秋聲迷夜雨，月色誤天明。", "爲客心長慣，思親意未平。", "歲華容易晚，寂寞壯心驚。"]'),
('fb0eee64-cb92-4fe4-8668-1b54295b1bcb','秋日雜詠六首  其四','韓元吉','宋','宋诗','song-poetry','','[]','古郡青山合，乘高眼倍寬。',48,'全唐诗/poet.song.124000.json','["古郡青山合，乘高眼倍寬。", "風驚梧葉陣，雨暗菊花團。", "凉色宜欹枕，秋光怯凭欄。", "向來疏懶意，景物暫相歡。"]'),
('ff31a5ff-509b-4656-843b-461ba1467355','秋日雜詠六首  其五','韓元吉','宋','宋诗','song-poetry','','[]','怪底西風別，秋香一夜繁。',48,'全唐诗/poet.song.124000.json','["怪底西風別，秋香一夜繁。", "攢金差可擬，揉蠟巧能摶。", "買地宜多種，移牀且細看。", "江南籬菊晚，頼爾慰愁端。"]'),
('c14f0203-569b-463c-9a37-73452954eb34','秋日雜詠六首  其六','韓元吉','宋','宋诗','song-poetry','','[]','絕壁跨城樓，連天海氣浮。',48,'全唐诗/poet.song.124000.json','["絕壁跨城樓，連天海氣浮。", "長空去鳥盡，落日斷雲留。", "鼓角深秋壯，山河薄暮愁。", "勞生知底所，倚杖寄滄洲。"]'),
('b056d75d-e849-4b62-a6ca-77ed4c208f43','聽雨','韓元吉','宋','宋诗','song-poetry','','[]','昨夜燈花暗，今晨雨意深。',48,'全唐诗/poet.song.124000.json','["昨夜燈花暗，今晨雨意深。", "殘花惟有葉，新笋已成林。", "未辦扶頭飲，聊爲擁鼻吟。", "興闌幽夢斷，簷際足清音。"]'),
('8d54de54-332b-4beb-aa44-74d9cb2fc62e','豐樂樓','韓元吉','宋','宋诗','song-poetry','','["\u897f\u6e56"]','今歲西湖上，經行始此迴。',48,'全唐诗/poet.song.124000.json','["今歲西湖上，經行始此迴。", "輕烟認花柳，細雨識樓臺。", "春半已多日，官閒能自來。", "情知欠樽酒，倚杖且徘徊。"]'),
('b26af405-d772-4295-a32d-5df23e95b33b','清明','韓元吉','宋','宋诗','song-poetry','','[]','老去驚時節，春來念物華。',48,'全唐诗/poet.song.124000.json','["老去驚時節，春來念物華。", "青烟百六日，同社兩三家。", "醉著凌風舸，歌成滿路花。", "滄江萬里意，獨立送殘霞。"]'),
('9650a5ee-4bc6-4465-9f69-0f06f0234bf2','閒居遣興','韓元吉','宋','宋诗','song-poetry','','[]','著雨柔桑暗，吹風小麥齊。',48,'全唐诗/poet.song.124000.json','["著雨柔桑暗，吹風小麥齊。", "江深涵日浄，野闊並雲低。", "車馬能相問，琴書故可携。", "村村花自好，不奈子規啼。"]'),
('3abb4feb-0c6b-4f1c-b712-85ddebab4511','道中遇停郊祀詔書','韓元吉','宋','宋诗','song-poetry','','[]','丹詔西來急，沿淮次第知。',48,'全唐诗/poet.song.124000.json','["丹詔西來急，沿淮次第知。", "應嗟饗帝日，却作視師期。", "士苦三年戍，人懷四郡悲。", "平戎可無策，帷幄定誰咨。"]'),
('603f5891-3159-4480-90de-83abe459c92a','建業書事','韓元吉','宋','宋诗','song-poetry','','[]','千載西州路，何人不此行。',48,'全唐诗/poet.song.124000.json','["千載西州路，何人不此行。", "山橫桃葉渡，江動石頭城。", "天闕雲端聳，秦淮雨後清。", "敢論風景異，舉目笑平生。"]'),
('127808a5-9d9d-4d81-8022-e01a9d69d6bd','過芙蓉對鏡嶺','韓元吉','宋','宋诗','song-poetry','','[]','世事日千變，勞生憂患多。',48,'全唐诗/poet.song.124000.json','["世事日千變，勞生憂患多。", "誰知度炎熱，正爾陟嵯峨。", "峰矗蓮初綻，崖枯鏡未磨。", "江東茲絕險，歎我兩經過。"]'),
('84c11874-222b-4aa6-8139-f11a7710ab05','慈雲嶺','韓元吉','宋','宋诗','song-poetry','','[]','極目慈雲路，看山立少時。',48,'全唐诗/poet.song.124000.json','["極目慈雲路，看山立少時。", "湖光經雨闊，柳色泥煙垂。", "琢石觀蹲獸，鎸崖讀斷碑。", "西關知底險，撫掌笑兒嬉。"]'),
('4cb3a351-e5eb-4c20-bf5f-369132f5a349','山行  其一','韓元吉','宋','宋诗','song-poetry','','[]','意適都忘遠，行歌未覺勞。',48,'全唐诗/poet.song.124000.json','["意適都忘遠，行歌未覺勞。", "崎嶇一徑入，上下數峰高。", "嫩白憐新菊，輕紅訝小桃。", "歸來情興動，風葉亂蕭騷。"]'),
('e8ec4f93-ebf1-40ea-bdec-2ecd7eb7f87a','山行  其二','韓元吉','宋','宋诗','song-poetry','','[]','秋盡暑猶劇，今朝凉意新。',48,'全唐诗/poet.song.124000.json','["秋盡暑猶劇，今朝凉意新。", "輕陰能障日，小雨不生塵。", "度壑時投策，看雲一岸巾。", "鄰僧問何往，茗果愧情親。"]'),
('564cb09f-3bf9-42fe-a2a8-6bfc39d97d70','登玉京洞遇雨','韓元吉','宋','宋诗','song-poetry','','[]','俗物祇散意，市朝那復情。',48,'全唐诗/poet.song.124000.json','["俗物祇散意，市朝那復情。", "未能蓬島去，且上玉京行。", "古洞深無底，幽泉細有聲。", "山靈知我意，賸乞片時晴。"]'),
('83c14214-62fc-4792-94cb-77ebd6dcdc9d','雨中同鄒德飯白雲菴  其一','韓元吉','宋','宋诗','song-poetry','','[]','小雨不成雪，凍雲猶沒山。',48,'全唐诗/poet.song.124000.json','["小雨不成雪，凍雲猶沒山。", "若無官事縛，聊傍野僧閒。", "濁酒間何闊，清遊阻且艱。", "相看成冷淡，得句不空還。"]'),
('e8b01fca-ff2d-48a5-9c57-74c73ae77005','雨中同鄒德飯白雲菴  其二','韓元吉','宋','宋诗','song-poetry','','[]','懶惰已成癖，幽尋湖上臺。',48,'全唐诗/poet.song.124000.json','["懶惰已成癖，幽尋湖上臺。", "應知千里近，動作半年來。", "一徑草仍碧，兩山梅未開。", "猶憐衝雨濕，路入亂雲堆。"]'),
('1a899093-fa82-4023-b664-f0e49773e6e0','龍華寺傅大士真身像','韓元吉','宋','宋诗','song-poetry','','[]','古寺郊丘側，鐘魚曉未喧。',48,'全唐诗/poet.song.124000.json','["古寺郊丘側，鐘魚曉未喧。", "雙林有遺骨，瑞萼記名園。", "粒石嗟餘飯，神槌想叩門。", "蠶桑猶有謁，鼓舞動山村。"]'),
('83c6ad74-8cbe-4294-bc29-32e909074d03','青陽龍池山潮泉其應有時禱于泉上坐頃三應山中人以爲未有也','韓元吉','宋','宋诗','song-poetry','','[]','八月錢塘岸，江潮晝殷雷。',48,'全唐诗/poet.song.124000.json','["八月錢塘岸，江潮晝殷雷。", "豈知驚浪涌，不轉此峰來。", "古竇深無際，神淵秘莫開。", "山靈如愛我，三送雪成堆。"]'),
('cd63f9fe-de4d-4977-bb99-9d7e8a39dbc0','寄題尹少稷借竹軒','韓元吉','宋','宋诗','song-poetry','','[]','借屋復借竹，主人貧可知。',48,'全唐诗/poet.song.124000.json','["借屋復借竹，主人貧可知。", "清風時引酒，長日最須棋。", "牆缺秋聲過，庭空月影隨。", "遥憐對高節，幽獨更題詩。"]'),
('b1130282-8901-4dd7-8760-d788f26abcab','龔敦頤芥隠詩','韓元吉','宋','宋诗','song-poetry','','[]','萬古須彌頂，嘗于芥子看。',48,'全唐诗/poet.song.124000.json','["萬古須彌頂，嘗于芥子看。", "憐君作書窟，喚客築詩壇。", "默識眼界浄，忘憂心地寬。", "老來同此味，廣厦任高寒。"]'),
('2619908f-25ec-46b7-a89e-8659db4cc3bb','僧仲儼芥室','韓元吉','宋','宋诗','song-poetry','','[]','設席纔方丈，誰將芥子看。',48,'全唐诗/poet.song.124000.json','["設席纔方丈，誰將芥子看。", "須彌藏自穩，琥珀拾應難。", "脚底芒鞋破，顱邊衲被寒。", "遥知八萬座，一笑且團欒。"]'),
('bba8b606-a107-4b80-99c3-664aff7b0a7d','易安齋','韓元吉','宋','宋诗','song-poetry','','[]','紫陌猶千里，禪房自一家。',48,'全唐诗/poet.song.124000.json','["紫陌猶千里，禪房自一家。", "翠深穿小徑，紅濕動迷花。", "絡石寒梢亂，欹巖碧幹斜。", "春江夜來雨，如爲洗烟霞。"]'),
('22f108d0-597f-4d3d-8e39-d2016d1037ce','過松江寄務觀五首  其一','韓元吉','宋','宋诗','song-poetry','','[]','四海習鑿齒，雲間陸士龍。',48,'全唐诗/poet.song.124000.json','["四海習鑿齒，雲間陸士龍。", "酒狂須一石，文好自三冬。", "風水客愁遠，烟花春事濃。", "還將枕流耳，來聽景陽鐘。"]'),
('952fce21-5603-43ce-9647-19d681d0d45a','過松江寄務觀五首  其二','韓元吉','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','風浪白如屋，垂虹烟靄間。',48,'全唐诗/poet.song.124000.json','["風浪白如屋，垂虹烟靄間。", "清心太湖水，滿眼洞庭山。", "放鶴迎人舞，飛鷗伴我閒。", "是中有佳句，詩思未容慳。"]'),
('21cfb759-ef01-4ee1-b0ce-dad5391b6594','過松江寄務觀五首  其三','韓元吉','宋','宋诗','song-poetry','','[]','一別未十日，舉頭楊柳黄。',48,'全唐诗/poet.song.124000.json','["一別未十日，舉頭楊柳黄。", "蜂來知酒美，梅度覺船香。", "岸幘春容好，翻書晝景長。", "無人共談麈，自酌引壺觴。"]'),
('3305e737-1d8a-4254-98fb-5ce4a12a17ba','過松江寄務觀五首  其四','韓元吉','宋','宋诗','song-poetry','','[]','湖岸見亭館，誰家長鎖門。',48,'全唐诗/poet.song.124000.json','["湖岸見亭館，誰家長鎖門。", "主人寧好事，淥水但名園。", "借我安茅屋，容君共酒樽。", "風波正奔走，獨立望江村。"]'),
('bba1afef-6e1d-4ed4-b43d-86a185110444','過松江寄務觀五首  其五','韓元吉','宋','宋诗','song-poetry','','[]','並舍盡垂柳，出簷多好花。',48,'全唐诗/poet.song.124000.json','["並舍盡垂柳，出簷多好花。", "獨尋江岸路，靜愛野人家。", "水暖分魚子，沙晴蹙荻芽。", "放歌吾亦醉，漁戶即生涯。"]'),
('f9e80696-24bd-46fe-b83a-9283d57d4f87','寄趙德莊二首  其一','韓元吉','宋','宋诗','song-poetry','','[]','報陟西樞掾，遥憐勢未行。',48,'全唐诗/poet.song.124000.json','["報陟西樞掾，遥憐勢未行。", "葬親嘗有請，去國豈無名。", "松菊關心在，江山到眼青。", "琵琶洲畔宅，歸計幾時成。"]'),
('d2854366-467c-456d-893e-b1321460f711','寄趙德莊二首  其二','韓元吉','宋','宋诗','song-poetry','','[]','早辱交情厚，年來事輒同。',48,'全唐诗/poet.song.124000.json','["早辱交情厚，年來事輒同。", "自知榮宦拙，甘爲好詩窮。", "鳬雁且依水，馬牛還信風。", "故應懷李白，但欲老江東。"]'),
('a76f87da-680e-4f77-a186-f47cfce989f9','送子雲五首  其一','韓元吉','宋','宋诗','song-poetry','','[]','四海雙兄弟，南來幾別離。',48,'全唐诗/poet.song.124000.json','["四海雙兄弟，南來幾別離。", "未成春草夢，先動白雲思。", "涕淚三年隔，風塵數月期。", "生涯奔走裏，卜築定何時。"]'),
('c7eda40c-2c94-49ce-966d-789a3c4d3b31','送子雲五首  其二','韓元吉','宋','宋诗','song-poetry','','[]','薄宦何堪遠，兄今奉板輿。',48,'全唐诗/poet.song.124000.json','["薄宦何堪遠，兄今奉板輿。", "貓頭供美筍，玉板薦嘉魚。", "川陸徐行李，暄寒慎起居。", "會因回雁足，時一問何如。"]'),
('f1c13d36-259f-4cfb-b359-3c167c1e509f','送子雲五首  其三','韓元吉','宋','宋诗','song-poetry','','[]','楚國富山水，衡湘千里餘。',48,'全唐诗/poet.song.124000.json','["楚國富山水，衡湘千里餘。", "人皆思太傅，我獨念三閭。", "貧賤真勞矣，功名果命歟。", "官閒道林寺，洗眼卧看書。"]'),
('9c3db08b-688c-4595-b9b5-6213cccc0d84','送子雲五首  其四','韓元吉','宋','宋诗','song-poetry','','[]','別意能淒楚，驪駒且緩聽。',48,'全唐诗/poet.song.124000.json','["別意能淒楚，驪駒且緩聽。", "百年三過一，萬事醉還醒。", "策馬身猶健，看山眼倍青。", "東風有底憾，吹柳暗長亭。"]'),
('e282f2cb-816d-4265-bda5-bc1553759a6c','送子雲五首  其五','韓元吉','宋','宋诗','song-poetry','','[]','水闊湖南道，春深可當遊。',48,'全唐诗/poet.song.124000.json','["水闊湖南道，春深可當遊。", "鳥聲喧綠樹，花影趁行舟。", "短袖那容舞，良疇不易謀。", "有親垂白髮，斂板未應羞。"]'),
('9b7d07a7-9844-43bf-9e8c-53e5905048b2','送漳赴分寧尉','韓元吉','宋','宋诗','song-poetry','','[]','挾筴度春水，絮飛花易闌。',48,'全唐诗/poet.song.124000.json','["挾筴度春水，絮飛花易闌。", "吾衰聊玩世，子壯且勤官。", "雨後半篙綠，風生孤棹寒。", "慇懃酌雙井，爲試茗芽看。"]'),
('dcedba25-7b90-4543-a077-a9656d4cb93f','送溫伯玉二首  其一','韓元吉','宋','宋诗','song-poetry','','[]','楚尾還重九，荒園菊半花。',48,'全唐诗/poet.song.124000.json','["楚尾還重九，荒園菊半花。", "因君向姑孰，使我墜烏紗。", "更度千秋嶺，休尋萬里沙。", "壯年豪氣在，途路莫興嗟。"]'),
('c6547f5b-e4e6-4abb-a1a9-95d6473b7606','送溫伯玉二首  其二','韓元吉','宋','宋诗','song-poetry','','[]','牛渚青山路，衰遲舊往來。',48,'全唐诗/poet.song.124000.json','["牛渚青山路，衰遲舊往來。", "西風動黄葉，朔雪記寒梅。", "戍鼓邊城近，樓船猛士催。", "然犀不用照，拔劍憶澹臺。"]'),
('a7bfff19-e3e9-4a1d-88fc-07cb2732adf7','送張仲良二首  其一','韓元吉','宋','宋诗','song-poetry','','[]','客裏親朋別，詩成倍黯然。',48,'全唐诗/poet.song.124000.json','["客裏親朋別，詩成倍黯然。", "春風動花柳，歸路繞雲煙。", "共絕過門盜，俱無使鬼錢。", "生涯知底許，消息幸頻傳。"]'),
('62f6681b-32d9-4aee-966b-b218bdd63f29','送張仲良二首  其二','韓元吉','宋','宋诗','song-poetry','','[]','氣概青雲上，聲華碧海邊。',48,'全唐诗/poet.song.124000.json','["氣概青雲上，聲華碧海邊。", "交遊俱得譽，伯仲總能賢。", "幕府寧淹薄，諸公肯薦延。", "功名第遲速，强飯且加鞭。"]'),
('45b21337-0024-4754-9904-f2f690cbcb06','送梁士衡歸餘杭  其一','韓元吉','宋','宋诗','song-poetry','','[]','一水分他縣，音書近可傳。',48,'全唐诗/poet.song.124000.json','["一水分他縣，音書近可傳。", "飄零俱北客，憔悴各中年。", "破屋春風裏，扁舟夜雪前。", "故人逢短簿，爲話意茫然。"]'),
('e94af9d5-3d1b-4bfa-9d9d-174297e1c27d','送梁士衡歸餘杭  其二','韓元吉','宋','宋诗','song-poetry','','[]','古寺荒山曲，相過日自宜。',48,'全唐诗/poet.song.124000.json','["古寺荒山曲，相過日自宜。", "插花狂墮幘，折屐醉爭棋。", "世事關情懶，風光逐意移。", "歲寒冰斷港，君去復何之。"]'),
('aa33bb6a-bea1-48fb-9803-411720bb1632','送諒弟丞邵陽','韓元吉','宋','宋诗','song-poetry','','[]','春水生南澗，吾衰久索居。',48,'全唐诗/poet.song.124000.json','["春水生南澗，吾衰久索居。", "三年還作別，數字且頻書。", "文史差無負，田園慨未餘。", "常存愛民意，門戶有權輿。"]'),
('d5937691-85fe-4a05-83cc-28e424719044','送中甫兄之淮南  其一','韓元吉','宋','宋诗','song-poetry','','[]','憶昔湖陰道，邊聲日夜聞。',48,'全唐诗/poet.song.124000.json','["憶昔湖陰道，邊聲日夜聞。", "遠峰明積雪，疊鼓墮層雲。", "未歎河山異，常憂玉石焚。", "三年真一夢，相見且論文。"]'),
('dd9fe523-7d9f-4fe7-9e06-ecd9cf643938','送中甫兄之淮南  其二','韓元吉','宋','宋诗','song-poetry','','[]','老惜親朋別，貧知客寓愁。',48,'全唐诗/poet.song.124000.json','["老惜親朋別，貧知客寓愁。", "青燈耿遥夜，濁酒對窮秋。", "寒日催征騎，新霜倚縣樓。", "因君問淝水，莫渡北來舟。"]'),
('46554844-fa26-4316-a085-f135e4c68da6','淲赴貴池簿','韓元吉','宋','宋诗','song-poetry','','[]','四十纔生子，今年亦效官。',48,'全唐诗/poet.song.124000.json','["四十纔生子，今年亦效官。", "國恩期共報，世路覺尤難。", "簿領猶應暇，詩書且細觀。", "傳家門戶立，即此慰衰殘。"]'),
('7fd2fd5b-3fdd-4c4e-94f0-1fdd95f60733','次韵子雲春日見懷二首  其一','韓元吉','宋','宋诗','song-poetry','','[]','每惜春光去，生憎鶗鴂鳴。',48,'全唐诗/poet.song.124000.json','["每惜春光去，生憎鶗鴂鳴。", "倦遊心易賞，多病戍仍更。", "風雨山花過，池塘野水生。", "買牛歸問舍，此計會應成。"]'),
('7e3d9408-a536-4c51-9fe9-bbf7336619a0','次韵子雲春日見懷二首  其二','韓元吉','宋','宋诗','song-poetry','','[]','山寺鶑花裏，懸知載酒行。',48,'全唐诗/poet.song.124000.json','["山寺鶑花裏，懸知載酒行。", "青春隨夢斷，白髮伴愁生。", "爛醉真吾事，忘機豈世情。", "書來得佳句，雙眼暫增明。"]'),
('a0e17369-407b-435c-b819-20f47fcedb13','次韵張晉彥書事','韓元吉','宋','宋诗','song-poetry','','[]','頡利何時縛，康居久未灰。',48,'全唐诗/poet.song.124000.json','["頡利何時縛，康居久未灰。", "天威如自震，敵勢不難摧。", "日月丹心在，風塵白眼開。", "受降城旋築，且緩羽書來。"]'),
('6d60c811-1312-4225-a157-cab69de459bc','次韵任信儒見過','韓元吉','宋','宋诗','song-poetry','','[]','鬭雀嗟窮巷，鳴騶枉故人。',48,'全唐诗/poet.song.124000.json','["鬭雀嗟窮巷，鳴騶枉故人。", "塵埃生破甑，風雨墊烏巾。", "別久情逾厚，詩來語更新。", "囊空得珠玉，此段不全貧。"]'),
('2c145d44-90e4-45a7-994e-5be4ecc84568','次韵趙任卿至北苑二首  其一','韓元吉','宋','宋诗','song-poetry','','[]','行樂須春事，微官日自忙。',48,'全唐诗/poet.song.124000.json','["行樂須春事，微官日自忙。", "輕雲弄天色，細雨出風光。", "筠甲連山破，林髯夾道蒼。", "擬尋花島去，更待茗芽香。"]'),
('e63565e2-46b5-461c-8f62-21842e3d0794','次韵趙任卿至北苑二首  其二','韓元吉','宋','宋诗','song-poetry','','[]','好雨驚連夜，疏鐘喜報晨。',48,'全唐诗/poet.song.124000.json','["好雨驚連夜，疏鐘喜報晨。", "池心春漲綠，花面曉粧勻。", "野渡經年別，官茶幾焙新。", "風光爲傳語，何事曲江濱。"]'),
('179139fd-c1c6-4eec-b12c-949fee1074d8','次韵魯如暉雪晴','韓元吉','宋','宋诗','song-poetry','','[]','臘近千門雪，風高一夜晴。',48,'全唐诗/poet.song.124000.json','["臘近千門雪，風高一夜晴。", "醉餘和被擁，夢破覺窗明。", "鼙鼓三年戍，關河萬里情。", "應憐鐵甲冷，烽火未須驚。"]'),
('103f94e7-0653-4afc-bfa9-63fd64f7e5f2','次韵金元鼎新年七十  其一','韓元吉','宋','宋诗','song-poetry','','[]','七十古稀有，君今還倦游。',48,'全唐诗/poet.song.124000.json','["七十古稀有，君今還倦游。", "危機直虎口，薄利祇蠅頭。", "黄髮宜登用，清時忍退休。", "遥知江上宅，聊近水邊鷗。"]'),
('f6bcd8da-d95a-4da6-9303-53f1a14e8821','次韵金元鼎新年七十  其二','韓元吉','宋','宋诗','song-poetry','','[]','論文傾滿座，嗜酒見天真。',48,'全唐诗/poet.song.124000.json','["論文傾滿座，嗜酒見天真。", "舊愜李君馭，今懷王翰鄰。", "歡情知老大，詩話倍清新。", "莫作懸車念，滔滔且問津。"]'),
('88c54131-1c01-4e83-80e9-6a206043b4ae','葉少保挽詞六首  其一','韓元吉','宋','宋诗','song-poetry','','[]','奧學餘家法，宏材邁古風。',48,'全唐诗/poet.song.124000.json','["奧學餘家法，宏材邁古風。", "剸煩樽俎上，禦侮笑談中。", "勳業中興殿，規模大駕宮。", "哀聞父老泣，遺愛六州同。"]'),
('8d459e5b-a03c-40e2-93a2-a79c892b22d0','葉少保挽詞六首  其二','韓元吉','宋','宋诗','song-poetry','','[]','望實諸公右，文章百代師。',48,'全唐诗/poet.song.124000.json','["望實諸公右，文章百代師。", "匡時存詔令，謀國見丞疑。", "易識悲麟意，難追吐鳳辭。", "門生滿天下，誰繼蔡邕碑。"]'),
('0697ecee-6de3-40b0-8e3f-459c011a264e','葉少保挽詞六首  其三','韓元吉','宋','宋诗','song-poetry','','[]','宦達平生早，高年及引歸。',48,'全唐诗/poet.song.124000.json','["宦達平生早，高年及引歸。", "安車榮絳節，黄髮遽衰衣。", "未致生芻奠，俄驚薤露晞。", "孝心天地惻，相望兩靈幃。"]'),
('a77a7a2d-a546-4ea3-bfba-d319a560214e','葉少保挽詞六首  其四','韓元吉','宋','宋诗','song-poetry','','[]','精舍湖山外，天開萬石林。',48,'全唐诗/poet.song.124000.json','["精舍湖山外，天開萬石林。", "五車娛晚歲，一壑遂初心。", "激水穿巖竇，栽花繞澗陰。", "佳名端不朽，揮淚記登臨。"]'),
('27340ba9-f0b3-4fd6-a4bc-8051f38dc3e1','葉少保挽詞六首  其五','韓元吉','宋','宋诗','song-poetry','','[]','翰墨通家舊，吁嗟大父時。',48,'全唐诗/poet.song.124000.json','["翰墨通家舊，吁嗟大父時。", "追隨千里駕，酬唱百篇詩。", "小器慚非遠，孤童誤見奇。", "慇懃授簡意，敢負昔年期。"]'),
('b6067899-11fe-450f-bb32-4a47d338e3a4','葉少保挽詞六首  其六','韓元吉','宋','宋诗','song-poetry','','[]','憶罷儀曹試，登門語更親。',48,'全唐诗/poet.song.124000.json','["憶罷儀曹試，登門語更親。", "故懷如昨日，一醉賞餘春。", "佳句猶霑墨，遺編竟掩塵。", "烟雲變朝暮，感慨獨傷神。"]'),
('804be653-465a-4ca1-a8fa-845c040b74d2','故資政殿大學士樞密洪公挽詞二首  其一','韓元吉','宋','宋诗','song-poetry','','[]','世學推東楚，文名冠異科。',48,'全唐诗/poet.song.124000.json','["世學推東楚，文名冠異科。", "弟兄聯玉筍，父子擅金坡。", "籌幄淵謀在，陪京惠愛多。", "無因奠雞酒，清淚灑江波。"]'),
('61406efa-74e8-4721-8d28-702309b273dd','故資政殿大學士樞密洪公挽詞二首  其二','韓元吉','宋','宋诗','song-poetry','','[]','甲第湖山美，人知小隠名。',48,'全唐诗/poet.song.124000.json','["甲第湖山美，人知小隠名。", "天方開樂土，地忽起佳城。", "祕殿疏殊渥，珍臺錫異榮。", "勳勞纔右府，曾未陟魁衡。"]'),
('88d62a2c-303c-4680-9da4-3c936aad5d44','故贈太師丞相文恭陳公挽詞三首  其一','韓元吉','宋','宋诗','song-poetry','','[]','拱揖消狂寇，從容奉兩宮。',48,'全唐诗/poet.song.124000.json','["拱揖消狂寇，從容奉兩宮。", "臨危幾謝傅，忍事實婁公。", "陶冶無偏黨，經綸盡樸忠。", "再來金鼎地，高卧亦成功。"]'),
('335f9219-1b79-48cb-acb5-a5c758733368','故贈太師丞相文恭陳公挽詞三首  其二','韓元吉','宋','宋诗','song-poetry','','[]','扶疾祗嚴詔，邦基整屢危。',48,'全唐诗/poet.song.124000.json','["扶疾祗嚴詔，邦基整屢危。", "紫宸朝奏事，黄閣暮興悲。", "德望儀千載，恩榮冠一時。", "石龜山下路，誰爲記豐碑。"]'),
('b1c486e2-28d8-4d1e-9ad2-ff239798b088','故贈太師丞相文恭陳公挽詞三首  其三','韓元吉','宋','宋诗','song-poetry','','[]','凜凜循良吏，休休一介臣。',48,'全唐诗/poet.song.124000.json','["凜凜循良吏，休休一介臣。", "投艱推宇量，禦侮頼精神。", "給侍恩雖渥，懷歸志莫伸。", "平泉開甲第，花木未經春。"]'),
('ec2442e8-766a-43be-8ccd-b131957ea470','故太師和王挽詩三首  其一','韓元吉','宋','宋诗','song-poetry','','[]','宿衛登環尹，榮恩四十春。',48,'全唐诗/poet.song.124000.json','["宿衛登環尹，榮恩四十春。", "威名傳瀚海，功烈上麒麟。", "却敵凝山岳，臨機妙鬼神。", "中興奉朝請，勞舊總無人。"]'),
('9d7ca35b-ea30-459a-bc11-ec2233cd70e1','故太師和王挽詩三首  其二','韓元吉','宋','宋诗','song-poetry','','[]','淮右偏師出，江津督府開。',48,'全唐诗/poet.song.124000.json','["淮右偏師出，江津督府開。", "橐臯賊陣蹙，瓜步敵鋒摧。", "寶劍疇能舉，神旗悵莫回。", "悲風苕水路，千載有餘哀。"]'),
('97bfd0fb-9c73-4c84-83c6-1659aa680549','故太師和王挽詩三首  其三','韓元吉','宋','宋诗','song-poetry','','[]','甲第神京冠，王封異姓優。',48,'全唐诗/poet.song.124000.json','["甲第神京冠，王封異姓優。", "風雲開傑閣，水月轉芳洲。", "種玉階庭盛，揮金族緒周。", "諸郎自持橐，衮衮尚公侯。"]'),
('37073efc-69d4-4b3b-967f-ef835d04c58c','致政龍圖給事吳公挽詞二首  其一','韓元吉','宋','宋诗','song-poetry','','[]','風采儀三院，循良著六州。',48,'全唐诗/poet.song.124000.json','["風采儀三院，循良著六州。", "譽高青瑣闥，名動紫雲樓。", "經世餘閎議，興邦閟遠猷。", "君王問黄髮，柱石可能留。"]'),
('c264d1b9-0fb3-43c4-892f-86ec288f8883','致政龍圖給事吳公挽詞二首  其二','韓元吉','宋','宋诗','song-poetry','','[]','勇退湖山地，心期白傅論。',48,'全唐诗/poet.song.124000.json','["勇退湖山地，心期白傅論。", "仙風占蒼嶺，樂土並桃源。", "壯節傳交舊，儒科付子孫。", "脩齡纔八十，殄瘁只聲吞。"]'),
('b0df05a4-a1f4-447d-b340-469059d82faf','致政龍圖給事徐公挽詞二首  其一','韓元吉','宋','宋诗','song-poetry','','[]','磊落南州士，家聲二百年。',48,'全唐诗/poet.song.124000.json','["磊落南州士，家聲二百年。", "失身幾利吻，得路已華顛。", "青瑣元虛位，黄扉久佇賢。", "九原寧可作，東望益潸然。"]'),
('ffda40d8-c90a-4f2f-8fa5-c730d5a8c44e','致政龍圖給事徐公挽詞二首  其二','韓元吉','宋','宋诗','song-poetry','','[]','今代詢黄髮，臨雍缺盛儀。',48,'全唐诗/poet.song.124000.json','["今代詢黄髮，臨雍缺盛儀。", "久從曾釜樂，俄重鯉庭悲。", "德履嗟如在，功名誤見期。", "平生拄頤劍，聊掛墓門枝。"]'),
('c4e0b1b4-a0a6-4804-afb6-576adbd046df','葉夢錫丞相挽詞二首  其一','韓元吉','宋','宋诗','song-poetry','','[]','製邑騰嘉譽，升平遂一州。',48,'全唐诗/poet.song.124000.json','["製邑騰嘉譽，升平遂一州。", "雍容持從橐，慷慨動宸旒。", "相業看調鼎，兵機久運籌。", "勳庸元未究，湖海淚空流。"]'),
('9abe5665-370c-4966-9df1-29a09ed5bea4','葉夢錫丞相挽詞二首  其二','韓元吉','宋','宋诗','song-poetry','','[]','味道蘇仙井，言歸鬢尚青。',48,'全唐诗/poet.song.124000.json','["味道蘇仙井，言歸鬢尚青。", "僅周新甲子，還仰舊儀刑。", "祕殿欣疏寵，華鐘待勒銘。", "追隨樽酒地，愁絕最高亭。"]'),
('80692d9c-3400-4e04-97af-7df26fbcf0d6','挽任諫議詞二首  其一','韓元吉','宋','宋诗','song-poetry','','[]','身致高門重，心無闇室欺。',48,'全唐诗/poet.song.124000.json','["身致高門重，心無闇室欺。", "臧孫宜有後，伯道乃無兒。", "千載君如此，流年疾若斯。", "寧無百人贖，遂作九原悲。"]'),
('35be4ed6-1044-46fe-b84c-f9e3ab1a4243','挽任諫議詞二首  其二','韓元吉','宋','宋诗','song-poetry','','[]','凜凜諍臣節，恂恂循吏名。',48,'全唐诗/poet.song.124000.json','["凜凜諍臣節，恂恂循吏名。", "世嗟陽諫議，人憶謝宣城。", "優詔纔三接，嘉言未一行。", "清霜數行淚，豈爲故人傾。"]'),
('dd2f36d7-64cd-4df6-bf78-098d3c46cefb','故端明尚書汪公挽詞二首  其一','韓元吉','宋','宋诗','song-poetry','','[]','未冠登華選，高文動漢廷。',48,'全唐诗/poet.song.124000.json','["未冠登華選，高文動漢廷。", "持身嚴榘席，慮世炳丹青。", "庶府咨沿革，諸儒見典型。", "空嗟廊廟略，不上鼎彝銘。"]'),
('1e199693-153d-4772-b7b9-6768f1bcb32c','故端明尚書汪公挽詞二首  其二','韓元吉','宋','宋诗','song-poetry','','[]','獻納高門地，君王識履聲。',48,'全唐诗/poet.song.124000.json','["獻納高門地，君王識履聲。", "閩山歌惠政，蜀道憺威名。", "逝矣嗟天命，誰歟總國成。", "弟兄無六十，殄瘁亦堪驚。"]'),
('ecc22a9d-5d52-49ef-b978-1eb453278bff','致政許侍郎挽詞二首  其一','韓元吉','宋','宋诗','song-poetry','','[]','海內循良政，高名實吏師。',48,'全唐诗/poet.song.124000.json','["海內循良政，高名實吏師。", "銅符嘗五換，玉節更三持。", "慷慨平戎策，雍容聖德詩。", "甘泉僅持橐，功不負明時。"]'),
('fb4023aa-6c00-45f3-97a0-c3cf051e2905','致政許侍郎挽詞二首  其二','韓元吉','宋','宋诗','song-poetry','','[]','蜀道煩司馬，宣城屈謝公。',48,'全唐诗/poet.song.124000.json','["蜀道煩司馬，宣城屈謝公。", "風行萬里外，身老十年中。", "厚德今疇繼，深知昔誤蒙。", "佳城閟千載，雞酒恨何窮。"]'),
('f419da5f-6a17-437b-a22a-7e2c8df38e52','故宮使待制侍郎陳公挽詞二首  其一','韓元吉','宋','宋诗','song-poetry','','[]','政譽京江口，威名峴首山。',48,'全唐诗/poet.song.124000.json','["政譽京江口，威名峴首山。", "折衝章貢外，制勝漢淮間。", "零落金閨彥，淒涼玉笋班。", "文章與功業，未老竟長閒。"]'),
('1504895c-f014-4637-a3a2-7111cef08af6','故宮使待制侍郎陳公挽詞二首  其二','韓元吉','宋','宋诗','song-poetry','','[]','結綬同郎省，幽居願卜鄰。',48,'全唐诗/poet.song.124000.json','["結綬同郎省，幽居願卜鄰。", "攖寧良自適，坎壈遂無伸。", "壯志嗟猶在，交情晚更親。", "秋風敬亭路，西望一霑巾。"]'),
('87b65d7c-e816-46a7-940d-97fab5a0f90d','故宮使參政觀文錢公挽詞二首  其一','韓元吉','宋','宋诗','song-poetry','','[]','忠孝全家法，清修極道腴。',48,'全唐诗/poet.song.124000.json','["忠孝全家法，清修極道腴。", "雍容調庶政，談笑靖邊隅。", "許國心猶壯，安時貌不枯。", "脩齡纔七十，誰爲隔黄壚。"]'),
('d14279cd-7d9d-4b1e-8ee7-755f27f57ea5','故宮使參政觀文錢公挽詞二首  其二','韓元吉','宋','宋诗','song-poetry','','[]','甲第依香火，棲心不離禪。',48,'全唐诗/poet.song.124000.json','["甲第依香火，棲心不離禪。", "頤神雖綠野，紀績自凌烟。", "榮觀丹丘外，真遊弱水邊。", "佳城近劉阮，覺路有飛仙。"]'),
('14ec6132-215e-48ce-8ad7-578c2905fa19','故致政參政大資張公挽詞三首  其一','韓元吉','宋','宋诗','song-poetry','','[]','海內推耆德，朝端藹直聲。',48,'全唐诗/poet.song.124000.json','["海內推耆德，朝端藹直聲。", "金輝餘烈火，玉價自連城。", "正色消羣枉，高風聳後生。", "君王問黄髮，猶僅陟台衡。"]'),
('0e24f943-aee0-461a-9be8-7533971032e0','故致政參政大資張公挽詞三首  其二','韓元吉','宋','宋诗','song-poetry','','[]','益部煩分陝，金陵起御戎。',48,'全唐诗/poet.song.124000.json','["益部煩分陝，金陵起御戎。", "逢時身已病，憂國志彌忠。", "廊廟訏謨外，丘園夢寐中。", "彈冠與歸老，盛節有初終。"]'),
('c2d99d4b-f5df-4966-af43-0b8b226baa5d','故致政參政大資張公挽詞三首  其三','韓元吉','宋','宋诗','song-poetry','','[]','憶荷公車薦，多慚識面求。',48,'全唐诗/poet.song.124000.json','["憶荷公車薦，多慚識面求。", "驚心異生死，倒指十春秋。", "國士懷青眼，門生慨白頭。", "束芻催老淚，東與大江流。"]'),
('dce2589d-27e3-4c5b-917e-3cdf2d18e611','挽曾伯充大夫詞二首  其一','韓元吉','宋','宋诗','song-poetry','','[]','作吏餘家法，臨民有古風。',48,'全唐诗/poet.song.124000.json','["作吏餘家法，臨民有古風。", "政推平易外，人在典型中。", "道擬莊生合，年幾衛武同。", "清時記耆舊，揮淚楚江東。"]'),
('bfdb72f7-193e-47a0-86ca-b10b9e8f6839','挽曾伯充大夫詞二首  其二','韓元吉','宋','宋诗','song-poetry','','[]','宦達雖無意，安榮自一門。',48,'全唐诗/poet.song.124000.json','["宦達雖無意，安榮自一門。", "剖符看令子，曳綬及諸孫。", "盛德清難繼，高風俗爲敦。", "葬車駢百兩，歸卧九華根。"]'),
('3dbf5680-b549-4fc8-b8db-5c4af14e2397','方務德侍郎挽詞二首  其一','韓元吉','宋','宋诗','song-poetry','','[]','壯歲分符節，飛騰四十春。',48,'全唐诗/poet.song.124000.json','["壯歲分符節，飛騰四十春。", "吁嗟循吏傳，無復老成人。", "三輔勤勞舊，西清寵數新。", "青山問何許，猶與謝公鄰。"]'),
('8325ea79-b460-4a6c-ad6a-096d824d0632','方務德侍郎挽詞二首  其二','韓元吉','宋','宋诗','song-poetry','','[]','上聖詢黄髮，清時慨莫留。',48,'全唐诗/poet.song.124000.json','["上聖詢黄髮，清時慨莫留。", "居中二千石，典外十三州。", "禁闥多閎議，籌幃裕遠猷。", "交親半天下，注海淚空流。"]'),
('019ce999-80a2-4731-9516-1796604404b7','周元特詹事挽詞二首  其一','韓元吉','宋','宋诗','song-poetry','','[]','道學尊閭里，衣冠見偉人。',48,'全唐诗/poet.song.124000.json','["道學尊閭里，衣冠見偉人。", "鷄羣真野鶴，麕角目祥麟。", "讜論追前輩，清時識諍臣。", "他年激貪懦，風動霅溪濱。"]'),
('872e77df-4ce9-476f-b490-0af59e35bec8','周元特詹事挽詞二首  其二','韓元吉','宋','宋诗','song-poetry','','[]','黄髮趨嚴詔，青宮啟太微。',48,'全唐诗/poet.song.124000.json','["黄髮趨嚴詔，青宮啟太微。", "園公方入侍，疏傅已言歸。", "奏牘三千在，流年七十稀。", "無從奠鷄酒，老疾只沾衣。"]'),
('c742b7fe-33fe-4983-b282-70788fd6368b','挽徐敦濟郎中詞二首  其一','韓元吉','宋','宋诗','song-poetry','','[]','南渡推人物，彝常有世家。',48,'全唐诗/poet.song.124000.json','["南渡推人物，彝常有世家。", "州麾三上最，使節五分華。", "通籍恩初渥，登車病已加。", "甘泉垂入侍，華屋漫興嗟。"]'),
('5cd17096-cba0-4b5d-aa4b-23b69ea679aa','挽徐敦濟郎中詞二首  其二','韓元吉','宋','宋诗','song-poetry','','[]','强學三冬足，高談四座傾。',48,'全唐诗/poet.song.124000.json','["强學三冬足，高談四座傾。", "書成唐北海，文似漢西京。", "籌幄嘗裨畫，星曹僅掛名。", "生芻纔一束，聊寄淚縱橫。"]'),
('74ef8f19-0602-4efd-bda7-479148250731','挽傅安道郎中詞二首  其一','韓元吉','宋','宋诗','song-poetry','','[]','節槩存先烈，文才藹儁聲。',48,'全唐诗/poet.song.124000.json','["節槩存先烈，文才藹儁聲。", "弟兄聯膴仕，父子擅英名。", "密勿棲郎省，光華擁使旌。", "甘泉虛從橐，曾未席恩榮。"]'),
('0e967aa8-6e77-46d5-b1b4-687b21fae587','挽傅安道郎中詞二首  其二','韓元吉','宋','宋诗','song-poetry','','[]','蚤負凌雲氣，長懷流水音。',48,'全唐诗/poet.song.124000.json','["蚤負凌雲氣，長懷流水音。", "詞場俱白首，世路只丹心。", "妙語空成誦，懽盟詎可尋。", "泉山幾千里，涕淚俱霑襟。"]'),
('1e8037e5-b536-444a-94d8-81758028bb5e','范泉州挽詞二首  其一','韓元吉','宋','宋诗','song-poetry','','[]','淡墨標名早，飛騰僅石渠。',48,'全唐诗/poet.song.124000.json','["淡墨標名早，飛騰僅石渠。", "學傳外家藴，論合古人餘。", "議本楓宸疏，評和相第書。", "忠言與危行，青史未應虛。"]'),
('ec84a925-dbfa-454d-a328-77cb790f5e5b','范泉州挽詞二首  其二','韓元吉','宋','宋诗','song-poetry','','[]','玉節江南道，銅符海上州。',48,'全唐诗/poet.song.124000.json','["玉節江南道，銅符海上州。", "登車人自化，截鐙士爭留。", "不作田園計，長懷世事憂。", "秋風閉黄壤，誰爲子孫謀。"]'),
('8b8018df-2d39-4f82-81ff-689ca3892c43','挽張元幹國錄詞二首  其一','韓元吉','宋','宋诗','song-poetry','','[]','左學馳聲舊，中朝得錄初。',48,'全唐诗/poet.song.124000.json','["左學馳聲舊，中朝得錄初。", "宏材知底用，壯志亦成虛。", "歸旐三千遠，親年八十餘。", "蒼天誰與問，行路亦欷歔。"]'),
('27ad53b7-44b9-4194-b1a9-3035f5617cad','挽張元幹國錄詞二首  其二','韓元吉','宋','宋诗','song-poetry','','[]','一第固已晚，九遷人共期。',48,'全唐诗/poet.song.124000.json','["一第固已晚，九遷人共期。", "功名雖有命，壽考獨無時。", "門士韜珪璧，諸郎襲禮詩。", "他年振儒學，猶慰九原悲。"]'),
('9348ff5c-cc75-4a9c-beba-4a42ecc7941d','尹少稷挽詞二首  其一','韓元吉','宋','宋诗','song-poetry','','[]','蚤擅奇童譽，中蜚處士聲。',48,'全唐诗/poet.song.124000.json','["蚤擅奇童譽，中蜚處士聲。", "談鋒粲開闔，筆力妙縱橫。", "主聖由言悟，官清以諫名。", "故交零落盡，老淚與河傾。"]'),
('912dc2e1-827d-40ef-86c6-959f3d324756','尹少稷挽詞二首  其二','韓元吉','宋','宋诗','song-poetry','','[]','今代賢良策，中興未一陳。',48,'全唐诗/poet.song.124000.json','["今代賢良策，中興未一陳。", "文章如漢士，家世亦齊人。", "遇合嗟云晚，忠嘉慨莫伸。", "朔風吹墓草，毀譽付千春。"]'),
('7a2ec4fc-6c14-4aa6-930c-50b62f48a200','毛平仲挽詞二首  其一','韓元吉','宋','宋诗','song-poetry','','[]','奧學窮千古，奇文擅兩都。',48,'全唐诗/poet.song.124000.json','["奧學窮千古，奇文擅兩都。", "功名一盃酒，身世五車書。", "未奏揚雄賦，長懷仲舉輿。", "溪塘巖下水，豈羨石爲渠。"]'),
('b960a967-a1f5-49c5-b307-0cce2188e0bb','毛平仲挽詞二首  其二','韓元吉','宋','宋诗','song-poetry','','[]','蚤歲聞嘉譽，論交鬢已絲。',48,'全唐诗/poet.song.124000.json','["蚤歲聞嘉譽，論交鬢已絲。", "長言雖面隔，千里但心期。", "故壘生芻奠，塵編幼婦辭。", "倚天長劍在，欲掛漫興悲。"]'),
('72114f83-17f2-4ced-83eb-ab5984d57f35','宋傳道挽詞二首  其一','韓元吉','宋','宋诗','song-poetry','','[]','德履無遺恨，絃歌有去思。',48,'全唐诗/poet.song.124000.json','["德履無遺恨，絃歌有去思。", "養親三釜樂，作郡十年遲。", "壯志沈黄壤，英遊閉赤墀。", "豐碑頌遺愛，誰爲繼羅池。"]'),
('aa7d0c32-680d-468b-b99c-37705766380a','宋傳道挽詞二首  其二','韓元吉','宋','宋诗','song-poetry','','[]','留落東州彥，相期幸卜鄰。',48,'全唐诗/poet.song.124000.json','["留落東州彥，相期幸卜鄰。", "筒詩餘唱永，樽酒記情親。", "舊國歸無日，諸鄉見有人。", "佳城千載恨，雪涕楚江濱。"]'),
('76b20307-8431-4651-8e0c-8ce466ebafae','故秦國太夫人鄧氏挽詞','韓元吉','宋','宋诗','song-poetry','','[]','諸父聯丞弼，元夫總化鈞。',48,'全唐诗/poet.song.124000.json','["諸父聯丞弼，元夫總化鈞。", "光華人莫並，恭儉古無倫。", "沐國三茅土，儀家五鳳麟。", "塗車閭里慟，矧此故園親。"]'),
('6e4413f4-009d-4c83-b7d4-69788897cc3e','信國太夫人慕容氏挽詞','韓元吉','宋','宋诗','song-poetry','','[]','望族尚書舊，宜家藹縉紳。',48,'全唐诗/poet.song.124000.json','["望族尚書舊，宜家藹縉紳。", "無人知善教，有子冠鴻鈞。", "箕箒惟安禮，詩書不待鄰。", "鴟堂萬鍾養，風木倍悲辛。"]'),
('51629fdc-4b6f-457d-8884-8d0ba9e7b54e','鹿鳴宴','韓元吉','宋','宋诗','song-poetry','','[]','金殿春風策雋賢，上林弧矢更爭先。',64,'全唐诗/poet.song.124000.json','["金殿春風策雋賢，上林弧矢更爭先。", "不辭老懦聊推轂，要見飛騰總著鞭。", "勳業肇端登鳳沼，詞章接武侍甘泉。", "明年貢籍還增倍，定作東州盛事傳。"]'),
('a0a01392-ae5d-4943-9271-5f144415a2b7','立春感懷','韓元吉','宋','宋诗','song-poetry','','[]','南北驅馳老病身，不堪節物更催人。',64,'全唐诗/poet.song.124000.json','["南北驅馳老病身，不堪節物更催人。", "梅梢白白猶藏臘，蔬甲青青便作春。", "鐵馬漸欣邊塞靜，土牛還祝歲時新。", "聖朝文物從茲始，元日郊丘得上辛。"]'),
('dcb943bd-438e-449a-8154-259f0c713d40','喜雪','韓元吉','宋','宋诗','song-poetry','','[]','苦寒無那歲崢嶸，一夜陰風雪滿城。',64,'全唐诗/poet.song.124000.json','["苦寒無那歲崢嶸，一夜陰風雪滿城。", "莫問牛羊迂使節，却思鵝鴨溷軍聲。", "庭空賸喜羅琪樹，履敝猶堪步玉京。", "更碾新芽試湯火，從來冷淡是書生。"]'),
('b1506bc8-186d-47f9-9709-b3214b727c8a','元夕再用韵','韓元吉','宋','宋诗','song-poetry','','[]','瑶山直上玉梯橫，不用銀花散火城。',64,'全唐诗/poet.song.124000.json','["瑶山直上玉梯橫，不用銀花散火城。", "著柳共看飛絮動，打窗渾作亂蚊聲。", "路尋鸞鶴天疑近，石壅鯨鯢觀易京。", "便擬乘風跨滄海，更須新月趁潮生。"]'),
('b471dfea-e12b-417f-80f0-1765818006b4','春日','韓元吉','宋','宋诗','song-poetry','','[]','霏霏小雨映煙光，睡起文書正滿牀。',64,'全唐诗/poet.song.124000.json','["霏霏小雨映煙光，睡起文書正滿牀。", "芍藥倚階纔弄色，酴醿堆架漸吹香。", "林端好鳥猶相應，葉底殘花欲自藏。", "便覺春風如我老，須君駐世有奇方。"]'),
('366c9822-d0a1-4129-bb3e-4e9a526b998d','春日山中','韓元吉','宋','宋诗','song-poetry','','[]','杜陵愛飲覓南鄰，我亦顛狂不奈貧。',64,'全唐诗/poet.song.124000.json','["杜陵愛飲覓南鄰，我亦顛狂不奈貧。", "漸有好花宜過雨，應須美酒細酬春。", "十年鄉國無窮思，千里江湖未老身。", "莫向空中厭愁寂，杏梢桃葉一番新。"]'),
('3098dc0f-efed-4cef-9bae-57f52a6f7886','雨後睡起有懷','韓元吉','宋','宋诗','song-poetry','','[]','菊枝萱草亂庭隅，旋卷疏簾卧看書。',64,'全唐诗/poet.song.124000.json','["菊枝萱草亂庭隅，旋卷疏簾卧看書。", "枕簟凉生秋雨後，軒窗睡足晚風初。", "官閒自愛門無轍，計拙猶慚食有魚。", "莫遣功名心易老，只應湖海氣難除。"]'),
('31c3bcc5-c47b-4802-b893-189766bdbc90','夜坐聞窗下水聲','韓元吉','宋','宋诗','song-poetry','','[]','書史懸知伴此生，敢求身外百年名。',64,'全唐诗/poet.song.124000.json','["書史懸知伴此生，敢求身外百年名。", "青燈又暗吹窗雨，流水長聞入夜聲。", "玩世久忘榮辱累，定交諳盡死生情。", "翛然隠几焚香坐，不獨心清境亦清。"]'),
('d54ce30c-1e40-4331-b40a-d00701670dd4','曉霽再用前韵二首  其一','韓元吉','宋','宋诗','song-poetry','','[]','窗外幽花無數生，亂紅相映不知名。',64,'全唐诗/poet.song.124000.json','["窗外幽花無數生，亂紅相映不知名。", "長條自轉風前影，別壑還添雨後聲。", "閉戶苦無佳客語，披書聊慰古人情。", "詩成步逐山腰月，相對茅簷夜色清。"]'),
('f95aa4d1-d473-45cd-9de2-69ab4cae4ac8','曉霽再用前韵二首  其二','韓元吉','宋','宋诗','song-poetry','','[]','新筍成行嫩菊生，故人爲作小軒名。',64,'全唐诗/poet.song.124000.json','["新筍成行嫩菊生，故人爲作小軒名。", "十年敢有旌麾意，兩部空遺鼓吹聲。", "世事如塵紛過眼，風光和酒最關情。", "曲肱不作南柯夢，槐影陰陰枕簟清。"]'),
('3080a508-b8ce-4efe-89ab-a2e296f35ea8','七夕亞之置酒再用前韵','韓元吉','宋','宋诗','song-poetry','','[]','烏鵲無聲夜向闌，空庭插竹巧誰看。',64,'全唐诗/poet.song.124000.json','["烏鵲無聲夜向闌，空庭插竹巧誰看。", "長生殿裏金釵暖，百子池邊五縷寒。", "夢破清風吹雨脚，醉餘新月上林端。", "閒來不辨論時節，賸喜秋花共夕餐。"]'),
('d537b3bb-22ee-4791-9ddc-c5d5c534dbc3','九日獨酌','韓元吉','宋','宋诗','song-poetry','','[]','茱萸滿把半青紅，强擬登臨少客同。',64,'全唐诗/poet.song.124000.json','["茱萸滿把半青紅，强擬登臨少客同。", "碧樹池塘秋色裏，黄花時節雨聲中。", "官閒覓句能消日，酒薄看山尚怯風。", "高李故人今健否，一樽懷古意無窮。"]'),
('f42f4032-7e59-49f4-bbef-fcd27aa775e3','病中放言五首  其一','韓元吉','宋','宋诗','song-poetry','','[]','松窗永日度凉颸，坐覺清陰寸寸移。',64,'全唐诗/poet.song.124000.json','["松窗永日度凉颸，坐覺清陰寸寸移。", "境靜故應閒可樂，形臞猶有病相隨。", "塵埃末路思千里，風露何年飽一枝。", "百歲窮通吾自了，閉門長詠子桑詩。"]'),
('eac5117e-b1b6-4f08-b20d-159d7637d9c3','病中放言五首  其二','韓元吉','宋','宋诗','song-poetry','','[]','長夏空齋冷欲冰，幾愁無米溷鄰僧。',74,'全唐诗/poet.song.124000.json','["長夏空齋冷欲冰，幾愁無米溷鄰僧。", "途窮誰爲一舉手，計拙自宜三折肱。", "風靜鳶飛猶跕跕，日斜蚊聚已{甍瓦=羽}{甍瓦=羽}。", "此身示疾非吾病，卧看南山翠作層。"]'),
('c0e019cd-b428-46b6-82d0-74c79657a861','病中放言五首  其三','韓元吉','宋','宋诗','song-poetry','','[]','歲月催人易白頭，只應蝴蝶夢爲周。',64,'全唐诗/poet.song.124000.json','["歲月催人易白頭，只應蝴蝶夢爲周。", "跰𨇤久悟人間世，汗漫已期方外遊。", "化鶴自知迷故國，斷鼇今見立神州。", "蓬萊水淺君須記，蓮葉翩翩僅可舟。"]'),
('20ca73ea-e7d1-453b-964b-ebf0517394aa','病中放言五首  其四','韓元吉','宋','宋诗','song-poetry','','[]','寓意平生止墨卿，轉喉無奈觸錢神。',64,'全唐诗/poet.song.124000.json','["寓意平生止墨卿，轉喉無奈觸錢神。", "敢將名利期當世，直欲文章似古人。", "積雨尚添門外轍，顛風不掃甑間塵。", "倦游儻有凌雲賦，肯爲黄金巧致身。"]'),
('b78d8e28-2cab-4baf-a8c1-66ae7b9dd281','病中放言五首  其五','韓元吉','宋','宋诗','song-poetry','','[]','少日功名謂立成，壯年漂蕩已心驚。',64,'全唐诗/poet.song.124000.json','["少日功名謂立成，壯年漂蕩已心驚。", "正平只合依文舉，元亮何妨慕孔明。", "墓上征西真底用，生前杯酒未宜輕。", "田園待足何時足，歸赴空山猿鶴盟。"]'),
('f8720c67-57e0-4479-8be8-9b1aa5434503','有童子市龜七以百金得而放之','韓元吉','宋','宋诗','song-poetry','','[]','百金爲換七玄衣，自啟筠籠俯釣磯。',64,'全唐诗/poet.song.124000.json','["百金爲換七玄衣，自啟筠籠俯釣磯。", "白水真人聊並聘，清江使者遂同歸。", "負圖可但逢時出，曳尾寧須與世違。", "好去滄波莫回首，餘不亭下柳依依。"]'),
('745ee8fd-aa71-4c54-a352-175a2f1d46c5','記建安大水','韓元吉','宋','宋诗','song-poetry','','[]','孤城雨脚暮雲平，不覺魚龍自滿庭。',64,'全唐诗/poet.song.124000.json','["孤城雨脚暮雲平，不覺魚龍自滿庭。", "托命已甘同木偶，置身端亦似羸瓶。", "浮家却羨鴟夷子，弄月常憂太白星。", "當日乘槎便仙去，故人應罪曲江靈。"]'),
('7232ba59-9c52-410b-aaac-1979db477ef9','與蘇訓直約遊招隠寺  其一','韓元吉','宋','宋诗','song-poetry','','[]','十日春晴未放梅，籃輿端爲看山來。',64,'全唐诗/poet.song.124000.json','["十日春晴未放梅，籃輿端爲看山來。", "路尋絕壑空流水，寺倚蒼巖只廢臺。", "處士尚餘三畝宅，野僧合買萬松栽。", "故知佳興難爲敗，上盡西峰眼界開。"]'),
('eb8f79bd-4a2f-4436-89b5-00a4d05b712e','與蘇訓直約遊招隠寺  其二','韓元吉','宋','宋诗','song-poetry','','[]','鼙鼓初歸塞上師，京江酒美勝年時。',64,'全唐诗/poet.song.124000.json','["鼙鼓初歸塞上師，京江酒美勝年時。", "春來逆旅真無事，身到名山合有詩。", "石底於菟窮作穴，泉間科斗閙成池。", "荒寒景色君休問，後日應懷此客隨。"]'),
('9b65723b-b635-4be4-80b3-2eaa366a3f8a','雨中同伯恭至湖上','韓元吉','宋','宋诗','song-poetry','','[]','莫嫌鞭馬踏春泥，茶鼎詩囊偶共携。',64,'全唐诗/poet.song.124000.json','["莫嫌鞭馬踏春泥，茶鼎詩囊偶共携。", "山色雨深看更好，湖光烟接望還迷。", "連天花絮飛將盡，夾道蒲荷長欲齊。", "官事得閒須洗眼，蓬壺只在帝城西。"]'),
('09ecfb20-eaf7-48a5-80aa-716c5315cfa4','清明日雨中同中甫子雲二兄集湖上','韓元吉','宋','宋诗','song-poetry','','[]','莫辭沖雨濕春衣，要看湖山滴翠微。',64,'全唐诗/poet.song.124000.json','["莫辭沖雨濕春衣，要看湖山滴翠微。", "絮重欲飛堤柳暗，花寒無頼海棠稀。", "官忙未覺追遊少，醖美猶堪盡醉歸。", "屈指薰風來幾日，綠荷簪水已依依。"]'),
('2a3325d5-d2de-46f8-96f6-88c16146d9e1','清明後一日同諸友湖上值雨','韓元吉','宋','宋诗','song-poetry','','[]','出遊初不計陰晴，聊喜湖山信馬行。',64,'全唐诗/poet.song.124000.json','["出遊初不計陰晴，聊喜湖山信馬行。", "弱柳自隨烟際綠，幽花還傍雨邊明。", "嫩蒲碧水人家好，密竹疏松野寺清。", "爛醉一春纔幾日，可無佳景付詩情。"]'),
('55842bf9-713b-4ee4-b350-320c44511cee','元夔以詩留別用韵示之  其一','韓元吉','宋','宋诗','song-poetry','','[]','密竹疏松一水邊，高舂自占曲肱眠。',64,'全唐诗/poet.song.124000.json','["密竹疏松一水邊，高舂自占曲肱眠。", "心如古井真無浪，跡似寒灰豈復然。", "舌在未應甘寂寞，地偏猶可小回旋。", "春風又綠池塘草，清夢從今只惠連。"]'),
('3cbfac02-078c-4c9d-814f-30a1ab3b8c4d','元夔以詩留別用韵示之  其二','韓元吉','宋','宋诗','song-poetry','','[]','淵明遶屋樹扶疏，大似蓬蒿仲蔚居。',64,'全唐诗/poet.song.124000.json','["淵明遶屋樹扶疏，大似蓬蒿仲蔚居。", "老矣强營三徑菊，閒來未厭五車書。", "詩成歎我同招隠，賦就須君敵子虛。", "努力青雲家世事，他年簪筆待嚴徐。"]'),
('564c557a-2a5d-4d52-afc2-11d04bd5738b','清明前一日與客自光孝登般若菴觀鐵塔舊基因至鐵獅頂','韓元吉','宋','宋诗','song-poetry','','[]','青鞵藜杖破層雲，勝日猶能眼界新。',64,'全唐诗/poet.song.124000.json','["青鞵藜杖破層雲，勝日猶能眼界新。", "窣堵已摧豪士手，狻猊猶現法王身。", "寺藏松竹疑無地，路接烟霄不到塵。", "車馬憧憧城市客，舉頭相望幾由旬。"]'),
('5206180f-8512-40d5-a9b0-0db9c298cc0f','夜宿斜溪聞杜鵑','韓元吉','宋','宋诗','song-poetry','','[]','船窗初日弄暉暉，起坐胡牀自攬衣。',64,'全唐诗/poet.song.124000.json','["船窗初日弄暉暉，起坐胡牀自攬衣。", "無數青山隨岸改，幾聲幽鳥喚人歸。", "鷗盟好在重遊戲，蝶夢驚回果是非。", "便擬走書聞稚子，歸來同買釣魚磯。"]'),
('24408236-2436-4738-8ab5-921ca2624f6f','過武夷','韓元吉','宋','宋诗','song-poetry','','[]','不到仙山二十年，道人雙鬢亦皤然。',64,'全唐诗/poet.song.124000.json','["不到仙山二十年，道人雙鬢亦皤然。", "却看翠嶺千尋石，又汎清溪九曲船。", "目極已高聊自喜，身輕欲上可無緣。", "只應猿鶴遥相認，笑我歸耕未有田。"]'),
('ceed4e4e-308e-4596-a6ff-2a271ef222ce','雨中望靈山呈明遠','韓元吉','宋','宋诗','song-poetry','','[]','騎曹公事日紛紛，荀令香爐欲罷薰。',64,'全唐诗/poet.song.124000.json','["騎曹公事日紛紛，荀令香爐欲罷薰。", "冷雨定知還作雪，好山無奈只藏雲。", "看花便覺名何用，勸酒誰能耳不聞。", "歲晚官倉塵滿眼，只應清坐獨輸君。"]'),
('00f15f3a-9147-41be-82d3-57779d562cf8','陪曾吉甫遊中山','韓元吉','宋','宋诗','song-poetry','','[]','去天尺五城南寺，目極層軒得此遊。',64,'全唐诗/poet.song.124000.json','["去天尺五城南寺，目極層軒得此遊。", "山闊雨收雲點綴，江清日淡柳風流。", "僧扉繚繞牛鳴地，樓閣參差斗大州。", "公自蓬萊舊仙伯，一麾真復占鼇頭。"]'),
('f6348b82-3d0d-4428-98dd-4e72f255ad66','勸耕至赤松山','韓元吉','宋','宋诗','song-poetry','','[]','謬誤君恩再領州，名山猶幸復春遊。',64,'全唐诗/poet.song.124000.json','["謬誤君恩再領州，名山猶幸復春遊。", "苦無羽客追元放，尚有羣兒識細侯。", "麥穗雨晴迷野岸，桃花風急滿溪流。", "隔林布穀如相應，更酌丹泉爲少留。"]'),
('fffabee3-e9f7-4353-89b0-7bbc2a3226b2','自天封登華頂將自桐柏以歸土人謂之望海尖','韓元吉','宋','宋诗','song-poetry','','[]','連天松影轉崔嵬，夾道桃花迤邐開。',64,'全唐诗/poet.song.124000.json','["連天松影轉崔嵬，夾道桃花迤邐開。", "便覺胸中有東海，不知脚底是三台。", "閒雲自作千峰雨，流水真成萬壑雷。", "喚起吹笙王子晉，夜深乘月上瓊臺。"]'),
('87d10adb-3924-4379-ae35-e558ec87c36a','望卞山懷石林翁','韓元吉','宋','宋诗','song-poetry','','[]','卞山苕水共蒼蒼，中有先生萬石堂。',64,'全唐诗/poet.song.124000.json','["卞山苕水共蒼蒼，中有先生萬石堂。", "早歲英名類終賈，暮年眉壽到劉楊。", "人琴遂欲成千載，雞酒猶能酹一觴。", "身後遺編尚塵積，豐碑誰復付中郎。"]'),
('e9ea753c-64cf-48d9-9951-38f6af8c3596','遊鹿田寺','韓元吉','宋','宋诗','song-poetry','','[]','路轉崔嵬第一峰，兩仙迎我度空濛。',64,'全唐诗/poet.song.124000.json','["路轉崔嵬第一峰，兩仙迎我度空濛。", "不知屨躡青霄上，但覺身行紺霧中。", "隴麥正隨高下綠，山花猶作淺深紅。", "極知靈運真任守，蠟屐穿林興未窮。"]'),
('f4610564-bafa-4068-9f1b-18769957ffaa','同葉夢錫趙德莊遊牛首山','韓元吉','宋','宋诗','song-poetry','','[]','不辭扶病觸春寒，及此新晴一日閒。',64,'全唐诗/poet.song.124000.json','["不辭扶病觸春寒，及此新晴一日閒。", "雲外經年見雙闕，馬頭乘興數前山。", "清泉細酌巉巖上，佛窟同探紫翠間。", "我亦無心話禪悅，銜花百鳥自飛還。"]'),
('d7a17f7f-903c-4d65-a30e-cc7c1caf5743','寶林院次韓廷玉韵','韓元吉','宋','宋诗','song-poetry','','[]','山繞孤城水拍空，惜無殘月照疏桐。',64,'全唐诗/poet.song.124000.json','["山繞孤城水拍空，惜無殘月照疏桐。", "江干雲斷夜來雨，木末凉生秋到風。", "六代興亡知寺古，老禪神異載碑豐。", "詩成極目蒼茫裏，惜別情懷醉夢中。"]'),
('4d1294b4-4416-4f6d-9eb6-fb6497043830','會稽道中有感','韓元吉','宋','宋诗','song-poetry','','[]','稠紅亂紫正芳菲，寒食青門客自歸。',64,'全唐诗/poet.song.124000.json','["稠紅亂紫正芳菲，寒食青門客自歸。", "江上酒醒聞燕語，日斜睡足看花飛。", "功名老去真何在，丘壑平生豈願違。", "尚喜繫船探禹穴，稽山雲淡雨霏霏。"]'),
('c41ae06c-ee18-4ee3-8d7c-2b0ac294c61d','九華道中','韓元吉','宋','宋诗','song-poetry','','[]','行人脚底不生塵，絕壁仙凡路已分。',64,'全唐诗/poet.song.124000.json','["行人脚底不生塵，絕壁仙凡路已分。", "一水奔騰崖覆雪，九峰羅立岫填雲。", "謫仙才大三千首，國老謀深十萬軍。", "莫對青山歎華髮，丹砂未就又論文。"]'),
('954c5b87-6951-4c20-a372-5a97f0bb6c71','至日建德道中','韓元吉','宋','宋诗','song-poetry','','[]','聖皇初款帝中壇，羽檄交馳玉仗寒。',64,'全唐诗/poet.song.124000.json','["聖皇初款帝中壇，羽檄交馳玉仗寒。", "佳節又看當警急，勞生底用較悲懽。", "腐儒憂國成千慮，强敵窺人詎一端。", "夢想淮南風雪裏，可無消息報平安。"]'),
('0863736b-1df3-4eb8-b625-28f9988dd643','葉丞相最高亭','韓元吉','宋','宋诗','song-poetry','','[]','丞相園林景物繁，花亭那更得躋攀。',64,'全唐诗/poet.song.124000.json','["丞相園林景物繁，花亭那更得躋攀。", "平看溪上千尋木，不數城南萬疊山。", "歌舞恍如銀漢外，笑談常在碧雲間。", "醉酣欲問劉公客，百尺樓中亦汗顔。"]'),
('69ce60cf-81fd-4803-b807-6fe999a0b36b','賞心亭','韓元吉','宋','宋诗','song-poetry','','[]','北風吹雨冷如秋，更上江干百尺樓。',64,'全唐诗/poet.song.124000.json','["北風吹雨冷如秋，更上江干百尺樓。", "瓊樹佳人閉黄壤，石城華屋變滄洲。", "三峰已覺蓬萊近，二水真成汗漫遊。", "六代風光幾人物，不妨擁鼻向南州。"]'),
('de709f96-c4a9-44f3-9e9d-706aee2b5b3b','重建極目亭','韓元吉','宋','宋诗','song-poetry','','[]','曲闌十里畫屏開，氣壓凌歊百仞臺。',64,'全唐诗/poet.song.124000.json','["曲闌十里畫屏開，氣壓凌歊百仞臺。", "不盡溪光空外見，無窮山色望中來。", "旋規北檻栽新竹，更闢東窗對野梅。", "老子興來真不淺，清秋忍負十分杯。"]'),
('9a41a749-9285-4d0a-b7f6-2633b0069beb','次韵張子儀倉司展翠亭','韓元吉','宋','宋诗','song-poetry','','[]','官事常忙心自閒，故應拄笏爲西山。',64,'全唐诗/poet.song.124000.json','["官事常忙心自閒，故應拄笏爲西山。", "舉頭但覺來風月，著足何妨涉闠闤。", "振廩功成聊共醉，追鋒詔下合俱還。", "須知蒼翠看無盡，輸我巖居晝掩關。"]'),
('00dda8b4-7283-4685-9732-1b1ee75268d3','晚登凌風亭戲作','韓元吉','宋','宋诗','song-poetry','','[]','咄咄真成了事癡，功名何在鬢霜垂。',64,'全唐诗/poet.song.124000.json','["咄咄真成了事癡，功名何在鬢霜垂。", "清談安得如夷甫，佳句無勞發愷之。", "山色倚江秋更好，煙光連市晚偏宜。", "田園底許歸能决，且擷黄花付酒巵。"]'),
('a3607ca6-2bd9-46bd-af42-1ce0b22519ca','再至凌風亭','韓元吉','宋','宋诗','song-poetry','','[]','目盡西山落照邊，危亭風景故依然。',64,'全唐诗/poet.song.124000.json','["目盡西山落照邊，危亭風景故依然。", "重來身忝二千石，老去心驚十九年。", "種柳已高丹檻外，栽花猶占綠窗前。", "不堪素髮紛垂領，還愧青春令尹賢。"]'),
('153a801b-c21a-4e23-9c07-340cf3fac779','題長春亭','韓元吉','宋','宋诗','song-poetry','','[]','一徑清深不起塵，芳菲紅紫意隨人。',64,'全唐诗/poet.song.124000.json','["一徑清深不起塵，芳菲紅紫意隨人。", "應知地勝無非景，但有花開即是春。", "萱草自隨蘭葉茂，棠花還與桂枝新。", "綵衣兄弟人生樂，莫惜支筇步武頻。"]'),
('050f3c0b-7e32-44a2-96e6-229b7dcccaab','題蒼筤亭','韓元吉','宋','宋诗','song-poetry','','[]','手種蒼筤數百竿，築亭相與枕書看。',64,'全唐诗/poet.song.124000.json','["手種蒼筤數百竿，築亭相與枕書看。", "故知落落非春事，直有青青共歲寒。", "一壑自欣幽意足，三年獨得此君歡。", "蕭然風露千尋影，搔首哦詩獨凭欄。"]'),
('3e410e8e-67d1-4e5a-9696-552e6daed408','采箬亭','韓元吉','宋','宋诗','song-poetry','','[]','山繚重城水拍堤，雨晴秋浦靜相宜。',64,'全唐诗/poet.song.124000.json','["山繚重城水拍堤，雨晴秋浦靜相宜。", "新篁弄日千竿玉，紋簟披風八尺漪。", "坐對芳洲端自樂，興來小艇亦頻移。", "他年穩侍蓬萊殿，聊記高亭一笑時。"]'),
('afdfa61d-2a9f-492c-89c5-596cd8752871','晝寒亭','韓元吉','宋','宋诗','song-poetry','','[]','月裏瓊宮不禁寒，誰令白晝墮人間。',64,'全唐诗/poet.song.124000.json','["月裏瓊宮不禁寒，誰令白晝墮人間。", "陰風淅淅來深谷，晴雪霏霏濺兩山。", "靜愛飛流聊洗耳，坐看絕磴可怡顔。", "紅塵熱客那知此，赤脚青松意自閒。"]'),
('79c0cdd9-4f7a-4bde-bc85-f7c9e47f3579','凌歊臺','韓元吉','宋','宋诗','song-poetry','','[]','山到西江勢却回，倚山樓殿更高臺。',64,'全唐诗/poet.song.124000.json','["山到西江勢却回，倚山樓殿更高臺。", "天容水色望中見，帆影車塵空際來。", "桑柘棋分千里迥，波濤壁立兩峰開。", "登臨擬問興亡事，白塔亭亭鎖翠苔。"]'),
('04940b02-2717-49ff-a167-51645e2516c5','蓬瀛臺','韓元吉','宋','宋诗','song-poetry','','[]','雨餘天宇澹澄瀛，及此秋郊一日晴。',64,'全唐诗/poet.song.124000.json','["雨餘天宇澹澄瀛，及此秋郊一日晴。", "軒蓋翩翩度林影，笙簫隠隠雜溪聲。", "風隨廣席歌呼轉，雲滿高臺步武生。", "記取今年作重九，丹崖絕壑是神清。"]'),
('8d06ac90-93b6-4341-8910-1faa78df7fa2','錢伯同新創明暉閣','韓元吉','宋','宋诗','song-poetry','','[]','使君談笑兩橋成，人向晴虹鏡裏行。',64,'全唐诗/poet.song.124000.json','["使君談笑兩橋成，人向晴虹鏡裏行。", "更闢軒窗待遊覽，要看山水倍澄明。", "波寬十頃知魚樂，歲熟千家響碓聲。", "收拾風光付華月，一樽還記昔文清。"]'),
('df82ed09-a952-4408-88bd-0615284d6e1f','題金元鼎至樂堂','韓元吉','宋','宋诗','song-poetry','','[]','百歲休論七十稀，羨君林壤得熙怡。',64,'全唐诗/poet.song.124000.json','["百歲休論七十稀，羨君林壤得熙怡。", "賦歸已久同元亮，至樂真能慕啟期。", "一壑過人聊自足，萬鍾于我亦何思。", "故應不羨紆朱貴，带索行歌世未知。"]'),
('294571fd-d938-4fa0-b811-7d4358b19639','題十二兄野堂','韓元吉','宋','宋诗','song-poetry','','[]','少年行樂記鄉關，月渚霞洲一夢間。',64,'全唐诗/poet.song.124000.json','["少年行樂記鄉關，月渚霞洲一夢間。", "爲愛軒窗臨野水，只疑風景是家山。", "荷香柳影情偏厚，竹色松聲意自閒。", "堪笑主翁持節手，却來垂釣傍蒼灣。"]'),
('5cfffd1c-cd5f-4a30-b383-21ce3c5f7c70','韓子師讀書堂置酒見留','韓元吉','宋','宋诗','song-poetry','','[]','酴醿插架未成陰，水滿方塘數尺深。',64,'全唐诗/poet.song.124000.json','["酴醿插架未成陰，水滿方塘數尺深。", "入戶幽花真有意，拂簷高竹更關心。", "鳴禽喚客知閒景，舞鶴迎人作好音。", "莫道相逢欠歌管，一觴酒盡讀書林。"]'),
('7e828c14-3a26-4fc5-97aa-ca28f2492f3d','山橋','韓元吉','宋','宋诗','song-poetry','','[]','倚杖溪橋暮雨垂，春寒空翠著人衣。',64,'全唐诗/poet.song.124000.json','["倚杖溪橋暮雨垂，春寒空翠著人衣。", "凌空怪石如旗豎，噴壑清泉作練飛。", "乘興正須隨地飲，醉狂聊共插花歸。", "從教拍手兒童笑，要是山深客到稀。"]'),
('a1b945ea-51e7-4cbd-a6d0-b49d063310ba','范良臣見過云有食粥之憂以斛米助之因得長句','韓元吉','宋','宋诗','song-poetry','','[]','捄饑豈復衛文子，闕食尚憐顔魯公。',64,'全唐诗/poet.song.124000.json','["捄饑豈復衛文子，闕食尚憐顔魯公。", "定知啜粥可餬口，未至復疾號山芎。", "東方千牘羨飽死，顔氏一瓢嗟屢空。", "我家無錢但斛粟，與子共坐詩能窮。"]'),
('f1501721-a3d4-4af7-9ceb-aa23c00d1785','伏日諸君小集沈明遠以小疾不預作詩戲之','韓元吉','宋','宋诗','song-poetry','','[]','廣文官冷酒錢空，平日清樽一笑同。',64,'全唐诗/poet.song.124000.json','["廣文官冷酒錢空，平日清樽一笑同。", "苦憶車公來座上，翻成王老隠牆東。", "定中示病應非病，詩裏能窮有底窮。", "凉月滿天新雨足，試憑檄語愈頭風。"]'),
('013363b8-50ed-482b-b639-a22161fb67a6','聞吳端朝作真率集','韓元吉','宋','宋诗','song-poetry','','[]','他年曾作社中人，骯髒歸來白髮新。',64,'全唐诗/poet.song.124000.json','["他年曾作社中人，骯髒歸來白髮新。", "闊別常思共杯酌，舊交那得更比鄰。", "黄雞白酒可勞勸，青笋烏椑未絕貧。", "恨不從君語終夕，空齋愁坐獨傷神。"]'),
('08a33c54-4306-4769-8609-c48adc748408','令防得女招飲以病不往走筆戲之','韓元吉','宋','宋诗','song-poetry','','[]','平生諸女重吾貧，敢意君家亦效顰。',64,'全唐诗/poet.song.124000.json','["平生諸女重吾貧，敢意君家亦效顰。", "醜惡未妨攘盜賊，長成難議卜比鄰。", "遥憐四十稱郎罷，豈惜千金辦主人。", "美酒尚須留待我，明年應見玉麒麟。"]'),
('1036d4ae-6ad8-4dd7-9647-ebcc867eb234','次韵陳子象謝新火詩','韓元吉','宋','宋诗','song-poetry','','[]','曲水流觴迹易陳，水邊那復御厨珍。',64,'全唐诗/poet.song.124000.json','["曲水流觴迹易陳，水邊那復御厨珍。", "茶煙永日看輕颺，槐火今年又一新。", "鄰舍未應煩束縕，官庖猶幸有輿薪。", "須公更試長檠夜，賸照歌臺拂鏡塵。"]'),
('4bce5669-e05a-4866-97dd-779f907c14d3','李彭元携曾吉甫詩卷數帖見過','韓元吉','宋','宋诗','song-poetry','','[]','十年松竹暗茶山，君有詩聲舊將壇。',64,'全唐诗/poet.song.124000.json','["十年松竹暗茶山，君有詩聲舊將壇。", "食薺誰如東野苦，無氈不奈廣文寒。", "閉門久詠高軒過，彈鋏今嗟行路難。", "我亦凋零舊賓客，遺編聊共拂塵看。"]'),
('ce5069f7-2665-4384-b37b-c996e8647598','李子永惠道中詩卷','韓元吉','宋','宋诗','song-poetry','','[]','踏雪衝寒徧幾州，豈妨乘興作清遊。',64,'全唐诗/poet.song.124000.json','["踏雪衝寒徧幾州，豈妨乘興作清遊。", "風橫白鷺歌瓊樹，月滿青山問釣舟。", "夢繞征途渾歷歷，老諳世事總悠悠。", "塵埃鞅掌君休恨，自有詩輕萬戶侯。"]'),
('97714295-f030-4696-b611-6bc1202e330d','熊子復惠十詩作長句謝之','韓元吉','宋','宋诗','song-poetry','','[]','白首相期翰墨中，衰齡況是甲庚同。',64,'全唐诗/poet.song.124000.json','["白首相期翰墨中，衰齡況是甲庚同。", "久懷妙論傳犀麈，尚喜清詩附驛筒。", "柳長五株知訟少，麥呈兩穗報年豐。", "去天一握歸來近，密令疇庸可拜公。"]'),
('255ba722-e8cc-4179-93ca-0d581b5ac5cb','姜特立寄近詩','韓元吉','宋','宋诗','song-poetry','','[]','雙溪巖曲蘆江岸，每見君詩句益奇。',64,'全唐诗/poet.song.124000.json','["雙溪巖曲蘆江岸，每見君詩句益奇。", "漸喜青雲今得路，豈妨白雪尚摛詞。", "斷蛟入海功何壯，披腹排雲世共知。", "斫却月中丹桂手，朝陽應占鳳凰枝。"]'),
('95bf7c8b-1ead-4851-97f8-9906f50912f7','周航定國携諸公所贈詩求次韵','韓元吉','宋','宋诗','song-poetry','','[]','拾青紫本一經明，得失由來信可驚。',64,'全唐诗/poet.song.124000.json','["拾青紫本一經明，得失由來信可驚。", "美玉固應人未識，千鈞何自俗能輕。", "馬曹寂寞心空在，驥子昂藏骨更清。", "穩步煙霄遲速耳，筆端夢覺已花生。"]'),
('f92f9410-90d3-404f-9245-a151b8e98126','季元衡寄示三池戲藁','韓元吉','宋','宋诗','song-poetry','','[]','文彩風流冠一時，三池聊作鳳凰池。',64,'全唐诗/poet.song.124000.json','["文彩風流冠一時，三池聊作鳳凰池。", "新詩到處傳桐葉，麗唱他年滿竹枝。", "歸夢故應懷古括，清談還喜對峨眉。", "玉堂待草山東詔，解纜春江莫放遲。"]'),
('2a6abb23-85b1-4937-a67b-45e6cfe022e8','曾丰惠文編','韓元吉','宋','宋诗','song-poetry','','[]','簿領裝懷筆擁塵，經年舌强不論文。',64,'全唐诗/poet.song.124000.json','["簿領裝懷筆擁塵，經年舌强不論文。", "跫然步武心還喜，籍甚聲華耳舊聞。", "曲水賦詩須鮑謝，甘泉第頌憶淵雲。", "相期穩上芸香閣，要策清時翰墨勳。"]'),
('860f2de6-33ec-4fa3-9bf0-5d4b44172b22','徐應祺惠文編','韓元吉','宋','宋诗','song-poetry','','[]','渴雨空齋晝不眠，疏簾竹簟意翛然。',64,'全唐诗/poet.song.124000.json','["渴雨空齋晝不眠，疏簾竹簟意翛然。", "借君妙語清袢暑，起我衰悰似壯年。", "得意每看雄霓句，逢時會奏白雲篇。", "漢庭久重春秋學，凌厲煙霄更著鞭。"]'),
('643c5a87-7338-47d4-bb4a-fd632ece73b9','寄懷子雲兄','韓元吉','宋','宋诗','song-poetry','','[]','長年游宦已堪嗟，寓舍無田豈是家。',64,'全唐诗/poet.song.124000.json','["長年游宦已堪嗟，寓舍無田豈是家。", "母子分飛還歲換，弟兄相望各天涯。", "塵埃閲世丹心在，朱墨縈人兩鬢華。", "聞道過庭新哭鯉，開書空有淚橫斜。"]'),
('5b1beff9-1d5f-461e-9abb-4bdcbea96e25','赴信幕寄子雲叔㬇及同寺  其一','韓元吉','宋','宋诗','song-poetry','','[]','田園未辦各身謀，兄弟今成迭去留。',64,'全唐诗/poet.song.124000.json','["田園未辦各身謀，兄弟今成迭去留。", "游宦三年方啟足，寄書千字又從頭。", "白雲不定山容晚，碧水無窮樹色秋。", "回首寺橋同社客，想因明月話離愁。"]'),
('775e8948-b6c3-46ee-be47-945073adee0b','赴信幕寄子雲叔㬇及同寺  其二','韓元吉','宋','宋诗','song-poetry','','[]','謝三船上醉同歸，黄四花邊手屢携。',64,'全唐诗/poet.song.124000.json','["謝三船上醉同歸，黄四花邊手屢携。", "巷裏何曾異南北，屋頭還復記東西。", "一杯相屬情猶在，千里分飛意自迷。", "堂下秋來足萱草，定傾家釀飫黄雞。"]'),
('a6cb3eb9-2f74-49e7-b6a6-066a9459524e','初至上饒寄子雲','韓元吉','宋','宋诗','song-poetry','','[]','險阻艱難客路賒，東西南北問生涯。',64,'全唐诗/poet.song.124000.json','["險阻艱難客路賒，東西南北問生涯。", "秋聲瑟縮生梧葉，野景蕭疏上菊花。", "去國已驚身老大，無家空有淚橫斜。", "遥知載酒齊山寺，應憶年時醉月華。"]'),
('6be19733-4959-44f0-babd-cdc7135a7a5b','寄梁士衡','韓元吉','宋','宋诗','song-poetry','','[]','江上潮聲日夜來，相望蹤跡共塵埃。',64,'全唐诗/poet.song.124000.json','["江上潮聲日夜來，相望蹤跡共塵埃。", "亂花洗雨紅成陣，疊嶂連天翠作堆。", "山市放歌知屢醉，沙津獨步想千回。", "松林月出溪橋夜，猶憶當年對野梅。"]'),
('48602d07-5abc-42da-bb2b-d3986a053e68','夜坐有感寄子雲','韓元吉','宋','宋诗','song-poetry','','[]','風景新亭舊往還，誰能舉目較河山。',64,'全唐诗/poet.song.124000.json','["風景新亭舊往還，誰能舉目較河山。", "宦情老去秋多感，官事忙時夜始閒。", "窗外槁梧風瑟縮，竹間亂石雨淙潺。", "青燈已作江湖夢，同約歸期早晚間。"]'),
('5c6921c7-b379-4d0a-9acf-0355d89e0c7d','過龐祐甫','韓元吉','宋','宋诗','song-poetry','','[]','半畝方園水到門，地偏人靜恰如村。',64,'全唐诗/poet.song.124000.json','["半畝方園水到門，地偏人靜恰如村。", "聲名不用卿王衍，文字真能僕屈原。", "舉世知君如我少，平生學道欲誰論。", "何時共結柴桑社，籬下秋來菊正繁。"]'),
('2f2a989c-8292-4dd9-9f6a-45fc2edf4b8e','劉子淵監廟年八十六耳目聰明能飲酒舉大白喜賦詩比過之因示長句次其韵','韓元吉','宋','宋诗','song-poetry','','[]','才疏政拙愧能名，黄髮猶欣見老成。',64,'全唐诗/poet.song.124000.json','["才疏政拙愧能名，黄髮猶欣見老成。", "林壤固知聊自樂，門閭要是已堪旌。", "持盃瀲灧千眉聳，落筆縱橫四坐驚。", "笳鼓過君應一笑，平田兩部足蛙聲。"]'),
('516055ad-f573-48d7-8e46-2c766adf63e3','過趙仲縝','韓元吉','宋','宋诗','song-poetry','','[]','山下清溪溪上亭，竹陰芳徑眼增明。',64,'全唐诗/poet.song.124000.json','["山下清溪溪上亭，竹陰芳徑眼增明。", "已知數日逢寒食，賸喜今朝作好晴。", "酒美故應容客醉，歌長不自覺詩成。", "春深準擬多行樂，却作花前送我行。"]'),
('8d5df7d4-bdcf-4e37-9bbe-46f2f086af9a','秋雨新霽過趙慎中留飲','韓元吉','宋','宋诗','song-poetry','','[]','門外黄塵有底忙，主人高卧興何長。',64,'全唐诗/poet.song.124000.json','["門外黄塵有底忙，主人高卧興何長。", "春風竹樹簫笙轉，雨足軒窗笑語凉。", "耳熱漫思官裏事，眼明猶識醉時粧。", "紫雲莫厭頻來客，未抵當年御史狂。"]'),
('ebef6c6e-94c0-4151-93a0-e07db939f74e','陸務觀赴闕經從留飲','韓元吉','宋','宋诗','song-poetry','','[]','溪岸風高霜作棱，杯盤草草對青燈。',64,'全唐诗/poet.song.124000.json','["溪岸風高霜作棱，杯盤草草對青燈。", "已甘鹽菜待梁柳，況有酒漿延杜陵。", "歲晚鬢毛紛似雪，天寒門巷冷于冰。", "春風穩送金閨步，看躡鰲山最上層。"]'),
('1d721e6e-3b7b-43d1-b43a-b093d4e3b645','寄徐滁州埻立','韓元吉','宋','宋诗','song-poetry','','[]','青瑣金鸞跡未容，寘公猶在昔賢中。',64,'全唐诗/poet.song.124000.json','["青瑣金鸞跡未容，寘公猶在昔賢中。", "著書定已追迂叟，得郡何妨號醉翁。", "豐樂橋邊魚動鏡，清流關下馬嘶風。", "獨憐湛輩猶奔走，不得登臨一笑同。"]'),
('2506532f-bce0-4d5d-a34d-fe27a1f94ad9','寄別子雲','韓元吉','宋','宋诗','song-poetry','','[]','江干風雪敝貂裘，兄弟相看已白頭。',64,'全唐诗/poet.song.124000.json','["江干風雪敝貂裘，兄弟相看已白頭。", "兩月追隨無十日，一春離別甚三秋。", "清時官職難頻竊，異縣田園合早求。", "並戲母前端有日，省郎雖美不如州。"]'),
('f38d9cfa-1bae-4903-9581-60f186d6e27d','次韵沈駒甫留別','韓元吉','宋','宋诗','song-poetry','','[]','筆下縱橫自學林，胸中玉海更清深。',64,'全唐诗/poet.song.124000.json','["筆下縱橫自學林，胸中玉海更清深。", "識君異縣見眉宇，過我空山聆足音。", "月近中秋還惜別，雪飛窮臘會重臨。", "閑門剝啄誰相問，與客寧論舊與今。"]'),
('0791cbc1-58a5-433e-b3c1-e9afa27a27b9','別范元卿','韓元吉','宋','宋诗','song-poetry','','[]','晴林綠樹越江邊，聊泊東來倦客船。',64,'全唐诗/poet.song.124000.json','["晴林綠樹越江邊，聊泊東來倦客船。", "風引花香微近酒，水浮月色澹連天。", "驚心朋舊皆千里，回首光陰又五年。", "莫笑相逢便離別，此生身計已飄然。"]'),
('f3e52fa0-c6d9-42eb-9b37-61a58580150e','松江別范至能朱伯陽  其一','韓元吉','宋','宋诗','song-poetry','','[]','彈鋏功名易白頭，歸歟未辦五湖舟。',64,'全唐诗/poet.song.124000.json','["彈鋏功名易白頭，歸歟未辦五湖舟。", "送君與我皆爲守，到處逢山且縱遊。", "薄日連雲千幛曉，斜風吹雨一江秋。", "買魚斫鱠垂虹上，更爲今年好景留。"]'),
('ab2f75c2-a405-4e27-b597-38ad74493249','松江別范至能朱伯陽  其二','韓元吉','宋','宋诗','song-poetry','','[]','吳歈灣月韵江船，屈指同行二十年。',64,'全唐诗/poet.song.124000.json','["吳歈灣月韵江船，屈指同行二十年。", "勝日五湖看老矣，倦游雙鬢各蒼然。", "擬尋詩酒平生社，未了塵埃薄宦緣。", "後夜西風相憶夢，琵琶亭下水籠烟。"]'),
('963f9dde-0a1d-4e48-ae76-1a6dae97145c','留別傅安道  其一','韓元吉','宋','宋诗','song-poetry','','[]','華髮相看四十年，飽諳世事欲忘言。',64,'全唐诗/poet.song.124000.json','["華髮相看四十年，飽諳世事欲忘言。", "一春離別當寒食，再歲追隨作上元。", "湖外溪山明小檻，雨餘花柳暗西園。", "極知老大交朋少，相與論文更一樽。"]'),
('e4b0b57b-3c61-4f68-bf1b-9de322bc5891','留別傅安道  其二','韓元吉','宋','宋诗','song-poetry','','[]','場屋俱爲拜賜師，烟霄獨喜鳳毛飛。',64,'全唐诗/poet.song.124000.json','["場屋俱爲拜賜師，烟霄獨喜鳳毛飛。", "壯心似鐵何曾老，健筆如椽合一揮。", "北渚青山勞我夢，西垣紅藥待君歸。", "詔環不作經時隔，沙路薰風卷繡衣。"]'),
('a570a7b2-1d0d-4f20-9b70-16d9773bc729','送湯丞相帥會稽  其一','韓元吉','宋','宋诗','song-poetry','','[]','淮岸春來罷夕烽，君王奏凱大明宮。',64,'全唐诗/poet.song.124000.json','["淮岸春來罷夕烽，君王奏凱大明宮。", "守關豈但勤蕭相，分陝猶宜屈召公。", "綵綬不妨龍衮貴，錦衣真與故鄉同。", "政成更上平戎略，歸作麒麟第一功。"]'),
('f66d447b-cbec-4a3b-a9b0-30f56e3b9dca','送湯丞相帥會稽  其二','韓元吉','宋','宋诗','song-poetry','','[]','翰墨英名多士先，經綸長策萬方傳。',64,'全唐诗/poet.song.124000.json','["翰墨英名多士先，經綸長策萬方傳。", "久知燕許文章大，要自臯夔事業賢。", "曲水蘭亭脩竹外，都門祖帳百花前。", "去天尺五調元舊，肯使邦人借一年。"]'),
('93ce5fa6-44c3-4463-ac42-386460bfc0c1','送湯丞相帥會稽  其三','韓元吉','宋','宋诗','song-poetry','','[]','疇昔追風幸執鞭，詞場好在筆如椽。',64,'全唐诗/poet.song.124000.json','["疇昔追風幸執鞭，詞場好在筆如椽。", "十年睎驥猶瞠若，晚歲登龍未偶然。", "下客陽春驚白雪，何人綠水近紅蓮。", "尚應九里蒙河潤，他日一天今二天。"]'),
('3a6ca9e1-e652-4415-bab3-c4adcec24a7a','送周承勛赴荆南幕','韓元吉','宋','宋诗','song-poetry','','[]','周南留滯幾年餘，筆力追還兩漢初。',64,'全唐诗/poet.song.124000.json','["周南留滯幾年餘，筆力追還兩漢初。", "無地寘君羣玉府，因人貽我萬金書。", "未嗟王粲依油幕，聊喜安仁奉板輿。", "夢想風帆轉平楚，眼明江樹綠扶疏。"]'),
('63f7dac6-d151-4116-8add-32823546a7c2','送馬莊甫攝幕鄱陽用趙文鼎韵','韓元吉','宋','宋诗','song-poetry','','[]','杖策衝寒不作難，弓刀結束笑談間。',64,'全唐诗/poet.song.124000.json','["杖策衝寒不作難，弓刀結束笑談間。", "便從幕府清民訟，已佐戎車靖蜑蠻。", "風雪幸無千里路，江湖纔隔數重山。", "荆南桃李新開徑，屈指春融及早還。"]'),
('ad0bfd6e-8593-4728-ae6c-9596676ba8d3','送陳天與知徽州','韓元吉','宋','宋诗','song-poetry','','[]','臺閣英名二十年，卜居那得便林泉。',64,'全唐诗/poet.song.124000.json','["臺閣英名二十年，卜居那得便林泉。", "履聲舊振星辰上，諫墨猶存雨露邊。", "欲考治功三府近，且施惠政一州先。", "黄山看盡須黄閣，六月天池更著鞭。"]'),
('e8327ec6-1269-4cf8-9dad-df9e516fbce4','送陸務觀得倅鎮江還越  其一','韓元吉','宋','宋诗','song-poetry','','[]','高文不試紫雲樓，猶得聲名動九州。',64,'全唐诗/poet.song.124000.json','["高文不試紫雲樓，猶得聲名動九州。", "金馬漸登難避世，蓬萊已近却迴舟。", "燒城赤口知何事，許國丹心惜未酬。", "歸卧鏡湖聊洗眼，雨餘萬壑正爭流。"]'),
('6077927e-700a-4c56-975d-038c12ed3682','送陸務觀得倅鎮江還越  其二','韓元吉','宋','宋诗','song-poetry','','[]','前年邊馬飲江水，烽火瓜州一水間。',64,'全唐诗/poet.song.124000.json','["前年邊馬飲江水，烽火瓜州一水間。", "正使樓船多戰士，要須京峴作重關。", "平戎得路可橫槊，佐郡經時應賜環。", "把酒賦詩甘露寺，眼中那更有金山。"]'),
('fbe6ef14-0959-4efa-ac0d-eb9420fdf101','送陸務觀福建提倉','韓元吉','宋','宋诗','song-poetry','','["\u79bb\u522b", "\u5fc6\u65e7", "\u996e\u9152", "\u611f\u6168"]','觥船相對百分空，京口追隨一夢中。',64,'全唐诗/poet.song.124000.json','["觥船相對百分空，京口追隨一夢中。", "落紙雲烟君似舊，盈巾霜雪我成翁。", "春來茗葉還爭白，臘近梅梢儘破紅。", "領略溪山須妙語，少迂使節上凌風。"]'),
('ea7e83e9-d64f-4381-9998-317ba28e1c60','送呂令防赴海門宰  其一','韓元吉','宋','宋诗','song-poetry','','[]','五斗由來豈療貧，尚應拄笏對秋雲。',64,'全唐诗/poet.song.124000.json','["五斗由來豈療貧，尚應拄笏對秋雲。", "未嗟薄宦來還去，但覺頻年我送君。", "舍北水生思共賞，淮南米賤好相聞。", "白魚青笋平生事，愁絕江寒雁影分。"]'),
('a92bc0ea-a811-4e4e-8833-0e069c8487d6','送呂令防赴海門宰  其二','韓元吉','宋','宋诗','song-poetry','','[]','野閣山扉舊卜鄰，竹陰花徑每情親。',64,'全唐诗/poet.song.124000.json','["野閣山扉舊卜鄰，竹陰花徑每情親。", "舉觴契闊又千里，同社淒涼無幾人。", "濯濯未妨如月柳，悠悠真不奈風塵。", "海門應去蓬萊近，我欲乘桴試問津。"]'),
('95a00b11-a90d-4bba-ac29-5076151c5e40','送趙蕃辰州司理','韓元吉','宋','宋诗','song-poetry','','[]','故家零落眼中稀，歲月崢嶸踏路岐。',64,'全唐诗/poet.song.124000.json','["故家零落眼中稀，歲月崢嶸踏路岐。", "詩解窮人君莫恨，錢能使鬼我方知。", "片言折獄非無日，談笑封侯會有時。", "一上梅山弔槃瓠，賸題佳句寫幽思。"]'),
('a75c09bd-7204-4c13-ba01-5fc9dd83c628','送張幾仲知泰州','韓元吉','宋','宋诗','song-poetry','','[]','紫橐甘泉不願留，虎符聊試海邊州。',64,'全唐诗/poet.song.124000.json','["紫橐甘泉不願留，虎符聊試海邊州。", "長城底用騎圍鐵，下瀨直須船有樓。", "草木已應知世望，江山好在得詩流。", "春風桃李西溪路，宣室歸來尚黑頭。"]'),
('0a2afd9e-b637-43a1-b5ef-81101f8eea5f','送施徽州二首  其一','韓元吉','宋','宋诗','song-poetry','','[]','御史英名世罕儔，峨冠聊復漸承流。',64,'全唐诗/poet.song.124000.json','["御史英名世罕儔，峨冠聊復漸承流。", "治功要自先馮翊，大惠何妨始歙州。", "野媼定知還去虎，山民從此罷賫牛。", "百年善政須公繼，尺一書頒願少留。"]'),
('d42378ee-5104-45fe-b0ac-5588cd96d5d3','送施徽州二首  其二','韓元吉','宋','宋诗','song-poetry','','[]','江出新安見底清，黄山高勢碧崢嶸。',64,'全唐诗/poet.song.124000.json','["江出新安見底清，黄山高勢碧崢嶸。", "袴襦會遣民皆有，枹鼓懸應夜不鳴。", "蠟屐未須懷別墅，虎符今喜得名城。", "他時一榻容徐穉，端共輿人樂政成。"]'),
('2880bf52-b606-4cc1-9a46-d32738a861f2','送李子永赴調改秩','韓元吉','宋','宋诗','song-poetry','','[]','逸驥騫騰十二閑，追風那復駐轅間。',64,'全唐诗/poet.song.124000.json','["逸驥騫騰十二閑，追風那復駐轅間。", "向來官況誠留滯，此去詩情記往還。", "會課未妨更美秩，趣班聊喜近天顔。", "割鷄莫費千牛刃，奏賦金門入道山。"]'),
('c5779d55-6fe0-426e-8825-be03eadb7859','送王德和赴調改秩','韓元吉','宋','宋诗','song-poetry','','[]','樽酒盤蔬語夜闌，三年猶得幾追歡。',64,'全唐诗/poet.song.124000.json','["樽酒盤蔬語夜闌，三年猶得幾追歡。", "海棠半折春方好，楊柳都青社正寒。", "籌畫定應瞻武帳，文華端合侍金鑾。", "割鷄底用磨天刃，遲日湖山滿意看。"]'),
('6586f3ee-bc30-43b6-b1f7-24256e521d35','送葉夢錫赴荆南','韓元吉','宋','宋诗','song-poetry','','[]','南郡開邊古上流，君王側席用嘉謀。',64,'全唐诗/poet.song.124000.json','["南郡開邊古上流，君王側席用嘉謀。", "壯懷何止入雲夢，雄略行看半九州。", "風勁鼓聲連岸動，雪晴江影與天浮。", "一樽莫作新亭語，勳業歸庸尚黑頭。"]'),
('d9a66895-cfad-424e-9427-1f4ee874eb1d','送韓子師守婺州','韓元吉','宋','宋诗','song-poetry','','[]','功名相望十年前，白首官曹僅接聯。',64,'全唐诗/poet.song.124000.json','["功名相望十年前，白首官曹僅接聯。", "良玉要須更九火，明珠那得閟重泉。", "清風遂作雙溪詠，老手懸知劇郡便。", "奏課不妨聊第一，歸來更著祖生鞭。"]'),
('f02913c4-da94-4327-83fa-38ec7f3440fc','送沈千里教授邵陽','韓元吉','宋','宋诗','song-poetry','','[]','縠紋江畔得君詩，俊逸清新字字奇。',64,'全唐诗/poet.song.124000.json','["縠紋江畔得君詩，俊逸清新字字奇。", "一笑偶成歸妹約，幾年還見外孫辭。", "橫經絳帳地雖遠，給劄金門天未遲。", "痛飲離騷吾事爾，湘山風物與春期。"]'),
('45bd9bda-5b22-4cc4-9ccd-cbeaa975520d','送潘元夙教授欽州','韓元吉','宋','宋诗','song-poetry','','[]','文筆超然自不羣，胸中韜略未全陳。',64,'全唐诗/poet.song.124000.json','["文筆超然自不羣，胸中韜略未全陳。", "詎應遠致嶺南士，會見來清塞北塵。", "桂海接天聊縱目，火雲堆露正關身。", "元戎在昔同科彥，一鶚飛書上紫宸。"]'),
('bfa702f8-c7da-427e-a0a6-aa162f48dca2','送澤赴新塗尉','韓元吉','宋','宋诗','song-poetry','','[]','少年薄宦幾東西，送汝臨岐意尚迷。',64,'全唐诗/poet.song.124000.json','["少年薄宦幾東西，送汝臨岐意尚迷。", "作尉未嗟官職小，致身當與古人齊。", "短篷載雪看梅蘂，古驛衝風信馬蹄。", "爾父漸衰吾已老，寄書時一到南溪。"]'),
('34114b09-1514-4cb7-ae52-a66438c3ebb3','送李直剛鹽官縣尉','韓元吉','宋','宋诗','song-poetry','','[]','蚤接君家大父遊，迺翁幕府尚淹留。',64,'全唐诗/poet.song.124000.json','["蚤接君家大父遊，迺翁幕府尚淹留。", "文華遂見諸郎秀，名宦懸知異日優。", "朝雨拍溪梅正熟，晴雲烘路麥初秋。", "渭南自昔多賢尉，官近長安不用愁。"]'),
('20059bad-50be-456b-a8bb-81f4a1f8f168','送元修歸廣東','韓元吉','宋','宋诗','song-poetry','','[]','十年門戶苦彫零，屈指天涯幾弟兄。',64,'全唐诗/poet.song.124000.json','["十年門戶苦彫零，屈指天涯幾弟兄。", "羈旅可堪懷世事，典型誰與振家聲。", "驚心朔岸秋風急，極目南溟瘴霧橫。", "好過貪泉未應酌，少年游宦要冰清。"]'),
('dcb2996c-5f08-4e47-9123-40e409fbe017','送沈駒甫','韓元吉','宋','宋诗','song-poetry','','[]','官曹邂逅得情親，一賦松齋遂絕塵。',64,'全唐诗/poet.song.124000.json','["官曹邂逅得情親，一賦松齋遂絕塵。", "天祿校書元有路，甘泉第頌可無人。", "江山興味不知老，芋栗生涯未覺貧。", "我欲邀君寺南住，春風聊與杏花鄰。"]'),
('1809c3e4-5dd2-4798-b5b8-7bfb2e3664df','送孟婿植還臨川','韓元吉','宋','宋诗','song-poetry','','[]','西風同泛婺江船，倒指光陰六換年。',64,'全唐诗/poet.song.124000.json','["西風同泛婺江船，倒指光陰六換年。", "秋色又看梧葉老，離懷還對菊花前。", "塵埃左宦空搔首，功業青雲更著鞭。", "兒女關情易來往，一樽臨路亦悽然。"]'),
('79e1c516-76cd-46af-8125-1d927c194e67','送郭誠思歸華下','韓元吉','宋','宋诗','song-poetry','','[]','忘懷物外且如愚，何事勞精據槁梧。',64,'全唐诗/poet.song.124000.json','["忘懷物外且如愚，何事勞精據槁梧。", "以馬喻馬即非馬，數輿無輿方得輿。", "莫執斧斤過櫟社，懶施几席向蘧廬。", "好歸玉秀峰前座，閑看晴雲自卷舒。"]'),
('574240fb-d6a3-4942-ac47-a1dc1eb3e5b4','依韵和御製秋晚曲宴詩','韓元吉','宋','宋诗','song-poetry','','[]','巍巍舜治浹嘉生，宴俎豐年萬寶成。',64,'全唐诗/poet.song.124000.json','["巍巍舜治浹嘉生，宴俎豐年萬寶成。", "禁幄雲深開曉色，上林風迥起秋聲。", "威加鼉鼓雷霆轉，喜動龍旂日月明。", "應手神珠看電擊，旄頭消盡鐵山平。"]'),
('bbd9655f-d98f-462e-9a52-1a214cf1e622','次韵子雲春日  其一','韓元吉','宋','宋诗','song-poetry','','[]','林壤欣欣樂有餘，杖藜常及曉鶑初。',64,'全唐诗/poet.song.124000.json','["林壤欣欣樂有餘，杖藜常及曉鶑初。", "春風入戶花開落，晴日當窗雲卷舒。", "契闊經年千里面，平安滿眼數行書。", "弟兄州縣真勞爾，疇昔交遊半石渠。"]'),
('387163fa-5b8f-48d3-92fe-9715a509e693','次韵子雲春日  其二','韓元吉','宋','宋诗','song-poetry','','[]','問舍求田苦未成，定逢丘壑眼先明。',64,'全唐诗/poet.song.124000.json','["問舍求田苦未成，定逢丘壑眼先明。", "極知官事無時了，且作青山任意行。", "元亮折腰應自笑，子荆洗耳詎忘情。", "不妨同是催科拙，下考他年更類城。"]'),
('31e4bf86-058a-4f08-a4c4-684b247446a3','次韵子雲途中見寄  其一','韓元吉','宋','宋诗','song-poetry','','[]','輕風獵獵轉殘紅，春去荒村暮雨中。',64,'全唐诗/poet.song.124000.json','["輕風獵獵轉殘紅，春去荒村暮雨中。", "花影带寒猶黯淡，山光和霧更空濛。", "百年拚却身長醉，五斗由來計日窮。", "慚愧賓朋有膠漆，不堪兄弟苦西東。"]'),
('548eab91-bc58-4c5c-b7b9-97768b8985be','次韵子雲途中見寄  其二','韓元吉','宋','宋诗','song-poetry','','[]','十年計拙未能伸，四海滔滔總是津。',64,'全唐诗/poet.song.124000.json','["十年計拙未能伸，四海滔滔總是津。", "但得有山供醉眼，不憂無地著寒身。", "鶑花撩亂空三月，風雨淒涼過幾旬。", "莫道衡陽無雁信，故應時有北來人。"]'),
('d2b5926e-2d9a-4a89-b718-ce87b79ad482','次韵子雲盱眙道中三首  其一','韓元吉','宋','宋诗','song-poetry','','[]','海上狼烽不起烟，兵戈猶記舊年前。',64,'全唐诗/poet.song.124000.json','["海上狼烽不起烟，兵戈猶記舊年前。", "巖居有客能招飲，肉食何人爲給鮮。", "但得生涯類盤谷，可無風景似斜川。", "共尋餬口田三畝，仍辦遮頭屋數椽。"]'),
('89e82efd-eb40-448e-b77d-fc4af6ab0a51','次韵子雲盱眙道中三首  其二','韓元吉','宋','宋诗','song-poetry','','[]','江南淮北市初通，人語忻忻作好風。',64,'全唐诗/poet.song.124000.json','["江南淮北市初通，人語忻忻作好風。", "抱耒只思耕隴底，買船誰復渡遼東。", "向來熊耳真投甲，此去天山擬挂弓。", "上策聖君今自治，白頭憂國寸心同。"]'),
('ffe1ddf4-53a2-42ae-8246-c4eea5064dca','次韵子雲盱眙道中三首  其三','韓元吉','宋','宋诗','song-poetry','','[]','桑間無褐半饑人，斗粟千金不換銀。',64,'全唐诗/poet.song.124000.json','["桑間無褐半饑人，斗粟千金不換銀。", "末路多慚逭溝壑，長年敢笑走埃塵。", "江聲直下黄牛峽，河勢遥分白馬津。", "回首向來征戰地，壯懷俱在只傷神。"]'),
('8d6064f9-77a1-47ec-84b2-6831fe5c6738','答金元鼎喜雨  其一','韓元吉','宋','宋诗','song-poetry','','[]','幾日雲陰合又開，良田秋近起黄埃。',64,'全唐诗/poet.song.124000.json','["幾日雲陰合又開，良田秋近起黄埃。", "一觴未致靈祠禱，半夜先欣好雨來。", "政拙自知容我懶，詩清要是得君催。", "不妨咳唾皆珠玉，漸喜新凉入酒杯。"]'),
('cfd549d0-8a6d-4497-a283-e7dfdb6f41f9','答金元鼎喜雨  其二','韓元吉','宋','宋诗','song-poetry','','[]','雨後紅蕖滿意開，風前綠浄絕纖埃。',64,'全唐诗/poet.song.124000.json','["雨後紅蕖滿意開，風前綠浄絕纖埃。", "獨憐病守孤吟賞，猶幸詩翁數往來。", "農事已知溝澮足，歡聲不待管絃催。", "旋舂玉粒添冰釀，莫負樽前鸚鵡杯。"]'),
('f1bca256-a35b-47df-a6f4-3f015b3844e9','次韵趙文鼎雨中','韓元吉','宋','宋诗','song-poetry','','[]','老病幽栖不厭閒，未須消息夢長安。',64,'全唐诗/poet.song.124000.json','["老病幽栖不厭閒，未須消息夢長安。", "一春意淡連牆竹，終日清香小檻蘭。", "紅蘂便驚風裏盡，青林猶愜雨中看。", "故人詩卷從頭讀，似酌芳樽爲解顔。"]'),
('4dfe6311-7151-4c52-a807-53831a4e39a7','次韵中甫兄九日同集張園','韓元吉','宋','宋诗','song-poetry','','[]','湖山秋盡作幽期，未覺浮舟菡萏衰。',64,'全唐诗/poet.song.124000.json','["湖山秋盡作幽期，未覺浮舟菡萏衰。", "怯酒自憐多病後，强歌還憶少年時。", "平蕪半綠煙猶接，好菊微黄雨更宜。", "單父層臺在何許，一樽懷古少陵詩。"]'),
('61d55739-c3e8-4a32-9c4f-1ba05de252ae','雪中走筆寄鄧延碩','韓元吉','宋','宋诗','song-poetry','','[]','去年雪裏共清遊，蕭子酣歌幾唱酬。',64,'全唐诗/poet.song.124000.json','["去年雪裏共清遊，蕭子酣歌幾唱酬。", "竹葉又看新釀熟，梅花還作暗香浮。", "青衫尚想君奔走，短褐空嗟我滯留。", "南北兩峰銀色界，不應孤負水邊樓。"]'),
('1a4e0c60-e1b7-445e-983e-edd4beb2cbb6','和同僚賀雪應祈','韓元吉','宋','宋诗','song-poetry','','[]','臘近春臨雪意遲，褰衣敢憚走靈祠。',64,'全唐诗/poet.song.124000.json','["臘近春臨雪意遲，褰衣敢憚走靈祠。", "夜聽小雨猶傾耳，曉看羣山頓展眉。", "好句懸知得冰柱，香醪試爲壓羔兒。", "便應風月臺中客，不減梁園賦就時。"]'),
('3a35b8d0-7a2e-432f-8d3e-11f52561b0e4','次韵韓子師雪中二首  其一','韓元吉','宋','宋诗','song-poetry','','[]','九門疊璧耀朝暾，不比千燈作上元。',64,'全唐诗/poet.song.124000.json','["九門疊璧耀朝暾，不比千燈作上元。", "天與蘂珠開漢殿，人將冰玉奉堯樽。", "寒威已覺邊聲靜，春意都隨詔語溫。", "夜入蔡州飛將在，肯容敵騎妄稱尊。"]'),
('749e409f-8a59-479a-98cd-8a4791c5dd5f','次韵韓子師雪中二首  其二','韓元吉','宋','宋诗','song-poetry','','[]','曲欄高檻倚崔嵬，要是仙京白玉臺。',64,'全唐诗/poet.song.124000.json','["曲欄高檻倚崔嵬，要是仙京白玉臺。", "雲色自連鳷鵲動，天顔亦爲近臣開。", "光翻午夜渾疑月，花滿新春未數梅。", "自笑詩成無好語，但知縞带與銀杯。"]'),
('48eecd1c-9fde-45f9-a100-ae3e0ee5b3f4','次韵黄文剛秀才雪中見詒且惠新柑','韓元吉','宋','宋诗','song-poetry','','[]','填空密雪借風威，深閉蓬窗晝掩扉。',64,'全唐诗/poet.song.124000.json','["填空密雪借風威，深閉蓬窗晝掩扉。", "待學仙人乘鶴駕，未容寒士泣牛衣。", "連篇妙語千金重，滿合黄柑數寸圍。", "細酌清樽酬夜月，更看庭樹作花飛。"]'),
('3a24ff0c-e686-4a55-9cf9-6a41ca4f593c','次韵梁子張雪中約遊湖上不至','韓元吉','宋','宋诗','song-poetry','','[]','東風閣雨釀重雲，賸喜天街玉作塵。',64,'全唐诗/poet.song.124000.json','["東風閣雨釀重雲，賸喜天街玉作塵。", "梅已著花還點綴，柳能吹絮便爭新。", "湖光照坐偏宜晚，酒力欹欄別是春。", "慚愧相如未能至，却將冰柱語驚人。"]'),
('4faad215-a5b7-4baf-87ab-a6ca1355785f','次韵子雲歸興','韓元吉','宋','宋诗','song-poetry','','[]','湖海周游未卜居，好山時一夢衡廬。',64,'全唐诗/poet.song.124000.json','["湖海周游未卜居，好山時一夢衡廬。", "苦無事業堪調鼎，薄有生涯可負鋤。", "玩世阮公方蠟屐，歸田陶令亦巾車。", "屋頭早晚東西住，愁絕江船夜雨餘。"]'),
('adcc3be4-524f-4101-b3c5-7615b6e7bcd1','次韵曾吉甫題畫屏風','韓元吉','宋','宋诗','song-poetry','','[]','何許江山發興長，渾疑廬阜對彭郎。',64,'全唐诗/poet.song.124000.json','["何許江山發興長，渾疑廬阜對彭郎。", "胸中丘壑元蕭爽，筆下煙波故渺茫。", "落落疏松長映座，冥冥飛雨欲侵牀。", "冷然已作華胥夢，便有羣仙到枕旁。"]'),
('ba9c7348-4798-487b-8376-c0e2bd4cdcb5','次韵王季夷時同宿蔣山','韓元吉','宋','宋诗','song-poetry','','[]','亭亭石塔寶公龕，賸喜僧牀得對談。',64,'全唐诗/poet.song.124000.json','["亭亭石塔寶公龕，賸喜僧牀得對談。", "坎壈詞場君亦滯，驅馳世路我何堪。", "軍書又見紛南北，敵勢由來說二三。", "淮岸西風晚更急，似傳烽火過江南。"]'),
('f52da0e6-a21a-4083-be1d-4f2ae6a75f24','次韵沈千里玉山道中見寄','韓元吉','宋','宋诗','song-poetry','','[]','霜晴懷玉自生烟，寒色淒淒過雁邊。',64,'全唐诗/poet.song.124000.json','["霜晴懷玉自生烟，寒色淒淒過雁邊。", "路轉湘南知幾日，山連楚尾又窮年。", "相期鷄黍情歡甚，惜別塵埃意黯然。", "馬上哦詩衝暮雪，清風懷我北窗眠。"]'),
('286752ab-553d-4aed-b029-f1dd91cac1ac','次韵沆姪','韓元吉','宋','宋诗','song-poetry','','[]','平生作計本山林，便腹空餘貯古今。',64,'全唐诗/poet.song.124000.json','["平生作計本山林，便腹空餘貯古今。", "致主未忘他日志，歸耕每動十年心。", "疏翎浪喜煙霄近，弱植多慚雨露深。", "早决儒科猶望汝，蛩然虛谷佇聞音。"]'),
('1b453340-0193-4e81-a217-b66f0e368599','次韵李子永見慶新居','韓元吉','宋','宋诗','song-poetry','','[]','旋移桐樹占高岡，更喜松筠翠作行。',64,'全唐诗/poet.song.124000.json','["旋移桐樹占高岡，更喜松筠翠作行。", "簷外參差見林影，門前溶漾足溪光。", "天涯留落還相識，地上經營豈太忙。", "好事肯來三徑在，已添籬菊待重陽。"]'),
('71ac04b0-1043-47d2-9f4b-a34c577035d8','次韵沈駒甫觀石井','韓元吉','宋','宋诗','song-poetry','','[]','湖裏鴐鵝亦洞天，最奇山下石坳泉。',64,'全唐诗/poet.song.124000.json','["湖裏鴐鵝亦洞天，最奇山下石坳泉。", "一泓自覺寒光浄，六月都無暑氣煎。", "清似錫峰藏雨露，迥如篁嶺箇風煙。", "壁端舊乏騷人句，從此須君妙墨傳。"]'),
('d33e8462-7c7e-4098-9462-ef8ee04d4b3e','次韵王亞之來過橫碧','韓元吉','宋','宋诗','song-poetry','','[]','君到層軒眼爲寬，諸峰還得雨中看。',64,'全唐诗/poet.song.124000.json','["君到層軒眼爲寬，諸峰還得雨中看。", "嵐光照座蒼翠出，寺影拂波金碧寒。", "詩興豈妨隨望極，秋聲不柰起愁端。", "相逢莫怪無樽酒，秀色崔嵬尚可餐。"]'),
('74ffd6e1-750c-424c-ba31-8f112089d5f6','次韵宋傳道夜雨聞捷  其一','韓元吉','宋','宋诗','song-poetry','','[]','松庭竹戶野僧家，獨坐荒齋到日斜。',64,'全唐诗/poet.song.124000.json','["松庭竹戶野僧家，獨坐荒齋到日斜。", "門外江風寒作雨，城頭戍鼓夜啼鴉。", "對牀更欲論心事，擁褐還驚逼歲華。", "却憶巴山舊時語，夢回窗竹已生花。"]'),
('ea680644-447f-4593-9102-758dc8971f53','次韵宋傳道夜雨聞捷  其二','韓元吉','宋','宋诗','song-poetry','','[]','邊地山川自漢家，蠭旗圖畫拂雲斜。',64,'全唐诗/poet.song.124000.json','["邊地山川自漢家，蠭旗圖畫拂雲斜。", "江干戰騎膺如虎，塞上神兵斧似鴉。", "羽檄故應煩號令，星車底用賦皇華。", "軍聲指日騰三捷，陣勢他年本六花。"]'),
('43b5e252-91c4-41f3-9d02-aedb05592027','再用前韵戲傳道','韓元吉','宋','宋诗','song-poetry','','[]','空谷天寒翠袖遮，無人曾見玉釵斜。',64,'全唐诗/poet.song.124000.json','["空谷天寒翠袖遮，無人曾見玉釵斜。", "詩成落日千尋竹，歌就殘陽萬點鴉。", "粧額淺深知內樣，舞衣裁翦勝京華。", "自憐已作高唐夢，須信饑腸眼易花。"]'),
('a181b53f-9d31-4c59-9460-e67c0d0b672b','次韵趙仲績久雨夜坐有感二首  其一','韓元吉','宋','宋诗','song-poetry','','[]','春雲黯黯未成晴，落盡緗桃見紫荆。',64,'全唐诗/poet.song.124000.json','["春雲黯黯未成晴，落盡緗桃見紫荆。", "薄宦馳驅雙鬢改，流年荏苒寸心驚。", "幽花映水淺深色，啼鳥穿林高下聲。", "幾許風光欠行樂，夜寒和雨聽殘更。"]'),
('5b332a28-4863-4770-a7cb-81b3f88f36f7','次韵趙仲績久雨夜坐有感二首  其二','韓元吉','宋','宋诗','song-poetry','','[]','十日風斜雨更橫，一春能得幾新晴。',64,'全唐诗/poet.song.124000.json','["十日風斜雨更橫，一春能得幾新晴。", "便須蠟屐穿花去，莫惜障泥傍水行。", "酒興未妨隨處發，詩狂賸判隔年程。", "醉來乞得西山藥，彷彿雲間吹鳳笙。"]'),
('43949746-8317-4dce-a219-db634ac8b81e','次韵張晉彥書事','韓元吉','宋','宋诗','song-poetry','','[]','舉世諸兄事孔方，平生學易問歸藏。',64,'全唐诗/poet.song.124000.json','["舉世諸兄事孔方，平生學易問歸藏。", "漸欣過客知吾懶，未怪小兒如我長。", "鶴怨猿驚成底事，烏踆兔蹶自奔忙。", "便須耳熱追行樂，更擬心齋得坐忘。"]'),
('9c69fc4f-a04c-483c-b8d6-6a6cb77d0003','次韵吳明可與史致道會飲牛渚','韓元吉','宋','宋诗','song-poetry','','[]','月出千山捲暮雲，遥知玉節會江濱。',64,'全唐诗/poet.song.124000.json','["月出千山捲暮雲，遥知玉節會江濱。", "便應擊楫酬今日，不用然犀歎昔人。", "煙外笛聲誰送晚，水邊花影自迎春。", "風流三百年無此，況有清詩句法新。"]'),
('b6d47db5-4578-4f1e-ba4a-dda49ad204e7','次韵徐應祺小樓','韓元吉','宋','宋诗','song-poetry','','[]','瀲瀲清波泊路衢，垂垂高柳對扶疏。',64,'全唐诗/poet.song.124000.json','["瀲瀲清波泊路衢，垂垂高柳對扶疏。", "已知百尺樓堪卧，況有三重茅可居。", "我老詎能賡鮑謝，君才端合紹嚴徐。", "直須座上千鍾酒，澆起胸中萬卷書。"]'),
('d3fd9693-d634-473c-be83-7bb233b46d33','次韵答沈明遠','韓元吉','宋','宋诗','song-poetry','','[]','如君絕足向風塵，顧我宜爲途路人。',64,'全唐诗/poet.song.124000.json','["如君絕足向風塵，顧我宜爲途路人。", "阿買八分時自笑，阮瞻三語詎能新。", "狂談尚欲嘲風伯，妙筆真堪賦洛神。", "得酒相尋那厭數，醉歸官長未應嗔。"]'),
('6891f177-8b06-4c9d-9bdb-f20df8a0e687','亞之出示其祖岐公墨迹及惠崇小景且和前韵復次答之','韓元吉','宋','宋诗','song-poetry','','[]','壁上春江萬頃寬，錦囊遺墨幸重看。',64,'全唐诗/poet.song.124000.json','["壁上春江萬頃寬，錦囊遺墨幸重看。", "功名世路真多畏，貧賤交盟敢自寒。", "新有詩聲見侯喜，盡攄懷抱得蘇端。", "極知鼎食君家舊，未厭堆盤苜蓿餐。"]'),
('d010842c-2eed-4911-b09b-7640b1eed340','新晴梅花可愛欲招明遠少稷凍醪未熟','韓元吉','宋','宋诗','song-poetry','','[]','癡兒了事不能閒，猶喜騷人共往還。',64,'全唐诗/poet.song.124000.json','["癡兒了事不能閒，猶喜騷人共往還。", "歲晚真成廢書史，雪晴那得負江山。", "多情春與梅花厚，一醉天于我輩慳。", "賸作新詩催酒熟，曲池冰斷水潺潺。"]'),
('73634ce6-e819-4ca8-a283-fbaf34ad2495','紅梅','韓元吉','宋','宋诗','song-poetry','','[]','不隨羣艷競年芳，獨自施朱對雪霜。',64,'全唐诗/poet.song.124000.json','["不隨羣艷競年芳，獨自施朱對雪霜。", "越女漫夸天下白，壽陽還作醉時粧。", "半依脩竹餘真態，錯認夭桃有暗香。", "月底瑶臺清夢到，霓裳新換舞衣長。"]'),
('ce01e285-b28b-4ca6-a424-530b4fb85ae7','陸子逸惠桃花戲贈','韓元吉','宋','宋诗','song-poetry','','[]','故人招我千山裏，也有仙葩巧送春。',64,'全唐诗/poet.song.124000.json','["故人招我千山裏，也有仙葩巧送春。", "麝馥染衣金縷重，酒紅生粉玉肌勻。", "洛城景物知誰紀，寒食風光觸處新。", "莫把天香調行客，曉粧留與綠窗人。"]'),
('2ea2237d-e118-4476-b48b-1dd34ecb0da9','次韵陳子象十月惠牡丹','韓元吉','宋','宋诗','song-poetry','','[]','芙蓉掃地菊花陳，國色天香一夜春。',64,'全唐诗/poet.song.124000.json','["芙蓉掃地菊花陳，國色天香一夜春。", "愛景自催芳意動，清霜不礙曉粧新。", "長生便可書仙籍，上瑞端宜首貢珍。", "詩就只應開頃刻，先生筆力起千鈞。"]'),
('7bc8b716-5bce-45d2-aaaa-6d6ac91395b6','用前韵以小春茶餉子象','韓元吉','宋','宋诗','song-poetry','','[]','仙花不用惱詩人，亦有靈芽特地春。',64,'全唐诗/poet.song.124000.json','["仙花不用惱詩人，亦有靈芽特地春。", "數朵嬌花真綽約，一甌釅白更清新。", "眼明共識西都艷，齒冷應懷北苑珍。", "佳茗奇葩堪竝賞，須公品第入陶鈞。"]'),
('f160ec39-84db-4eb0-b928-0c2c34f493d6','次韵余寺正瑞香花','韓元吉','宋','宋诗','song-poetry','','[]','香爐峰下異香風，長憶幽芳夢寐通。',64,'全唐诗/poet.song.124000.json','["香爐峰下異香風，長憶幽芳夢寐通。", "渴雨旋傾茶作椀，護霜新織翠成籠。", "丹青點綴瓊瑶上，蘭麝飛浮錦繡中。", "花品曏來誰第一，似挼玉蘂間鞓紅。"]'),
('71f5bcbf-198d-4fc7-b41b-6ee53e9a5403','故致政宣義葉公挽詞','韓元吉','宋','宋诗','song-poetry','','[]','植德由來不自知，成家今見寧馨兒。',64,'全唐诗/poet.song.124000.json','["植德由來不自知，成家今見寧馨兒。", "名駒有種能千里，仙桂騰芳定五枝。", "綵綬螭坳方致養，素車雲路忽興悲。", "死生了了真餘事，流水斷煙空好詩。"]'),
('af3b185a-c111-4d65-82f3-dec7961398d6','挽王僑卿右司詞','韓元吉','宋','宋诗','song-poetry','','[]','壯年嘉譽藹瀛洲，衮衮諸公並儁游。',64,'全唐诗/poet.song.124000.json','["壯年嘉譽藹瀛洲，衮衮諸公並儁游。", "獻納未持天上橐，光華頻總嶠南州。", "牢盆賸算波熬素，蒲澤終期劍買牛。", "世路榮枯真莫問，浮雲山眇淚橫秋。"]'),
('fa89347d-5145-49fb-a0f0-8de2244674a8','挽汪南美大夫詞','韓元吉','宋','宋诗','song-poetry','','[]','年如衛武尚安强，名似康成善一鄉。',64,'全唐诗/poet.song.124000.json','["年如衛武尚安强，名似康成善一鄉。", "三邑久知歌惠愛，西州何幸著循良。", "真清在昔傳家世，治狀由來籍廟堂。", "千載蔣山分未朽，芝蘭玉樹藹餘芳。"]'),
('b98efcb5-d076-4031-9623-840b1c54e253','挽知泰州宋公大夫詞','韓元吉','宋','宋诗','song-poetry','','[]','投老溪南幸卜鄰，一麾頻見寵章新。',64,'全唐诗/poet.song.124000.json','["投老溪南幸卜鄰，一麾頻見寵章新。", "養花別圃成三徑，種木佳城度十春。", "前席遂孤明主意，留鞭難繼澧陽塵。", "空餘樽酒追隨地，同社淒涼淚滿巾。"]'),
('5eb693bd-da5c-4935-9f89-6c88ed6ba0c3','挽故鈐轄趙公彥遠詞','韓元吉','宋','宋诗','song-poetry','','[]','平昔長材未一施，尚餘嘉譽藹天支。',64,'全唐诗/poet.song.124000.json','["平昔長材未一施，尚餘嘉譽藹天支。", "事親養志人爭仰，教子成名世共推。", "盛德故應傳後裔，清規誰爲勒豐碑。", "華林岡下寒泉水，隠隠雷聲紀孝思。"]'),
('f70c5671-e702-4f04-9bda-4d9b391ba050','楊待制挽詞','韓元吉','宋','宋诗','song-poetry','','[]','妙齡著足道家山，壯歲升華玉筍班。',64,'全唐诗/poet.song.124000.json','["妙齡著足道家山，壯歲升華玉筍班。", "千里麾符纔假手，幾年香火竟投閒。", "詩書坐使家聲大，簪紱誰令壽歷慳。", "太傅功名有遺恨，鵷雛凋落淚頻潸。"]'),
('3352ca06-6175-4c20-a24e-4265a7d00612','周彥廣待制挽詞','韓元吉','宋','宋诗','song-poetry','','[]','淮海歡騰五袴歌，政聲京兆益中和。',64,'全唐诗/poet.song.124000.json','["淮海歡騰五袴歌，政聲京兆益中和。", "鄴侯井在功堪紀，鄭國渠成利更多。", "紫禁遄躋知異眷，珍臺歸卧本微疴。", "功名方展凌雲步，奈此佳城白日何。"]'),
('a4441395-226a-41ee-afe9-dbb81d3ec185','故運使直閣少卿劉公挽詞','韓元吉','宋','宋诗','song-poetry','','["\u592a\u6e56"]','清時得路每投閒，垂上甘泉玉筍班。',64,'全唐诗/poet.song.124000.json','["清時得路每投閒，垂上甘泉玉筍班。", "借箸幾看趨魏闕，請纓常欲度天山。", "放懷俠氣千夫上，抵掌高談一夢間。", "使節塵生人共惜，朔風吹淚太湖灣。"]'),
('e5257a03-9870-44da-b6e4-1219d01245d6','故致政敷文少卿魯公挽詞','韓元吉','宋','宋诗','song-poetry','','[]','左學摛文藹儁聲，青雲接武二難兄。',64,'全唐诗/poet.song.124000.json','["左學摛文藹儁聲，青雲接武二難兄。", "主知自紀宜三院，使節更持僅九卿。", "庭下芝蘭方競秀，舍南桃李已成陰。", "掛冠不待甘泉橐，愁絕高門淚滿纓。"]'),
('a2a3e735-c302-42dd-a4bc-bd59d77681ff','故致政提刑少卿方公挽詞','韓元吉','宋','宋诗','song-poetry','','[]','籌策霑榮譽最賢，青雲回步接英躔。',64,'全唐诗/poet.song.124000.json','["籌策霑榮譽最賢，青雲回步接英躔。", "請纓莫遂終軍志，投紱方期衛武年。", "原隰觀風頻玉節，省臺聯秩近甘泉。", "一舟五鶴符佳夢，陂水成湖問葛仙。"]'),
('5d88352a-75cb-437d-9a35-693549b8f3b4','挽主奉路分趙公詞','韓元吉','宋','宋诗','song-poetry','','[]','畫舸安輿霅水清，春風猶憶送君行。',64,'全唐诗/poet.song.124000.json','["畫舸安輿霅水清，春風猶憶送君行。", "無家舉案人方恨，有子分符世共榮。", "德履未容居祭酒，聲華端合主宗盟。", "太支耆老凋零甚，蘭玉階庭獨擅名。"]'),
('afbce13f-248e-43bd-9924-3e0ea7ba4970','故提點判院魏公挽詞','韓元吉','宋','宋诗','song-poetry','','[]','當年卓魯盛材猷，循吏聲名始一州。',64,'全唐诗/poet.song.124000.json','["當年卓魯盛材猷，循吏聲名始一州。", "功在龍津看雨施，風行金穴見錢流。", "褒庸合上清華貫，奏課俄驚疾病留。", "嶷嶷諸郎富儒雅，蓋棺十世可無愁。"]'),
('cbb3c45c-4a7d-4eba-85d5-94491c3da116','劉子宣侍郎挽詞','韓元吉','宋','宋诗','song-poetry','','[]','妙齡嘉譽滿江東，晚接甘泉豹尾中。',64,'全唐诗/poet.song.124000.json','["妙齡嘉譽滿江東，晚接甘泉豹尾中。", "烜赫身榮知有道，從容心計不言功。", "威行峴首追羊叔，名在鄱江憶魯公。", "種木十年歸莫遂，塗車千里恨何窮。"]'),
('ef2728aa-fbe5-476f-9fe1-974ab2f37f0a','李壽翁侍郎挽詞','韓元吉','宋','宋诗','song-poetry','','[]','同解銓衡並把麾，五年相望楚江湄。',64,'全唐诗/poet.song.124000.json','["同解銓衡並把麾，五年相望楚江湄。", "鄰牆會面嘗談易，吏選偷閒更說詩。", "北客遭逢人共歎，南州流轉事難知。", "投簪自有江湖志，雲白天青淚滿頤。"]'),
('06acf666-8d06-4a54-bd67-169b364ca715','挽周仲深郎中詞','韓元吉','宋','宋诗','song-poetry','','[]','才力軒軒動漢庭，清時指日致功名。',64,'全唐诗/poet.song.124000.json','["才力軒軒動漢庭，清時指日致功名。", "一同在昔歌遺愛，兩郡于今有治聲。", "使節暫分秦望重，郎星初近太微明。", "死生契闊空泉壤，賻典殊恩世亦榮。"]'),
('60b256f4-999f-4cf4-a0f6-3516ae614ab3','王中奉漢老挽詞','韓元吉','宋','宋诗','song-poetry','','[]','符節光華二十春，壯猷曾不侍嚴宸。',64,'全唐诗/poet.song.124000.json','["符節光華二十春，壯猷曾不侍嚴宸。", "棲心香火纔同社，放意溪山幸卜鄰。", "再世簪纓宜衮衮，一門蘭玉尚詵詵。", "霜清三港追隨地，丹旐飄然淚滿巾。"]'),
('b4482154-4d46-4d4d-a1c9-6b53e2845a53','呂伯恭挽詞','韓元吉','宋','宋诗','song-poetry','','[]','青雲塗路本青氈，聖願相期四十年。',64,'全唐诗/poet.song.124000.json','["青雲塗路本青氈，聖願相期四十年。", "臺閣久嗟君卧疾，山林空歎我華顛。", "傷心二女同新穴，拭目諸生續舊編。", "斗酒無因相沃酹，朔風東望涕潸然。"]'),
('88df5972-2483-448c-801c-e2ff36ac45e3','周濟美挽詞','韓元吉','宋','宋诗','song-poetry','','[]','迺翁持橐舊知名，兩郡分符見典型。',64,'全唐诗/poet.song.124000.json','["迺翁持橐舊知名，兩郡分符見典型。", "禁闥方應馳儁步，中臺俄忽隨修翎。", "故人零落風前葉，北客漂流雨後萍。", "白馬素車三巷路，淚兼臘雪灑林坰。"]'),
('c6ef28ca-52be-4fef-beb9-5378bab89918','暉仲叔挽詞','韓元吉','宋','宋诗','song-poetry','','[]','材業光華藹薦紳，由來孝子出忠臣。',64,'全唐诗/poet.song.124000.json','["材業光華藹薦紳，由來孝子出忠臣。", "五年字邑祗明詔，兩路觀風惠遠民。", "徐穉湖邊纔卜築，葛翁山下忽棲神。", "朔雲千里人揮淚，遺命歸從大母鄰。"]'),
('5ae41910-c63c-4c5d-961f-dbfd044d2d07','次韵唐與正喜雪二十韵','韓元吉','宋','宋诗','song-poetry','','[]','窮臘逢三白，山城兩換年。',240,'全唐诗/poet.song.124000.json','["窮臘逢三白，山城兩換年。", "破寒初淅瀝，作態正翩翾。", "倚杖心逾喜，搔頭意自便。", "直疑填巨壑，豈惜沍長川。", "宮粉慙施白，仙禽恨奪鮮。", "銀牀凝露綆，玉柱澀風絃。", "徑滿巇難認，窗虛隙易穿。", "共尋瑶草路，俱誦蘂珠篇。", "獵騎朝羣擁，漁燈夜獨然。", "凌風幾閬苑，照日盡藍田。", "賸約佳賓集，先煩好句傳。", "荷枯疑璧碎，柳細訝絲牽。", "有士迷青眼，無人笑黑肩。", "豐年期不日，瑞氣靄非烟。", "竹密還爭舞，梅疏只鬭妍。", "輕鷗隨浩蕩，戲蝶伴聯翩。", "强續麻衣詠，真逢縞带賢。", "凋零屬國節，片段廣文氈。", "短棹尋安道，高樓憶仲宣。", "名駒紛照夜，無復愛連錢。"]'),
('0d739d58-26f3-4ae6-8862-4d088985ef68','湯丞相生日二十韵','韓元吉','宋','宋诗','song-poetry','','[]','寶歷千齡會，神槎八月流。',240,'全唐诗/poet.song.124000.json','["寶歷千齡會，神槎八月流。", "人知挺生傑，天欲中興周。", "文筆超三古，聲名溢九州。", "宏才自伊呂，餘事豈應劉。", "繄昔開黄閣，于今尚黑頭。", "裴公旋卧護，蕭相暫居留。", "舄奕稽山綬，光華綠野遊。", "銀輿壽母貴，玉耳上公優。", "嗣聖資爰立，昌時副聿求。", "來歸嘉季子，入覲偉韓侯。", "今日恢王略，蒼生跂廟謀。", "中原尚紛擾，絕塞要懷柔。", "勝算如先定，成機會可投。", "洪源端欲汎，前箸匪無籌。", "日月符羲馭，乾坤協禹疇。", "行看靜蛇豕，俱議息貔貅。", "考有中書第，官無太尉酬。", "兩京期汛掃，九廟得重修。", "祉福天方錫，勳庸世未休。", "斯民納仁壽，公壽幾千秋。"]'),
('9f27c187-1513-4251-82c4-0ef36680cae5','投贈徐平江三十韵','韓元吉','宋','宋诗','song-poetry','','[]','上聖恢方域，吳門翊帝京。',288,'全唐诗/poet.song.124000.json','["上聖恢方域，吳門翊帝京。", "千秋季子國，百雉闔閭城。", "屏翰資良牧，文昌輟貳卿。", "龍墀虛紫橐，虎節駐紅旌。", "河潤功初洽，棠陰政已成。", "農桑歸愷悌，弦管樂升平。", "世仰韋公譽，人高白傅名。", "雲樓凌月府，花島爛蓬瀛。", "香霧凝春晝，橋虹卧曉晴。", "清規三不惑，盛事二難并。", "舊俗寧論化，重臨倍有聲。", "向來宣使指，曾是格刑清。", "自覿銅魚拜，欣聞竹馬迎。", "五湖歌吹滿，兩郡吏民爭。", "嚴助書頻賜，蕭卿治欲更。", "還應對宣室，俱議直承明。", "鼎席猶虛位，戎亭正息兵。", "安危均注意，中外等持衡。", "補衮才猷壯，康時智略宏。", "天津飛驥足，雲路逸鵬程。", "疇昔參賓從，頑疏荷鑒評。", "馳驅奉刀筆，談笑接簪纓。", "夢結閩陬遠，心驚漲潦橫。", "寄身侔困鮒，盡室逭長鯨。"]'),
('62baab77-97dc-4a74-969d-0ff318890c92','少稷家觀雪賦江字三十韵','韓元吉','宋','宋诗','song-poetry','','[]','雪暮來無際，長吟坐北窗。',288,'全唐诗/poet.song.124000.json','["雪暮來無際，長吟坐北窗。", "未嫌光奪月，先恐勢填江。", "雲色生冰柱，風聲倒石矼。", "疏簾纔的皪，破屋漸錚鏦。", "始訝烏能白，旋驚馬盡䮾。", "會朝瓊飾弁，獵較素綢杠。", "玉帝開宮闕，瑶姬擁旆幢。", "仰空蜂作陣，窺徑蝶成雙。", "價重連城璞，明逾釘壁釭。", "冷烟紛莫辨，凍溜不成淙。", "計拙夸遼豕，塗窮笑越尨。", "戴牛迷象齒，覆鹿誤羊羫。", "酪乳浮茶鼎，花甆瑩鼓椌。", "崖枯頻畏住，鵠瘦暫胮肛。", "共想周王宴，誰虞漢使降。", "獻衣知念札，加璧殆追逄。", "蹇駟深憂沒，籃輿重莫扛。", "淹鍾應預賜，增斗定先撞。", "短日棲窮巷，豐年卜萬邦。", "緇塵異羈旅，華髮逐耆厖。", "處士欣尋戴，參軍豈遇龐。", "裘穿心易怯，履敗足微跫。", "荷笠閒垂釣，迴船穩繫樁。", "清狂時仄帽，泥飲屢空缸。"]'),
('a3b41ec1-efa7-4a69-8a24-e6ca7d31da01','遺直堂六首  其一','韓元吉','宋','宋诗','song-poetry','','[]','蒿萊自輿臺，松桂猶伯叔。',24,'全唐诗/poet.song.124000.json','["蒿萊自輿臺，松桂猶伯叔。", "便合追孔林，無庸號寒木。"]'),
('e4d0309b-8807-4369-bdf3-35e91c6cc6ac','遺直堂六首  其二','韓元吉','宋','宋诗','song-poetry','','[]','虬龍舞雲端，風雨來海上。',24,'全唐诗/poet.song.124000.json','["虬龍舞雲端，風雨來海上。", "尚想堂中人，詩成一迴向。"]'),
('fbfc2753-efaa-4162-9a24-9d2a4ad4b971','遺直堂六首  其三','韓元吉','宋','宋诗','song-poetry','','[]','苦心有深思，勁質無軟語。',24,'全唐诗/poet.song.124000.json','["苦心有深思，勁質無軟語。", "賢科廢因公，此事亙千古。"]'),
('010eb196-4c87-433e-ae32-7b6190bf7c4f','遺直堂六首  其四','韓元吉','宋','宋诗','song-poetry','','[]','種木已如此，高賢有餘思。',24,'全唐诗/poet.song.124000.json','["種木已如此，高賢有餘思。", "頼公酷似舅，其誰羨牢之。"]'),
('738bf815-b816-41f5-8d3f-1db4f2b0023a','遺直堂六首  其五','韓元吉','宋','宋诗','song-poetry','','[]','鄭虔骨已朽，孔父天不遺。',24,'全唐诗/poet.song.124000.json','["鄭虔骨已朽，孔父天不遺。", "他年從事賢，手板空倒持。"]'),
('5380a356-7c4c-457b-a310-a4b2fe0e2389','遺直堂六首  其六','韓元吉','宋','宋诗','song-poetry','','[]','棟梁乃不取，得地且深植。',24,'全唐诗/poet.song.124000.json','["棟梁乃不取，得地且深植。", "妖嬈紫薇花，歲晚猶伴直。"]'),
('5676fbf1-8c7b-4e5c-bce4-0e6bd18e79d6','夜宿斜溪聞杜鵑','韓元吉','宋','宋诗','song-poetry','','[]','解纜山銜日，移舟雨暗溪。',24,'全唐诗/poet.song.124000.json','["解纜山銜日，移舟雨暗溪。", "無情子規鳥，夢斷隔林啼。"]'),
('df8ce6fd-99b3-4f91-80e9-857b3788b8bb','送龐祐甫五首  其一','韓元吉','宋','宋诗','song-poetry','','[]','燕鴻望南飛，春至還北去。',24,'全唐诗/poet.song.124000.json','["燕鴻望南飛，春至還北去。", "託食波浪中，瀟湘幾回渡。"]'),
('2c8b48db-67b6-4a69-96a7-ccbe11ab044e','送龐祐甫五首  其二','韓元吉','宋','宋诗','song-poetry','','[]','遊子思故鄉，天涯兩相逢。',24,'全唐诗/poet.song.124000.json','["遊子思故鄉，天涯兩相逢。", "時平甘卹緯，定交各塗窮。"]'),
('848b90de-aedb-4b01-b3ac-a404bf90540d','送龐祐甫五首  其三','韓元吉','宋','宋诗','song-poetry','','[]','濯濯機中絲，粲粲錦繡段。',24,'全唐诗/poet.song.124000.json','["濯濯機中絲，粲粲錦繡段。", "自非同心人，千金孰肯換。"]'),
('98c195f9-0e1a-46ad-933a-62e02fbdf608','送龐祐甫五首  其四','韓元吉','宋','宋诗','song-poetry','','[]','江湖多青山，舟楫長往還。',24,'全唐诗/poet.song.124000.json','["江湖多青山，舟楫長往還。", "山色難送客，不如住山間。"]'),
('c3768fbc-ca72-4bf5-9895-359025412bc8','送龐祐甫五首  其五','韓元吉','宋','宋诗','song-poetry','','[]','中宵櫂謳發，菰蒲翳明月。',24,'全唐诗/poet.song.124000.json','["中宵櫂謳發，菰蒲翳明月。", "月黑君忽行，恐墮蛟龍窟。"]'),
('e311e019-bdc7-428c-907e-73eb6cc77ca5','題日出雨脚圖二首  其一','韓元吉','宋','宋诗','song-poetry','','[]','絕壑春林映綠，半山曉霧迷紅。',28,'全唐诗/poet.song.124000.json','["絕壑春林映綠，半山曉霧迷紅。", "長憶西巖夢覺，小舟欵乃聲中。"]'),
('2a01a587-8ec5-403d-813a-79fe906655c5','題日出雨脚圖二首  其二','韓元吉','宋','宋诗','song-poetry','','[]','隠隠遥分樹色，蕭蕭似聽風聲。',28,'全唐诗/poet.song.124000.json','["隠隠遥分樹色，蕭蕭似聽風聲。", "何處江傾海墮，隔山霧白煙明。"]'),
('bcd20b49-6fd7-47f7-b473-7ddb2a4475d0','次韵趙公直題米元暉畫軸','韓元吉','宋','宋诗','song-poetry','','[]','天際歸雲挾雨，江干亂木藏山。',28,'全唐诗/poet.song.124000.json','["天際歸雲挾雨，江干亂木藏山。", "耳冷似聽蕭瑟，眼明驚見孱顔。"]'),
('c3705234-47b8-4ff6-a448-e02e74a5a669','春雪得小詩五首且約客登賞心亭  其一','韓元吉','宋','宋诗','song-poetry','','[]','東窗坐愛枝間雪，大似酴醿壓架花。',32,'全唐诗/poet.song.124000.json','["東窗坐愛枝間雪，大似酴醿壓架花。", "天氣更晴宜有月，夜深來看玉交加。"]'),
('a0dcde67-2561-4aef-96de-991a13ffa484','春雪得小詩五首且約客登賞心亭  其二','韓元吉','宋','宋诗','song-poetry','','[]','淮南山色一千里，落水層城江更湍。',32,'全唐诗/poet.song.124000.json','["淮南山色一千里，落水層城江更湍。", "何地江山有如許，與君聊趁雪中看。"]');
